INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette d''antidétection', '<p>Tant que vous portez cette amulette, vous ne pouvez<br>ni être la cible d''un sort de divination ni perçu par un<br>capteur de scrutation, sauf si vous le permettez.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette de bonne santé', '<p>Tant que vous portez ce pendentif, vous pouvez entre -<br>prendre l''action Magie pour récupérer 2d4 + 2 points<br>de vie. Une fois utilisée, cette propriété ne peut plus<br>resservir avant l''aube suivante.<br>Tant que vous portez ce pendentif, vous bénéficiez<br>en outre de l''Avantage aux jets de sauvegarde visant à<br>éviter l''état Empoisonné ou à y mettre fin.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette de cicatrisation', '<p>Tant que vous portez ce pendentif, vous recevez les<br>bénéfices ci-après.<br>Préservation de la vie. Chaque fois que vous effec -<br>tuez un jet de sauvegarde contre la mort, vous pouvez<br>transformer un résultat de 9 ou moins en 10, transfor -<br>mant ainsi un échec en réussite.Stimulation de la guérison. Chaque fois que vous<br>lancez un dé de vie pour récupérer des points de vie,<br>vous doublez le nombre de points de vie que ce dé<br>vous octroie.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette de protection contre le poison', '<p>Cette chaîne en argent délicatement ouvragée porte<br>en sautoir une gemme noire magnifiquement taillée.<br>Tant que vous la portez, vous bénéficiez de l''Immunité<br>contre l''état Empoisonné et les dégâts de poison.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette de santé', '<p>Votre Constitution est de 19 tant que vous portez<br>cette amulette. Elle est sans effet sur vous si votre<br>Constitution est déjà supérieure ou égale à 19.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Amulette des plans', '<p>Tant que vous portez cette amulette, vous pouvez<br>entreprendre l''action Magie en nommant un lieu<br>que vous connaissez sur un autre plan d''existence.<br>Effectuez ensuite un test d''Intelligence (Arcanes)<br>DD 15. En cas de réussite, vous lancez changement de<br>plan . En cas d''échec, vous-même et chaque créature et<br>objet dans un rayon de 4,50 m voyagez vers une desti -<br>nation aléatoire déterminée par un jet de 1d100 sur la<br>table ci-après.<br>1d100 Destination<br>01-60 Emplacement aléatoire sur le plan que vous<br>aviez nommé<br>61-70 Emplacement aléatoire sur un Plan Intérieur<br>déterminé par le résultat de 1d6 : 1 , le Plan<br>de l''Air ; 2 , le Plan de la Terre ; 3 , le Plan<br>du Feu ; 4 , le Plan de l''Eau ; 5 , la Féerie ; et<br>6, la Gisombre<br>71-80 Emplacement aléatoire sur un Plan Extérieur<br>déterminé par le résultat de 1d8 : 1 , l''Arbo -<br>rée ; 2 , l''Arcadie ; 3 , les Terres des Bêtes ;<br>4, la Bytopie ; 5 , l''Élysée ; 6 , Méchanus ;<br>7, le Mont Céleste ; et 8 , Ysgard<br>81-90 Emplacement aléatoire sur un Plan Extérieur<br>déterminé par le résultat de 1d8 : 1 , les<br>Abysses ; 2 , l''Achéron ; 3 , les Carcères ;<br>4, la Géhenne ; 5 , Hadès ; 6 , les Limbes ;<br>7, les Neuf Enfers ; et 8 , le Pandémonium<br>91-00 Emplacement aléatoire sur le Plan Astral</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau d''action libre', '<p>Tant que vous portez cet anneau, le Terrain difficile<br>ne vous coûte aucun déplacement supplémentaire.<br>En outre, aucune magie ne peut réduire vos Vitesses ni<br>vous imposer l''état Paralysé ou Entravé.<br>Document de Référence du Système 5.2.Anneau d''esquive totale</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau d''influence animale', '<p>Cet anneau dispose de 3 charges et récupère quoti -<br>diennement 1d3 charges dépensées, à l''aube. Tant<br>que vous portez l''anneau, vous pouvez en dépenser<br>1 charge pour lancer l''un des sorts suivants (DD de<br>sauvegarde 13) par son intermédiaire :<br>• amitié avec les animaux<br>• terreur (affecte uniquement les Bêtes)<br>• communication avec les animaux</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau d''invisibilité', '<p>Tant que vous portez cet anneau, vous pouvez entre -<br>prendre l''action Magie pour recevoir l''état Invisible.<br>Vous restez Invisible jusqu''à ce que l''anneau soit retiré<br>ou que vous entrepreniez une action Bonus pour rede -<br>venir visible.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de barrière mentale', '<p>Tant que vous portez cet anneau, vous êtes immunisé<br>contre toute magie permettant à une autre créature<br>de lire vos pensées, de déterminer si vous mentez, de<br>connaître votre alignement ou de découvrir votre type<br>de créature. Les créatures ne peuvent communiquer<br>par télépathie avec vous que si vous les y autorisez.<br>Vous pouvez entreprendre l''action Magie pour que<br>l''anneau devienne imperceptible jusqu''à ce que vous<br>le rendiez à nouveau perceptible au prix d''une autre<br>action Magie (ou que vous retiriez l''anneau, ou encore<br>que vous mouriez).<br>Si vous mourez en portant l''anneau, votre âme vient<br>l''habiter, à moins qu''il abrite déjà une autre âme.<br>Vous pouvez choisir de demeurer dans l''anneau ou<br>de partir pour l''au-delà. Tant que votre âme réside<br>dans l''anneau, vous pouvez communiquer par télé -<br>pathie avec la créature qui le porte. Le porteur ne<br>peut rien faire pour empêcher cette communication<br>télépathique.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de chaleur constante', '<p>Si vous subissez des dégâts de froid alors que vous<br>portez l''anneau, il réduit ces dégâts de 2d8.<br>En outre et tant que vous portez cet anneau,<br>vous-même et tout ce que vous portez êtes insensibles<br>aux effets délétères des températures inférieures ou<br>égales à -18 °C.Anneau de convocation de djinn</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de feu d''étoiles', '<p>Vous pouvez lancer lumières dansantes ou lumière par<br>le biais de l''anneau.<br>L''anneau dispose de 6 charges et récupère quotidien -<br>nement 1d6 charges dépensées, à l''aube. Vous pouvez<br>en dépenser les charges pour utiliser les propriétés<br>ci-dessous.<br>Étoiles filantes. Vous pouvez dépenser 1 à 3 charges<br>au prix de l''action Magie. Pour chaque charge dépen -<br>sée, vous faites jaillir une particule de lumière<br>incandescente depuis l''anneau vers un point que vous<br>voyez dans un rayon de 18 m. Chaque créature prise<br>dans un Cube de 4,50 m ayant ce point pour origine<br>subit une pluie d''étincelles. Elle effectue un jet de<br>sauvegarde de Dextérité DD 15 et subit 5d4 dégâts<br>radiants en cas d''échec, la moitié en cas de réussite.<br>Lueurs féeriques. Dépensez 1 charge pour lancer<br>lueurs féeriques par l''anneau.<br>Sphères de foudre. Dépensez 2 charges au prix<br>de l''action Magie pour créer un maximum de quatre<br>sphères de foudre de 90 cm de diamètre.<br>Chaque sphère apparaît en un espace inoccupé que<br>vous voyez, dans un rayon de 36 m. Les sphères per -<br>sistent tant que vous maintenez votre Concentration,<br>jusqu''à 1 minute. Chaque sphère émet une Lumière<br>faible dans un rayon de 9 m.<br>Par une action Bonus, vous pouvez déplacer chaque<br>sphère d''un maximum de 9 m à condition qu''elles<br>restent dans un rayon de 36 m de vous. La première<br>fois qu''une sphère arrive à 1,50 m ou moins d''une<br>créature autre que vous et que celle-ci ne bénéficie<br>pas d''un Abri total, la sphère libère un éclair sur la<br>créature et disparaît. Cette créature effectue un jet<br>de sauvegarde de Dextérité DD 15. En cas d''échec,<br>elle subit des dégâts de foudre dépendant du nombre<br>de sphères créées, comme indiqué sur la table<br>Document de Référence du Système 5.2.suivante. En cas de réussite, la créature subit la moitié<br>de ces dégâts.<br>Nombre de<br>sphèresDégâts de<br>foudreNombre de<br>sphèresDégâts de<br>foudre<br>1 4d12 3 2d6<br>2 5d4 4 2d4</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de feuille morte', '<p>Quand vous tombez alors que vous portez cet anneau,<br>vous descendez de 18 m par round sans subir de<br>dégâts de chute.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de maîtrise élémentaire', '<p>Chaque anneau de maîtrise élémentaire est lié à l''un<br>des quatre Plans Élémentaires. Le MJ choisit ou laisse<br>le hasard décider à quel plan il est lié. Par exemple,<br>un anneau de maîtrise élémentaire (air) est lié au Plan<br>Élémentaire de l''Air.<br>Chaque anneau de maîtrise élémentaire est doté des<br>deux propriétés suivantes :<br>Fléau élémentaire. Tant que vous portez cet anneau,<br>vous avez l''Avantage aux jets d''attaque contre les<br>Élémentaires originaires du plan lié, qui subissent le<br>Désavantage à leurs jets d''attaque contre vous.<br>Coercition élémentaire. Tant que vous portez<br>l''anneau, vous pouvez entreprendre l''action Magie<br>pour tenter de contraindre un Élémentaire que vous<br>voyez dans un rayon de 18 m. L''Élémentaire effec -<br>tue un jet de sauvegarde de Sagesse DD 18. En cas<br>d''échec, il subit l''état Charmé jusqu''au début de<br>votre tour suivant, et vous déterminez comment<br>il consacre son déplacement et son action à son<br>tour suivant.<br>Affinité élémentaire. Tant que vous portez l''anneau,<br>vous bénéficiez de propriétés supplémentaires corres -<br>pondant au Plan Élémentaire qui y est lié :<br>Air. Vous parlez l''aérien, bénéficiez de la Résistance<br>aux dégâts de foudre, ainsi que d''une Vitesse de vol<br>égale à votre Vitesse (avec le vol stationnaire).<br>Eau. Vous parlez l''aquatique, recevez une Vitesse de<br>nage de 18 m et pouvez respirer sous l''eau.<br>Feu. Vous parlez l''igné et bénéficiez de l''Immunité<br>contre les dégâts de feu.<br>Terre. Vous parlez le terreux et bénéficiez de la<br>Résistance aux dégâts d''acide. Les sols composés ou<br>jonchés de gravats, de roches ou de terre ne consti -<br>tuent pas un Terrain difficile pour vous. Vous pouvez<br>en outre traverser la terre ou la roche solide comme<br>s''il s''agissait d''un simple Terrain difficile, sans même<br>perturber la matière traversée. Si vous terminez<br>votre tour dans la terre ou la roche solide, vous êtes<br>expulsé vers l''espace inoccupé le plus proche parmi<br>ceux que vous venez d''occuper.Sorts. L''anneau dispose de 5 charges et récupère<br>quotidiennement 1d4 + 1 charges dépensées, à l''aube.<br>Tant que vous portez l''anneau, vous pouvez lancer un<br>sort par son intermédiaire. Choisissez le sort dans<br>la liste des sorts disponibles, comme indiqué dans<br>la table suivante (selon le Plan Élémentaire auquel<br>l''anneau est lié). La table indique le nombre de charges<br>à dépenser pour lancer le sort, dont le DD de sauve -<br>garde est de 18.<br>Plan Sorts (charges)<br>Air bourrasque (2 charges), chaîne d''éclairs<br>(3 charges), feuille morte (0 charge), mur de<br>vent (1 charge)<br>Eau création ou destruction d''eau (1 charge),<br>marche sur l''onde (2 charges), mur de glace<br>(3 charges), tempête de grêle (2 charges),<br>tsunami (5 charges)<br>Feu boule de feu (2 charges), mains brûlantes<br>(1 charge), mur de feu (3 charges), tempête de<br>feu (4 charges)<br>Terre façonnage de la pierre (2 charges), mur de<br>pierre (3 charges), peau de pierre (3 charges),<br>tremblement de terre (5 charges)</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de marche sur l''eau', '<p>Tant que vous portez cet anneau, vous lancez marche<br>sur l''onde par son biais, en ne ciblant que vous-même.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de nage', '<p>Tant que vous portez cet anneau, vous disposez d''une<br>Vitesse de nage de 12 m.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de protection', '<p>Vous recevez un bonus de +1 à la CA et aux jets de sau -<br>vegarde tant que vous portez cet anneau.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de rayons X', '<p>Tant que vous portez cet anneau, vous pouvez entre -<br>prendre l''action Magie pour recevoir la vision aux<br>rayons X sur 9 m pendant 1 minute. Pour vous, les<br>objets solides dans ce rayon apparaissent transparents<br>et ne bloquent pas la lumière. Cette vision pénètre<br>30 cm de pierre, 2,5 cm de métal courant et jusqu''à<br>90 cm de bois ou de terre. Des substances plus denses<br>ou une fine feuille de plomb bloquent la vision.<br>Chaque fois que vous réutilisez cet anneau sans avoir<br>pris de Repos long, vous devez réussir un jet de sauve -<br>garde de Constitution DD 15 sous peine de recevoir un<br>niveau d''Épuisement.<br>Document de Référence du Système 5.2.Anneau de régénération</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de renvoi des sorts', '<p>Tant que vous portez cet anneau, vous avez l''Avantage<br>aux jets de sauvegarde contre les sorts. Si vous réus -<br>sissez le JS contre un sort du 7e niveau ou inférieur,<br>ce sort n''a aucun effet sur vous. Si ce sort ne ciblait<br>que vous sans créer de zone d''effet, vous pouvez jouer<br>votre Réaction pour le retourner vers son lanceur ;<br>l''incantateur effectue un JS contre le sort en prenant<br>son propre DD de sauvegarde des sorts.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de résistance', '<p>Tant que vous portez cet anneau, vous bénéficiez de la<br>Résistance à un type de dégâts. La gemme de l''anneau<br>indique le type, que le MJ choisit ou détermine aléatoi -<br>rement selon la table suivante.<br>1d10 Type de dégâts Gemme<br>1 Acide Perle<br>2 Feu Grenat<br>3 Force Saphir<br>4 Foudre Citrine<br>5 Froid Tourmaline<br>6 Nécrotiques Jais<br>7 Poison Améthyste<br>8 Psychiques Jade<br>9 Radiants Topaze<br>10 Tonnerre Spinelle</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de saut', '<p>Tant que vous portez cet anneau, vous pouvez lancer<br>saut par son intermédiaire, mais vous ne pouvez cibler<br>que vous-même.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de stockage de sorts', '<p>Cet anneau stocke les sorts qui sont lancés sur lui et<br>les conserve jusqu''à ce que le porteur harmonisé les<br>utilise. L''anneau peut stocker jusqu''à 5 niveaux de sort<br>à la fois. Quand on le trouve, il contient 1d6 − 1 niveaux<br>de sort choisis par le MJ.Toute créature peut lancer un sort du 1er au 5e niveau<br>dans l''anneau à condition de le toucher au moment de<br>l''incantation. Le sort ne produit aucun effet hormis<br>celui d''être stocké dans l''anneau. Si l''anneau ne peut<br>pas contenir ce sort, celui-ci est dépensé sans effet.<br>Le niveau de l''emplacement utilisé pour lancer le sort<br>détermine la quantité d''espace qu''il utilise.<br>Tant que vous portez cet anneau, vous pouvez lan -<br>cer l''un des sorts qui y sont stockés. Ce sort utilise le<br>niveau d''emplacement de sort, le DD de sauvegarde<br>des sorts, le bonus d''attaque de sort et la caractéris -<br>tique d''incantation de l''incantateur d''origine, mais il<br>est par ailleurs traité comme si vous le lanciez. Le sort<br>lancé par l''anneau n''y est plus stocké et libère l''espace<br>correspondant.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de télékinésie', '<p>Tant que vous portez cet anneau, vous pouvez lancer<br>télékinésie par son intermédiaire.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau de triple souhait', '<p>Tant que vous portez cet anneau, vous pouvez dépen -<br>ser 1 de ses 3 charges pour lancer souhait par son<br>biais. L''anneau devient non magique lorsque vous<br>dépensez sa dernière charge.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Anneau du bélier', '<p>Cet anneau dispose de 3 charges et récupère quoti -<br>diennement 1d3 charges dépensées, à l''aube. Tant que<br>vous le portez, vous pouvez entreprendre l''action<br>Magie pour en dépenser 1 à 3 charges et effectuer<br>une attaque de sort à distance contre une créature<br>que vous voyez dans un rayon de 18 m. L''anneau pro -<br>duit une tête de bélier spectrale et effectue son jet<br>d''attaque avec un bonus de +7. Si l''attaque touche,<br>la cible subit 2d10 dégâts de force pour chaque charge<br>dépensée, et elle est repoussée de 1,50 m de vous.<br>Au lieu de cela, vous pouvez dépenser 1 à 3 des<br>charges de l''anneau au prix de l''action Magie pour<br>tenter de briser un objet non magique que vous voyez<br>dans un rayon de 18 m, à condition qu''il ne soit porté<br>par personne. L''anneau effectue un test de Force avec<br>un bonus de +5 par charge dépensée.<br>Arc à énergie<br>Arme (arc court ou arc long), très rare (Harmonisation<br>requise)<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique, qui n''a pas<br>de corde. Chaque fois que vous faites le geste de tendre<br>l''arc, une flèche magique faite d''énergie dorée appa -<br>raît, prête à être décochée. Les flèches produites par<br>cette arme infligent des dégâts de force au lieu des<br>dégâts perforants si l''attaque touche, et s''évanouis -<br>sent après avoir touché ou raté leur cible. Jusqu''à sa<br>Document de Référence du Système 5.2.disparition, une telle flèche émet une Lumière vive<br>dans un rayon de 6 m et une Lumière faible sur 6 m<br>de plus.<br>L''arme est dotée des propriétés supplémentaires<br>suivantes.<br>Échelle d''énergie. Au prix de l''action Magie,<br>vous décochez une volée de flèches d''énergie pure avec<br>cette arme en direction d''un mur situé dans un rayon<br>de 18 m. Les flèches se transforment en barreaux<br>lumineux qui dépassent du mur, formant une échelle<br>magique pouvant atteindre 18 m de haut. Cette échelle<br>persiste pendant 1 minute avant de disparaître.<br>Flèche d''entrave. Chaque fois que vous utilisez cette<br>arme pour effectuer une attaque à distance contre une<br>créature, vous pouvez tenter d''entraver la cible au lieu<br>de lui infliger des dégâts. Si la flèche touche, la cible<br>doit réussir un jet de sauvegarde de Force DD 15 sous<br>peine de subir l''état Entravé pendant 1 minute. Au prix<br>d''une action, toute créature Entravée par une flèche<br>peut effectuer un test de Force (Athlétisme) DD 20<br>pour tenter de se libérer, et met fin à l''effet sur elle-<br>même en cas de réussite.<br>Flèche de transport. Au prix de l''action Magie,<br>vous décochez avec cette arme une flèche d''énergie<br>sur une cible que vous voyez dans un rayon de 18 m.<br>La cible peut être une créature consentante de taille M<br>ou inférieure ou un objet qui n''est porté par personne,<br>à condition que celui-ci contienne dans un Cube de<br>1,50 m. La flèche téléporte la cible en un espace inoc -<br>cupé que vous voyez, dans un rayon de 3 m de vous.<br>Arc du serment<br>Arme (arc court ou arc long), très rare (Harmonisation<br>requise)<br>Lorsque vous encochez une flèche sur cet arc, il mur -<br>mure en elfique « Une prompte défaite pour mes<br>ennemis. » Lorsque vous utilisez l''arme pour effec -<br>tuer une attaque à distance, vous pouvez prononcer<br>ou signer les mots de commande suivants : « Une mort<br>rapide à toi qui m''as fait du tort. » La cible devient<br>votre ennemi désigné et le reste pendant 7 jours,<br>jusqu''à l''aube du dernier jour. Elle ne l''est plus si elle<br>meurt dans l''intervalle. Vous ne pouvez avoir qu''un<br>seul ennemi désigné de ce type à la fois. Lorsque votre<br>ennemi désigné meurt, vous pouvez en désigner un<br>nouveau après l''aube suivante.<br>Lorsque vous effectuez un jet d''attaque à distance<br>avec cette arme contre votre ennemi désigné, vous<br>bénéficiez de l''Avantage sur le jet. De plus, votre cible<br>ne reçoit aucun bénéfice lié à un Abri partiel ou supé -<br>rieur, et vous ne subissez aucun Désavantage dû à la<br>portée longue. Si l''attaque touche, votre ennemi dési -<br>gné subit 3d6 dégâts perforants supplémentaires.<br>Tant que votre ennemi désigné est vivant, vous<br>subissez le Désavantage aux jets d''attaque avec toutes<br>les autres armes.Arme +1, +2 ou +3<br>Arme (courante ou de guerre), peu courante (+1), rare<br>(+2) ou très rare (+3)<br>Vous recevez un bonus aux jets d''attaque et de dégâts<br>effectués avec cette arme magique. Ce bonus est déter -<br>miné par la rareté de l''arme.<br>Arme ardente<br>Arme (toute arme de corps à corps), rare<br>(Harmonisation requise)<br>Tant que vous tenez cette arme magique, vous pou -<br>vez, par une action Bonus et en prononçant son mot<br>de commande, susciter des flammes autour de la<br>partie de l''arme qui inflige des dégâts. Ces flammes<br>projettent une Lumière vive sur un rayon de 12 m et<br>une Lumière faible sur 12 m de plus. Tant que l''arme<br>est nimbée de flammes, elle inflige 2d6 dégâts de feu<br>supplémentaires si l''attaque touche. Ces flammes<br>persistent jusqu''à ce que, par une action Bonus, vous<br>réitériez le mot de commande ou que vous lâchiez,<br>rangiez ou rengainiez l''arme.<br>Arme brutale<br>Arme (courante ou de guerre), rare<br>Cette arme magique inflige 2d6 dégâts supplémen -<br>taires à toute créature qu''elle touche. Ces dégâts<br>supplémentaires sont du même type que les dégâts<br>normaux de l''arme.<br>Arme vigilante<br>Arme (courante ou de guerre), peu courante<br>(Harmonisation requise)<br>Tant que cette arme est à portée d''allonge et que per -<br>siste votre Harmonisation avec elle, vous-même et<br>vos alliés dans un rayon de 9 m recevez les bénéfices<br>suivants.<br>Alarme. L''arme réveille magiquement chaque sujet<br>endormi lorsqu''un combat commence. Ce bénéfice ne<br>tire pas un sujet d''un sommeil provoqué magiquement.<br>Vigilance surnaturelle. Chaque sujet a l''Avantage<br>aux jets d''Initiative.<br>Armure +1, +2 ou +3<br>Armure (légère, intermédiaire ou lourde), rare (+1),<br>très rare (+2) ou légendaire (+3)<br>Vous recevez un bonus à la CA tant que vous portez<br>cette armure. Ce bonus est déterminé par sa rareté.<br>Armure d''écailles de dragon<br>Armure (armure d''écailles), très rare (Harmonisation<br>requise)<br>Chaque armure d''écailles de dragon est faite avec des<br>écailles d''une espèce de dragon. Il arrive à certains<br>dragons de rassembler leurs écailles tombées pour en<br>faire don. En d''autres occasions, ces écailles sont pré -<br>levées avec soin sur le cadavre d''un dragon tué par des<br>chasseurs. Dans tous les cas, une armure d''écailles de<br>dragon est un bien inestimable.<br>Document de Référence du Système 5.2.Tant que vous portez cette armure, vous recevez un<br>bonus de +1 à la CA, bénéficiez de l''Avantage aux jets<br>de sauvegarde contre le souffle des Dragons, et de la<br>Résistance à un type de dégâts déterminé par l''espèce<br>de dragon qui a fourni les écailles (cf. table ci-après).<br>Au prix de l''action Magie, vous pouvez en outre foca -<br>liser vos sens afin de percevoir à quelle distance et<br>dans quelle direction se trouve le plus proche dragon<br>de l''espèce correspondant à l''armure dans un rayon de<br>45 km. Cette action ne peut alors plus resservir avant<br>l''aube suivante.<br>Dragon Résistance Dragon Résistance<br>Airain Feu Cuivre Acide<br>Argent Froid Noir Acide<br>Blanc Froid Or Feu<br>Bleu Foudre Rouge Feu<br>Bronze Foudre Vert Poison<br>Armure d''invulnérabilité<br>Armure (harnois), légendaire (Harmonisation requise)<br>Vous bénéficiez de la résistance aux dégâts conton -<br>dants, perforants et tranchants tant que vous portez<br>cette armure.<br>Carapace métallique. Vous pouvez entreprendre<br>l''action Magie pour vous octroyer l''Immunité contre<br>les dégâts contondants, perforants et tranchants pen -<br>dant 10 minutes (l''effet prend prématurément fin si<br>vous ne portez plus l''armure). Une fois cette propriété<br>utilisée, vous ne pouvez plus y recourir avant l''aube<br>suivante.<br>Armure de cuir clouté enchantée<br>Armure (armure de cuir clouté) rare<br>Tant que vous portez cette armure, vous recevez un<br>bonus de +1 à la CA. Par une action Bonus, vous faites<br>prendre à l''armure l''apparence de vêtements ordi -<br>naires ou d''un autre type d''armure. Vous décidez de<br>son aspect, y compris sa couleur, son style et ses acces -<br>soires, mais l''armure conserve son encombrement<br>normal et son poids. L''apparence illusoire persiste<br>jusqu''à ce que vous réutilisiez cette propriété ou<br>ôtiez l''armure.<br>Armure de mailles elfique<br>Armure (chemise de mailles ou cotte de mailles), rare<br>Vous recevez un bonus de +1 à la CA tant que vous por -<br>tez cette armure. Vous êtes considéré comme formé au<br>port de cette armure même s''il vous manque la forma -<br>tion aux armures lourdes et intermédiaires.<br>Armure de mithral<br>Armure (intermédiaire ou lourde, sauf armure de<br>peaux), peu courante<br>Le mithral est un métal léger et souple. Une armure<br>fabriquée dans ce matériau peut être portée sous<br>des vêtements normaux. Si l''armure dans sa version normale impose le Désavantage aux tests de Dextérité<br>(Discrétion) ou requiert une valeur de Force minimale,<br>ce n''est pas le cas de la version en mithral.<br>Armure de résistance<br>Armure (légère, intermédiaire ou lourde), rare<br>(Harmonisation requise)<br>Vous bénéficiez de la résistance à un type de dégâts<br>tant que vous portez cette armure. Le MJ en choisit<br>le type ou le détermine aléatoirement selon la table<br>suivante.<br>1d10 Type de dégâts 1d10 Type de dégâts<br>1 Acide 6 Nécrotiques<br>2 Feu 7 Poison<br>3 Force 8 Psychiques<br>4 Foudre 9 Radiants<br>5 Froid 10 Tonnerre<br>Armure de vulnérabilité<br>Armure (légère, intermédiaire ou lourde),<br>rare (Harmonisation requise)<br>Tant que vous portez cette armure, vous bénéficiez<br>de la résistance à l''un des types de dégâts suivants :<br>contondants, perforants ou tranchants. Le MJ choisit<br>ce type ou laisse le hasard en décider.<br>Malédiction. Cette armure est maudite, un fait<br>qui n''est révélé que lorsque le sort identification est<br>lancé sur l''armure ou quand vous vous harmonisez<br>avec elle. S''harmoniser avec l''armure vous maudit<br>jusqu''à ce que vous soyez la cible du sort délivrance<br>des malédictions ou d''un effet magique équivalent ;<br>ôter l''armure ne suffit pas à lever cette malédiction.<br>Tant que cette malédiction vous affecte, vous subissez<br>la Vulnérabilité à deux des trois types de dégâts asso -<br>ciés à l''armure (autres que celui auquel elle octroie<br>une résistance).<br>Armure démoniaque<br>Armure (légère, intermédiaire ou lourde), très rare<br>(Harmonisation requise)<br>Tant que vous portez cette armure, vous recevez un<br>bonus de +1 à la CA et parlez l''abyssal. Les gantelets<br>griffus de l''armure permettent en outre à vos attaques<br>à mains nues d''infliger 1d8 dégâts tranchants au lieu<br>des dégâts contondants habituels, et vous recevez<br>un bonus de +1 aux jets d''attaque et de dégâts de vos<br>attaques à mains nues.<br>Malédiction. Une fois cette armure maudite enfilée,<br>vous ne pouvez plus l''ôter sauf si vous êtes la cible<br>du sort délivrance des malédictions ou d''une magie<br>équivalente. Tant que vous portez cette armure, vous<br>subissez le Désavantage aux jets d''attaque contre les<br>démons et aux jets de sauvegarde contre leurs sorts et<br>aptitudes spéciales.<br>Document de Référence du Système 5.2.Armure en adamantium<br>Armure (intermédiaire ou lourde, sauf armure de<br>peaux), peu courante<br>Les parties en adamantium, l''un des matériaux les plus<br>résistants qui existent, augmentent la solidité de cette<br>armure. Tant que vous la portez, tout Coup critique<br>contre vous devient un coup normal.</p>', 2, 93, 2, 1, 33);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette d''éclairs', '<p>incantateur)<br>Cette baguette dispose de 7 charges. Lorsque vous la<br>tenez, vous pouvez dépenser jusqu''à 3 charges pour<br>lancer éclair (DD de sauvegarde 15). Avec 1 charge,<br>vous lancez le sort au 3e niveau. Vous augmentez le<br>niveau du sort d''un cran par charge additionnelle<br>dépensée.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de boules de feu', '<p>incantateur)<br>Cette baguette dispose de 7 charges. Lorsque vous la<br>tenez, vous pouvez dépenser jusqu''à 3 charges pour lan -<br>cer boule de feu (DD de sauvegarde 15). Avec 1 charge,<br>vous lancez le sort au 3e niveau. Vous augmentez le<br>niveau du sort d''un cran par charge additionnelle<br>dépensée.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de détection de l''ennemi', '<p>Cette baguette dispose de 7 charges. Lorsque vous la<br>tenez, vous pouvez entreprendre l''action Magie pour<br>dépenser 1 charge. Pendant 1 minute, vous connais -<br>sez la direction dans laquelle se trouve la créature<br>Hostile la plus proche dans un rayon de 18 m, mais pas<br>la distance qui vous en sépare. La baguette détecte<br>la présence de créatures Hostiles qui sont éthérées,<br>Invisibles, déguisées ou cachées, ainsi que celles expo -<br>sées à la vue de tous. L''effet se termine si vous cessez<br>de tenir la baguette.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.Baguette de détection de la magie</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de métamorphose', '<p>un incantateur)<br>Cette baguette dispose de 7 charges. Lorsque vous<br>la tenez, vous pouvez dépenser 1 charge pour lancer<br>métamorphose (DD de sauvegarde 15) par son biais.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de paralysie', '<p>incantateur)<br>Cette baguette dispose de 7 charges. Tant que vous la<br>tenez, vous pouvez entreprendre l''action Magie pour<br>dépenser 1 de ses charges afin de produire un fin<br>rayon bleuté qui jaillit de la pointe vers une créature<br>que vous voyez dans un rayon de 18 m. La cible doit<br>réussir un jet de sauvegarde de Constitution DD 15<br>sous peine de subir l''état Paralysé pendant 1 minute.<br>À la fin de chacun de ses tours, la cible réitère le JS et<br>met un terme à l''effet sur elle-même en cas de réussite.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de projectiles magiques', '<p>Cette baguette dispose de 7 charges. Lorsque vous la<br>tenez, vous pouvez dépenser jusqu''à 3 charges pour<br>lancer projectile magique par son biais. Avec 1 charge,<br>vous lancez le sort au 1er niveau. Vous augmentez le<br>niveau du sort d''un cran par charge additionnelle<br>dépensée.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette de terreur', '<p>Cette baguette dispose de 7 charges.<br>Sorts. Lorsque vous tenez la baguette, vous pouvez<br>lancer l''un des sorts de la table suivante (DD de sau -<br>vegarde 15). La table indique le nombre de charges à<br>dépenser pour lancer le sort.<br>Document de Référence du Système 5.2.SortCoût en<br>charges<br>injonction (« fuis » ou « rampe » uniquement) 1<br>terreur (Cône de 18 m) 3<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette des entraves', '<p>Cette baguette dispose de 7 charges.<br>Sorts. Lorsque vous tenez la baguette, vous pouvez<br>lancer l''un des sorts de la table suivante (DD de sau -<br>vegarde 17). La table indique le nombre de charges à<br>dépenser pour lancer le sort.<br>SortCoût en<br>charges<br>immobilisation de monstre 5<br>immobilisation de personne 2<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette se réduit en cendres,<br>à jamais détruite.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette des merveilles', '<p>Cette baguette dispose de 7 charges. Lorsque vous<br>la tenez, vous pouvez entreprendre l''action Magie<br>pour dépenser 1 charge en choisissant un point dans<br>un rayon de 36 m. Ce lieu devient le point d''origine<br>d''un sort ou d''un autre effet magique déterminé<br>aléatoirement selon la table « Effets de baguette des<br>merveilles ». Le DD de sauvegarde des sorts lancés par<br>la baguette est de 15. Quand la portée maximale d''un<br>sort est normalement inférieure à 36 m, elle passe à<br>36 m lorsqu''il est lancé par la baguette. Quand un effet<br>a plusieurs cibles potentielles, le MJ détermine aléatoi -<br>rement lesquelles sont affectées.<br>Récupération des charges. La baguette récupère<br>quotidiennement 1d6 + 1 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, la baguette tombe en poussière,<br>à jamais détruite.Effets de baguette des merveilles<br>1d100 Effet<br>01-20 Vous lancez un sort émanant du point d''origine<br>choisi. Lancez 1d10 pour déterminer le sort :<br>1-2, boule de feu ; 3-4 , lenteur ; 5-6 , lueurs fée -<br>riques ; 7-8 , nuage nauséabond ; 9-10 , ténèbres .<br>21-25 Rien ne se passe au point d''origine. Au lieu de<br>cela, vous subissez l''état Étourdi jusqu''au début<br>de votre tour suivant, convaincu qu''un événe -<br>ment extraordinaire se produit sous vos yeux.<br>26-30 Vous lancez bourrasque . La Ligne créée par le<br>sort s''étend de vous jusqu''au point d''origine.<br>31-35 Rien ne se passe au point d''origine. Au lieu de<br>cela, vous subissez 1d6 dégâts psychiques.<br>36-40 Une pluie torrentielle s''abat pendant 1 minute<br>dans un Cylindre de 36 m de haut et 18 m de<br>rayon centré sur le point d''origine. Pendant<br>cette durée, la zone d''effet est à Visibilité<br>réduite.<br>41-45 Une nuée de 600 papillons surdimensionnés<br>emplit un Cylindre de 18 m de haut et 9 m<br>de rayon centré sur le point d''origine. Les<br>papillons restent pendant 10 minutes, durant<br>lesquelles la zone d''effet est à Visibilité nulle.<br>46-50 Vous lancez éclair . La Ligne créée par le sort<br>s''étend de vous jusqu''au point d''origine.<br>51-55 La créature la plus proche du point d''origine<br>est agrandie comme si vous aviez lancé sur elle<br>agrandissement/rapetissement . Si vous n''êtes<br>pas cette cible et que celle-ci ne peut pas être<br>affectée par ce sort, c''est vous qui en devenez<br>la cible.<br>56-60 Une créature formée magiquement apparaît<br>dans un espace inoccupé aussi près que pos -<br>sible du point d''origine. Elle n''est pas sous<br>votre contrôle, agit normalement et disparaît<br>après 1 heure ou lorsqu''elle tombe à 0 point<br>de vie. Lancez 1d4 pour déterminer quelle<br>créature apparaît. Sur un 1, un rhinocéros se<br>présente ; 2 , un éléphant ; 3-4 , un rat .<br>61-64 De l''herbe recouvre un cercle de 18 m de<br>rayon au sol, le centre de ce cercle étant aussi<br>proche que possible du point d''origine. Si de<br>l''herbe était déjà présente, elle grandit jusqu''à<br>atteindre dix fois sa taille normale et demeure<br>ainsi pendant 1 minute.<br>65-68 Un objet au choix du MJ disparaît dans le Plan<br>Éthéré. L''objet ne doit être porté par personne,<br>doit se trouver dans un rayon de 36 m du point<br>d''origine et ne doit pas mesurer plus de 3 m de<br>long, de large ou de haut. S''il n''y a aucun objet<br>de la sorte à portée, rien ne se passe.<br>d100 Effet<br>69-72 Rien ne se passe au point d''origine. À la place,<br>vous rapetissez comme si vous aviez lancé<br>agrandissement/rapetissement sur vous-même<br>et restez dans cet état pendant 1 minute.<br>73-77 Des feuilles poussent sur la créature la plus<br>proche du point d''origine. À moins d''être arra -<br>chées avant, ces feuilles brunissent et tombent<br>au bout de 24 heures.<br>78-82 Rien ne se passe au point d''origine. Au lieu de<br>cela, une explosion de lumière colorée et scin -<br>tillante s''étend depuis vous dans une Émanation<br>de 9 m. Chaque créature prise dans la zone doit<br>réussir un jet de sauvegarde de Constitution<br>DD 15 sous peine de subir l''état Aveuglé pen -<br>dant 1 minute. Une créature affectée réitère<br>le JS à la fin de chacun de ses tours, et met un<br>terme à l''effet sur elle-même en cas de réussite.<br>83-87 Rien ne se passe au point d''origine. Au lieu de<br>cela, vous lancez invisibilité sur vous-même.<br>88-92 Rien ne se passe au point d''origine. Au lieu de<br>cela, un torrent de 1d4 × 10 gemmes, chacune<br>d''une valeur de 1 po, jaillit de la pointe de la<br>baguette vers le point d''origine en formant<br>une Ligne de 9 m de long sur 1,50 m de large.<br>Chaque gemme inflige 1 dégât contondant ;<br>les dégâts totaux infligés par les gemmes se<br>divisent équitablement entre toutes les créa -<br>tures présentes sur cette Ligne.<br>93-97 Vous lancez métamorphose , en ciblant la créa -<br>ture la plus proche du point d''origine. Lancez<br>1d4 pour déterminer la nouvelle forme de la<br>cible. 1 , la nouvelle forme est un ours noir ;<br>2, une guêpe géante ; 3-4 , une grenouille .<br>98-00 La créature la plus proche du point d''origine<br>effectue un jet de sauvegarde de Constitution<br>DD 15. En cas d''échec, elle subit l''état Entravé<br>et commence à se pétrifier. Tant qu''elle est<br>ainsi Entravée, la créature réitère le JS à la<br>fin de son tour suivant. En cas de réussite,<br>l''effet prend fin. En cas d''échec, la créature<br>subit l''état Pétrifié qui remplace l''état Entravé.<br>La pétrification persiste jusqu''à ce que la créa -<br>ture en soit affranchie par le sort restauration<br>suprême ou une magie équivalente.</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Baguette des secrets', '<p>Cette baguette dispose de 3 charges et récupère quoti -<br>diennement 1d3 charges dépensées, à l''aube. Tant que<br>vous la tenez, vous pouvez entreprendre l''action<br>Magie pour dépenser 1 charge ; si un passage secret<br>ou un piège se trouve dans un rayon de 18 m de vous,<br>la baguette émet des impulsions et pointe en direction<br>de l''élément détecté le plus proche.Baguette des toiles</p>', 2, 93, 2, 1, 36);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Balai volant', '<p>Ce balai en bois remplit la fonction de balai ordinaire<br>jusqu''à ce que vous le chevauchiez et entrepreniez<br>l''action Magie pour le placer en vol stationnaire<br>au-dessous de vous, faisant de lui une monture<br>aérienne. Sa Vitesse de vol est de 15 m. Il peut trans -<br>porter jusqu''à 200 kg, mais sa Vitesse de vol est<br>réduite à 9 m s''il porte plus de 100 kg. Le balai cesse<br>son vol stationnaire quand vous posez les pieds au sol<br>ou ne le chevauchez plus.<br>Au prix de l''action Magie, vous pouvez envoyer le<br>balai voler seul vers une destination située dans un<br>rayon de 1,5 km si vous nommez l''emplacement et<br>connaissez cet endroit. Le balai revient à vous quand<br>vous entreprenez l''action Magie et prononcez le mot de<br>commande correspondant, à condition qu''il se trouve<br>toujours dans un rayon de 1,5 km.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bandeau d''intelligence', '<p>Votre Intelligence est de 19 tant que vous portez ce<br>bandeau. Il est sans effet sur vous si votre Intelligence<br>est déjà supérieure ou égale à 19.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bateau pliable', '<p>Cet objet apparaît d''emblée comme une caisse<br>oblongue en bois, longue de 30 cm pour une largeur<br>et une hauteur de 15 cm. Elle pèse 2 kg et flotte. Il est<br>possible de l''ouvrir et de ranger des objets à l''intérieur.<br>L''objet est aussi doté de trois mots de commande, cha -<br>cun nécessitant l''action Magie :<br>Premier mot de commande. La caisse se déplie pour<br>former une barque.<br>Deuxième mot de commande. La caisse se déplie<br>pour former une barge.<br>Document de Référence du Système 5.2.Troisième mot de commande. Le bateau pliable se<br>replie et retrouve sa forme de caisse si aucune créa -<br>ture ne se trouve à bord. Les objets restés à bord et<br>qui ne tiennent pas dans cette caisse se retrouvent à<br>l''extérieur de celle-ci lorsqu''elle se replie. Tout objet<br>resté à bord du navire et qui tient dans la caisse y<br>est rangé.<br>Lorsque la caisse se transforme en véhicule, son poids<br>devient celui d''un bâtiment normal de son gabarit,<br>et tout ce qui était rangé dans la caisse reste à bord.<br>Les profils de la barque et de la barge sont dispo -<br>nibles en section « Équipement ». Si l''un ou l''autre<br>véhicule est réduit à 0 point de vie, le bateau pliable<br>est détruit.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton d''envoûtement', '<p>Clerc, Druide, Ensorceleur, Magicien ou Occultiste)<br>Ce bâton dispose de 10 charges. Tant que vous tenez ce<br>bâton, vous pouvez recourir à ses propriétés :<br>Incantation. Vous pouvez dépenser 1 charge du bâton<br>pour lancer charme-personne , compréhension des<br>langues ou injonction en prenant votre DD de sauve -<br>garde des sorts.<br>Renvoi d''enchantement. Si vous réussissez un JS<br>contre un sort d''Enchantement qui ne cible que<br>vous, vous pouvez jouer votre Réaction pour dépen -<br>ser 1 charge du bâton, ce qui renvoie le sort sur son<br>incantateur comme si vous aviez lancé le sort.<br>Résistance aux enchantements. Si vous ratez un jet<br>de sauvegarde contre un sort d''Enchantement qui ne<br>cible que vous, vous pouvez transformer cet échec en<br>réussite. Cette propriété du bâton ne peut plus res -<br>servir avant l''aube suivante.<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 1d8 + 2 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton est réduit en poussière.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de feu', '<p>Druide, Ensorceleur, Magicien ou Occultiste)<br>Vous bénéficiez de la Résistance aux dégâts de feu tant<br>que vous tenez ce bâton.<br>Sorts. Le bâton dispose de 10 charges. Lorsque vous<br>tenez le bâton, vous pouvez lancer l''un des sorts de la<br>table suivante en prenant votre DD de sauvegarde des<br>sorts. La table indique le nombre de charges à dépen -<br>ser pour lancer le sort.<br>SortCoût en<br>charges SortCoût en<br>charges<br>boule de feu 3 mur de feu 4<br>mains brûlantes 1<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 1d6 + 4 charges dépensées, à l''aube. Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton est réduit en cendres.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de flétrissement', '<p>Ce bâton dispose de 3 charges et récupère quotidien -<br>nement 1d3 charges dépensées, à l''aube.<br>Il peut également servir de bâton de combat<br>magique. Une attaque qui touche avec ce bâton inflige<br>les dégâts d''un bâton de combat normal, sachant<br>que vous pouvez dépenser 1 charge pour qu''il inflige<br>2d10 dégâts nécrotiques supplémentaires à la cible et<br>lui impose un jet de sauvegarde de Constitution DD 15.<br>En cas d''échec, la cible subit le Désavantage pendant<br>1 heure à tout test de caractéristique et jet de sauve -<br>garde basé sur la Force ou la Constitution.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de givre', '<p>Druide, Ensorceleur, Magicien ou Occultiste)<br>Vous bénéficiez de la Résistance aux dégâts de froid<br>tant que vous tenez ce bâton.<br>Sorts. Le bâton dispose de 10 charges. Lorsque vous<br>tenez le bâton, vous pouvez lancer l''un des sorts de la<br>table suivante en prenant votre DD de sauvegarde des<br>sorts. La table indique le nombre de charges à dépen -<br>ser pour lancer le sort.<br>SortCoût en<br>charges SortCoût en<br>charges<br>cône de froid 5 nappe de<br>brouillard1<br>mur de glace 4 tempête<br>de grêle4<br>Récupération des charges. Le bâton récupère<br>quotidiennement 1d6 + 4 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton se liquéfie et il<br>est détruit.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de guérison', '<p>Clerc ou Druide)<br>Ce bâton dispose de 10 charges. Lorsque vous tenez<br>le bâton, vous pouvez lancer l''un des sorts de la table<br>suivante en prenant votre modificateur de caracté -<br>ristique d''incantation. La table indique le nombre de<br>charges à dépenser pour lancer le sort.<br>Sort Coût en charges<br>restauration partielle 2<br>soins 1 charge par niveau de<br>sort (maximum 4 pour<br>un sort du 4e niveau)<br>soins de groupe 5<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 1d6 + 4 charges dépensées, à l''aube.<br>230Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton disparaît dans un éclat<br>de lumière, perdu à jamais.<br>Bâton de l''acrobate<br>Arme (bâton de combat), très rare (Harmonisation<br>requise)<br>Vous recevez un bonus de +2 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>Tant que vous tenez cette arme, vous pouvez lui faire<br>émettre une Lumière faible verte dans un rayon de<br>3 m, soit par une action Bonus, soit après avoir joué<br>l''Initiative ; vous pouvez aussi en éteindre la lumière<br>par une action Bonus.<br>Si vous tenez l''arme, vous pouvez entreprendre une<br>action Bonus pour modifier sa forme et la transformer<br>en bâtonnet de 15 cm (pour en faciliter le rangement)<br>ou une perche de 3 m, ou bien la ramener à sa forme<br>de bâton de combat. L''arme ne s''allongera que dans la<br>limite de l''espace disponible.<br>Sous certaines formes, l''arme est dotée des proprié -<br>tés supplémentaires suivantes.<br>Arme à distance (bâton de combat uniquement).<br>L''arme est dotée de la propriété Lancer avec une por -<br>tée normale de 9 m et une portée longue de 36 m.<br>Aussitôt après votre attaque à distance avec le bâton,<br>il revient dans votre main.<br>Assistance acrobatique (bâton de combat et<br>perche de 3 m uniquement). En tenant cette arme,<br>vous bénéficiez de l''Avantage aux tests de Dextérité<br>(Acrobaties).<br>Déviation d''attaque (bâton de combat unique -<br>ment). Lorsque vous êtes touché par une attaque<br>alors que vous tenez l''arme, vous pouvez jouer votre<br>Réaction pour décrire des moulinets avec le bâton et<br>recevoir un bonus de +5 à votre CA contre l''attaque<br>correspondante, ce qui peut la faire échouer. Vous ne<br>pouvez ensuite plus recourir à cette propriété avant<br>d''avoir terminé un Repos court ou long.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de surpuissance', '<p>Ensorceleur, Magicien ou Occultiste)<br>Ce bâton, qui dispose de 20 charges, peut se manier<br>comme un bâton de combat magique octroyant un<br>bonus de +2 aux jets d''attaque et de dégâts. Tant que<br>vous le tenez, vous recevez un bonus de +2 à la classe<br>d''armure, aux jets de sauvegarde et aux jets d''attaque<br>de sort.<br>Sorts. Lorsque vous tenez le bâton, vous pouvez<br>lancer l''un des sorts de la table suivante en prenant<br>votre DD de sauvegarde des sorts. La table indique le<br>nombre de charges à dépenser pour lancer le sort.<br>SortCoût en<br>charges<br>boule de feu (au 5e niveau) 5<br>cône de froid 5SortCoût en<br>charges<br>éclair (au 5e niveau) 5<br>globe d''invulnérabilité 6<br>immobilisation de monstre 5<br>lévitation 2<br>mur de force 5<br>projectile magique 1<br>rayon affaiblissant 1<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 2d8 + 4 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton conserve son bonus de<br>+2 aux jets d''attaque et de dégâts, mais perd toutes ses<br>autres propriétés. Sur un résultat de 20, il récupère<br>1d8 + 2 charges.<br>Explosion vengeresse. Vous pouvez entreprendre<br>l''action Magie pour rompre le bâton sur votre genou<br>ou contre une surface solide. Le bâton se détruit alors<br>en libérant sa magie dans une explosion qui emplit<br>une Émanation de 9 m, dont il est l''origine. Vous avez<br>50 % de chances d''être propulsé instantanément vers<br>un plan d''existence aléatoire et d''éviter ainsi l''explo -<br>sion. Si vous n''évitez pas l''effet, vous subissez autant<br>de dégâts de force que 16 fois le nombre de charges<br>que contient le bâton. Chaque autre créature de la<br>zone effectue un jet de sauvegarde de Dextérité DD 17.<br>En cas d''échec, une créature subit autant de dégâts de<br>force que 4 fois le nombre de charges contenues dans<br>le bâton. En cas de réussite, elle ne subit que la moitié<br>de ces dégâts.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton de tonnerre et de foudre', '<p>Ce bâton peut se manier comme un bâton de combat<br>magique qui octroie un bonus de +2 aux jets d''attaque<br>et de dégâts. Il dispose en outre des propriétés sup -<br>plémentaires suivantes. Une fois que l''une de ces<br>propriétés est utilisée, vous ne pouvez plus y recourir<br>avant l''aube suivante.<br>Foudre. Lorsque vous touchez une cible avec une<br>attaque de corps à corps utilisant le bâton, vous pou -<br>vez lui infliger 2d6 dégâts de foudre supplémentaires<br>(pas d''action requise).<br>Tonnerre. Lorsque vous touchez avec une attaque<br>de corps à corps utilisant le bâton, vous pouvez faire<br>produire à celui-ci un éclat de tonnerre audible à 90 m<br>(pas d''action requise). La cible que vous avez touchée<br>doit réussir un jet de sauvegarde de Constitution<br>DD 17 sous peine de subir l''état Étourdi jusqu''à la fin<br>de votre tour suivant.<br>Tonnerre et foudre. Aussitôt après avoir touché<br>une cible avec une attaque de corps à corps utilisant<br>le bâton, vous pouvez entreprendre une action Bonus<br>pour utiliser simultanément les propriétés Foudre<br>et Tonnerre (voir ci-dessus). Cela ne dépense pas<br>231l''utilisation quotidienne de ces deux propriétés, seule -<br>ment celle de « Tonnerre et foudre ».<br>Trait de foudre. Vous pouvez entreprendre l''action<br>Magie pour faire jaillir la foudre de la pointe du bâton<br>sur une Ligne de 1,50 m de large et 36 m de long.<br>Chaque créature prise dans cette Ligne effectue un jet<br>de sauvegarde de Dextérité DD 17 et subit 9d6 dégâts<br>de foudre en cas d''échec, la moitié en cas de réussite .<br>Coup de tonnerre. Vous pouvez entreprendre<br>l''action Magie pour que le bâton produise un coup de<br>tonnerre audible à 180 m. Chaque créature dans une<br>Émanation de 18 m centrée sur vous effectue un jet<br>de sauvegarde de Constitution DD 17. En cas d''échec,<br>une créature subit 2d6 dégâts de tonnerre, ainsi que<br>l''état Assourdi pendant 1 minute. En cas de réussite,<br>elle subit uniquement la moitié de ces dégâts.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton des forêts', '<p>Ce bâton, qui dispose de 6 charges, peut se manier<br>comme un bâton de combat magique octroyant un<br>bonus de +2 aux jets d''attaque et de dégâts. Tant que<br>vous le tenez, vous recevez un bonus de +2 aux jets<br>d''attaque de sort.<br>Sorts. Lorsque vous tenez le bâton, vous pouvez<br>lancer l''un des sorts de la table suivante en prenant<br>votre DD de sauvegarde des sorts. La table indique le<br>nombre de charges à dépenser pour lancer le sort.<br>SortCoût en<br>charges<br>amitié avec les animaux 1<br>communication avec les animaux 1<br>communication avec les plantes 3<br>éveil 5<br>localisation d''animaux ou de plantes 2<br>mur d''épines 6<br>passage sans trace 2<br>peau d''écorce 2<br>Forme d''arbre. Vous pouvez entreprendre l''action<br>Magie pour planter une extrémité du bâton dans<br>une terre fertile en un espace inoccupé et dépenser<br>1 charge pour transformer le bâton en un arbre vigou -<br>reux. L''arbre mesure 18 m de haut et son tronc 1,50 m<br>de diamètre, la ramure au sommet atteignant 6 m<br>de rayon. L''arbre semble ordinaire, mais dégage une<br>faible aura de magie de Transmutation détectable par<br>le sort détection de la magie . En touchant l''arbre et en<br>entreprenant l''action Magie, vous ramenez le bâton à<br>sa forme normale. Toute créature perchée dans l''arbre<br>tombe lorsque celui-ci redevient un bâton.<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 1d6 charges dépensées, à l''aube. Si vous<br>dépensez la dernière charge, lancez 1d20. Sur un<br>résultat de 1, le bâton perd ses propriétés et devient<br>un bâton de combat non magique.Bâton du grand essaim</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton du python', '<p>Au prix de l''action Magie, vous pouvez lancer ce bâton<br>pour qu''il atterrisse en un espace inoccupé dans un<br>rayon de 3 m et s''y transforme en serpent constric -<br>teur géant . Le serpent, sous votre contrôle, partage<br>votre rang d''initiative et joue son tour juste après<br>le vôtre.<br>À votre tour, vous pouvez donner un ordre mental<br>au serpent (pas d''action requise) s''il se trouve dans un<br>rayon de 18 m de vous et si vous ne subissez pas l''état<br>Neutralisé. Vous décidez quelle action le serpent entre -<br>prend et où il se déplacera à son tour, ou pouvez vous<br>contenter de lui donner une instruction plus générale,<br>comme veiller sur un lieu ou attaquer vos ennemis.<br>En l''absence d''ordres de votre part, le serpent<br>se défend.<br>Par une action Bonus, vous pouvez ordonner au<br>serpent de reprendre sa forme de bâton dans son<br>espace actuel, après quoi vous ne pouvez plus utiliser<br>la propriété du bâton pendant 1 heure. Si le serpent<br>tombe à 0 point de vie, il meurt et retrouve sa forme<br>de bâton ; le bâton se détruit alors en se brisant. Si le<br>serpent retrouve sa forme de bâton avant d''avoir<br>perdu tous ses points de vie, il les récupère tous.<br>232Bâton du thaumaturge</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton du thaumaturge', '<p>Ensorceleur, Magicien ou Occultiste)<br>Ce bâton, qui dispose de 50 charges, peut se manier<br>comme un bâton de combat magique octroyant un<br>bonus de +2 aux jets d''attaque et de dégâts. Tant que<br>vous le tenez, vous recevez un bonus de +2 aux jets<br>d''attaque de sort.<br>Absorption de sort. Tant que vous tenez le bâton,<br>vous avez l''Avantage aux jets de sauvegarde contre les<br>sorts. Vous pouvez en outre jouer votre Réaction lors -<br>qu''une autre créature lance un sort qui ne cible que<br>vous. Dans ce cas, le bâton absorbe la magie du sort,<br>ce qui en annule l''effet ; le bâton reçoit alors un nombre<br>de charges égal au niveau du sort absorbé. Cependant,<br>si cela amène le nombre total de charges du bâton<br>au-dessus de 50, l''objet explose comme si vous aviez<br>activé son Explosion vengeresse (voir ci-après).<br>Sorts. Lorsque vous tenez le bâton, vous pouvez<br>lancer l''un des sorts de la table suivante en prenant<br>votre DD de sauvegarde des sorts. La table indique le<br>nombre de charges à dépenser pour lancer le sort.<br>SortCoût en<br>charges<br>agrandissement/rapetissement 0<br>boule de feu (au 7e niveau) 7<br>changement de plan 7<br>déblocage 2<br>détection de la magie 0<br>dissipation de la magie 3<br>éclair (au 7e niveau) 7<br>invisibilité 2<br>invocation d''élémentaire 7<br>lumière 0<br>main du mage 0<br>mur de feu 4<br>passe-muraille 5<br>protection contre le mal et le bien 0<br>sphère de feu 2<br>télékinésie 5<br>tempête de grêle 4<br>toile d''araignée 2<br>verrou magique 0<br>Récupération des charges. Le bâton récupère quoti -<br>diennement 4d6 + 2 charges dépensées, à l''aube. Si vous<br>dépensez la dernière charge, lancez 1d20. Sur un résul -<br>tat de 20, le bâton récupère 1d12 + 1 charges.<br>Explosion vengeresse. Vous pouvez entreprendre<br>l''action Magie pour rompre le bâton sur votre genou<br>ou contre une surface solide. Le bâton se détruit alors<br>en libérant sa magie dans une explosion qui emplit<br>une Émanation de 9 m, dont il est l''origine. Vous avez 50 % de chances d''être propulsé instantanément vers<br>un plan d''existence aléatoire et d''éviter ainsi l''explo -<br>sion. Si vous n''évitez pas l''effet, vous subissez autant<br>de dégâts de force que 16 fois le nombre de charges<br>que contient le bâton. Chaque autre créature de la<br>zone effectue un jet de sauvegarde de Dextérité DD 17.<br>En cas d''échec, une créature subit des dégâts de force<br>égaux à 6 fois le nombre de charges contenues dans le<br>bâton. En cas de réussite, elle ne subit que la moitié de<br>ces dégâts.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bâton percussif', '<p>Ce bâton peut se manier comme un bâton de combat<br>magique qui octroie un bonus de +3 aux jets d''attaque<br>et de dégâts.<br>Le bâton dispose de 10 charges. Lorsque vous<br>touchez avec une attaque de corps à corps par<br>son intermédiaire, vous pouvez dépenser jusqu''à<br>3 charges. Pour chaque charge dépensée, la cible subit<br>1d6 dégâts de force supplémentaires.<br>Récupération des charges. Le bâton récupère quo -<br>tidiennement 1d6 + 4 charges dépensées, à l''aube.<br>Si vous dépensez la dernière charge, lancez 1d20.<br>Sur un résultat de 1, le bâton devient un bâton de com -<br>bat non magique.</p>', 2, 93, 2, 1, 37);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes ailées', '<p>Ces bottes disposent de 4 charges et récupèrent<br>quotidiennement 1d4 charges dépensées, à l''aube.<br>Tant qu''elles vous chaussent, vous pouvez entre -<br>prendre l''action Magie pour dépenser 1 charge et<br>recevoir une Vitesse de vol de 9 m pendant 1 heure.<br>Si vous volez au moment où la durée expire, vous des -<br>cendez à une vitesse de 9 m par round jusqu''à ce que<br>vous touchiez terre.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes elfiques', '<p>Tant que vous portez ces bottes, vos pas restent<br>silencieux, quelle que soit la surface que vous fou -<br>lez. Vous avez l''Avantage aux tests de Dextérité<br>(Discrétion).</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes de lévitation', '<p>Porter ces bottes vous permet de lancer le sort lévita -<br>tion sur vous-même.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes de rapidité', '<p>Tant que vous portez ces bottes, vous pouvez consa -<br>crer une action Bonus à faire claquer vos talons l''un<br>contre l''autre. Dès lors, les bottes doublent votre<br>Vitesse et toute créature qui effectue une attaque<br>d''Opportunité contre vous subit le Désavantage à son<br>jet d''attaque. Cet effet prend fin si vous faites de nou -<br>veau claquer vos talons.<br>233Quand la propriété des bottes a été utilisée pendant<br>un total de 10 minutes, leur magie cesse de fonction -<br>ner jusqu''à ce que vous ayez terminé un Repos long.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes de sept lieues', '<p>Tant que vous portez ces bottes, votre Vitesse devient<br>9 m sauf si elle est déjà supérieure, et elle n''est pas<br>réduite par le fait de porter un poids supérieur à votre<br>capacité de charge ni une armure lourde.<br>Une fois à chacun de vos tours, vous pouvez effec -<br>tuer un saut de 9 m maximum en ne dépensant que<br>3 m de déplacement.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bottes des terres gelées', '<p>Ces confortables bottes fourrées gardent les pieds au<br>chaud. Tant que vous les portez, vous recevez les béné -<br>fices suivants :<br>Arpenteur de l''hiver. Vous ne tenez pas compte du<br>Terrain difficile créé par la glace et la neige.<br>Résistance au froid. Vous bénéficiez de la Résistance<br>aux dégâts de froid et tolérez les températures infé -<br>rieures à -18 °C sans protection supplémentaire.<br>Bouclier +1, +2 ou +3<br>Armure (bouclier), peu courante (+1), rare (+2) ou très<br>rare (+3)<br>Tant que vous tenez ce bouclier, vous bénéficiez à la<br>classe d''armure d''un bonus déterminé par la rareté du<br>bouclier, en plus du bonus normal du bouclier à la CA.<br>Bouclier animé<br>Armure (bouclier), très rare (Harmonisation requise)<br>Tant que vous maniez ce bouclier, vous pouvez l''ani -<br>mer par une action Bonus. Le bouclier s''élance dans<br>les airs, reste en vol stationnaire dans votre espace<br>en vous protégeant comme si vous le portiez, ce qui<br>vous laisse les mains libres. Le bouclier reste animé<br>pendant 1 minute, mais disparaît avant cela si vous<br>consacrez une action Bonus pour mettre fin à cet effet,<br>mourez ou subissez l''état Neutralisé ; il tombe alors<br>au sol ou revient dans votre main si vous avez une<br>main libre.<br>Bouclier antiprojectiles<br>Armure (bouclier), rare (Harmonisation requise)<br>Vous recevez un bonus de +2 à la classe d''armure<br>contre les jets d''attaque à distance tant que vous por -<br>tez ce bouclier. Ce bonus s''ajoute à celui que le bouclier<br>octroie normalement à la CA.<br>Chaque fois qu''un assaillant effectue un jet d''attaque<br>à distance contre une cible dans un rayon de 1,50 m de<br>vous, vous pouvez jouer votre Réaction pour devenir la<br>cible de cette attaque à sa place.Bouclier d''attraction des projectiles<br>Armure (bouclier), rare (Harmonisation requise)<br>Tant que vous tenez ce bouclier, vous bénéficiez de<br>la Résistance aux dégâts des attaques des armes<br>à distance.<br>Malédiction. Ce bouclier est maudit. S''harmoniser<br>avec lui vous maudit jusqu''à ce que vous soyez la<br>cible du sort délivrance des malédictions ou d''un effet<br>magique équivalent. Retirer le bouclier ne suffit pas à<br>lever la malédiction. Chaque fois qu''une attaque avec<br>une arme à distance cible une créature dans un rayon<br>de 3 m de vous, vous en devenez en fait la cible.<br>Bouclier du hussard<br>Armure (bouclier), très rare (Harmonisation requise)<br>Tant que vous portez ce bouclier, vous recevez un<br>bonus de +2 à la classe d''armure. Ce bonus s''ajoute à<br>celui que le bouclier octroie normalement à la CA.<br>Le bouclier dispose des propriétés supplémentaires<br>suivantes, accessibles lorsque vous le tenez.<br>Champ protecteur. Lorsque vous-même ou un allié<br>que vous voyez dans un rayon de 1,50 m êtes la cible<br>d''une attaque ou effectuez un jet de sauvegarde contre<br>une zone d''effet, vous pouvez jouer votre Réaction<br>pour que le bouclier produise une Émanation immobile<br>de 1,50 m centrée sur vous. Quand apparaît l''Éma -<br>nation, tous les objets et créatures qui n''y sont que<br>partiellement sont repoussés vers les espaces inoccu -<br>pés les plus proches, hors de l''Émanation. L''attaque ou<br>la zone d''effet qui a déclenché la Réaction reste sans<br>effet sur les créatures et objets dans l''Émanation, qui<br>persiste tant que vous maintenez votre Concentration<br>(maximum 1 minute). Rien ne peut entrer dans<br>l''Émanation ni en sortir. Les créatures et objets dans<br>l''Émanation ne peuvent subir de dégâts des attaques et<br>effets venant de l''autre côté, pas plus qu''une créature<br>à l''intérieur ne peut infliger de dégâts vers l''extérieur.<br>Une fois cette propriété utilisée, vous ne pouvez plus y<br>recourir avant l''aube suivante.<br>Taquet. Lorsque vous entreprenez l''action Attaque,<br>vous pouvez effectuer l''un des jets d''attaque avec le<br>bouclier, contre une cible dans un rayon de 1,50 m.<br>Appliquez votre bonus de maîtrise et votre modifi -<br>cateur de Force à ce jet d''attaque. Si l''attaque touche,<br>le bouclier inflige à la cible des dégâts de force égaux<br>à 2d6 + 2 plus votre modificateur de Force. Si la cible<br>est une créature, vous pouvez en outre la repousser<br>d''un maximum de 3 m. Si sa catégorie de taille est<br>inférieure ou égale à la vôtre, vous pouvez aussi lui<br>imposer l''état À terre.<br>Bouclier gardesort<br>Armure (bouclier), très rare (Harmonisation requise)<br>Tant que vous tenez ce bouclier, vous avez l''Avantage<br>aux jets de sauvegarde contre les sorts et autres effets<br>magiques, et les jets d''attaque de sort contre vous<br>subissent le Désavantage.<br>234Bouclier sentinelle<br>Armure (bouclier), peu courant<br>Tant que vous tenez ce bouclier, vous bénéficiez de<br>l''Avantage aux jets d''Initiative et aux tests de Sagesse<br>(Perception). Ce bouclier est orné d''un symbole repré -<br>sentant un œil.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Boule de cristal', '<p>Tant que vous touchez cet orbe de cristal, vous pouvez<br>lancer scrutation (DD de sauvegarde 17) par son biais.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Boule de cristal de lecture des pensées', '<p>Tant que vous touchez cet orbe de cristal, vous pouvez<br>lancer scrutation (DD de sauvegarde 17) par son biais.<br>Vous pouvez en outre lancer détection des pensées<br>(DD de sauvegarde 17) en prenant pour cible les créa -<br>tures que vous voyez dans un rayon de 9 m du capteur<br>du sort. Vous n''avez pas besoin de vous concentrer sur<br>le sort détection des pensées pour le maintenir pendant<br>toute sa durée, mais il s''achève si le sort scrutation<br>se termine.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Boule de cristal de télépathie', '<p>Tant que vous touchez cet orbe de cristal, vous pouvez<br>lancer scrutation (DD de sauvegarde 17) par son biais.<br>Vous pouvez en outre communiquer par télépathie<br>avec les créatures que vous voyez dans un rayon de<br>9 m du capteur du sort. Vous pouvez enfin lancer sug -<br>gestion (DD de sauvegarde 17) par le biais du capteur<br>sur l''une de ces créatures. Vous n''avez pas besoin de<br>vous concentrer sur cette suggestion pour la main -<br>tenir pendant toute sa durée, mais elle s''achève si la<br>scrutation se termine. Vous ne pouvez pas relancer<br>suggestion par ce biais avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Boule de cristal de vision suprême', '<p>Tant que vous touchez cet orbe de cristal, vous pouvez<br>lancer scrutation (DD de sauvegarde 17) par son biais.<br>Vous bénéficiez en outre de la Vision lucide à 36 m,<br>centrée sur le capteur du sort.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bouteille du mauvais génie', '<p>Lorsque vous consacrez l''action Magie à retirer le<br>bouchon, un épais nuage de fumée s''échappe de cette<br>bouteille en bronze peint. À la fin de votre tour, la<br>fumée se dissipe dans une gerbe de feu inoffensive et<br>un éfrit apparaît en un espace inoccupé dans un rayon<br>de 9 m.<br>La première fois que la bouteille est ouverte, le MJ<br>jette le dé et consulte la table ci-après pour déterminer<br>ce qui se produit.1d10 Effet<br>1 L''éfrit vous attaque. Après 5 rounds de combat,<br>l''éfrit disparaît et la bouteille perd sa magie.<br>2-9 L''éfrit comprend les mêmes langues que vous<br>et obéit à vos ordres pendant 1 heure, après<br>quoi il retourne dans la bouteille, scellée par un<br>nouveau bouchon. La bouteille ne peut pas être<br>débouchée pendant 24 heures. Lors des deux<br>prochains débouchages de la bouteille, le même<br>effet se produit. Si l''on ouvre la bouteille une<br>quatrième fois, l''éfrit s''enfuit, disparaît et la<br>bouteille perd sa magie.<br>10 L''éfrit comprend les mêmes langues que vous<br>et peut lancer souhait une fois pour vous. Il dis -<br>paraît après avoir exaucé le souhait (au bout de<br>1 heure sans cela) et la bouteille perd sa magie.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bracelets d''archer', '<p>Tant que vous portez ces bracelets, vous avez la maî -<br>trise de l''arc long et de l''arc court, et recevez un bonus<br>de +2 aux jets de dégâts effectués avec ces armes.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Bracelets de défense', '<p>Tant que vous portez ces bracelets et ne portez ni<br>armure ni bouclier, vous recevez un bonus de +2 à la CA.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Brasero de contrôle des élémentaires du feu', '<p>Tant que ce brasero se trouve dans un rayon de 1,50 m<br>de vous, vous pouvez entreprendre l''action Magie<br>pour convoquer un élémentaire du feu . L''élémentaire<br>apparaît en un espace inoccupé aussi près que possible<br>du brasero, comprend les mêmes langues que vous,<br>obéit à vos ordres et joue son tour juste après vous à<br>votre rang d''initiative. Il disparaît au bout de 1 heure,<br>s''il meurt, ou si vous le révoquez par une action Bonus.<br>Le brasero ne peut plus être utilisé de cette manière<br>avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Broche de défense', '<p>Tant que vous portez cette broche, vous bénéficiez<br>de la Résistance aux dégâts de force et de l''Immunité<br>contre les dégâts du sort projectile magique .</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape d''invisibilité', '<p>Cette cape dispose de 3 charges et récupère quotidien -<br>nement 1d3 charges dépensées, à l''aube. Tant que vous<br>portez cette cape, vous pouvez entreprendre l''action<br>Magie pour vous couvrir la tête de sa capuche et<br>dépenser 1 charge, ce qui vous octroie l''état Invisible<br>pendant 1 heure. L''effet prend fin prématurément<br>si vous vous décoiffez de la capuche (pas d''action<br>requise) ou cessez de porter la cape.<br>235Cape de déplacement</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape de déplacement', '<p>Tant que vous portez cette cape, elle projette magi -<br>quement un double illusoire de vous-même qui vous<br>fait apparaître à côté de votre véritable position.<br>Toutes les créatures subissent le Désavantage à leurs<br>jets d''attaque contre vous. Si vous subissez des dégâts,<br>cette propriété cesse de fonctionner jusqu''au début de<br>votre tour suivant. Cette propriété est réprimée quand<br>votre Vitesse tombe à 0 et tant qu''elle le reste.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape de l''arachnide', '<p>Ce somptueux vêtement en soie noire est brodé de<br>fils d''argent. Tant que vous le portez, vous recevez les<br>bénéfices suivants :<br>Déplacement arachnéen. Aucune toile d''araignée<br>ne peut vous coincer ; vous pouvez vous déplacer<br>librement à travers toute toile d''araignée comme s''il<br>s''agissait d''un Terrain difficile.<br>Pattes d''araignée. Vous bénéficiez d''une Vitesse<br>d''escalade égale à votre Vitesse et pouvez monter,<br>descendre ou vous déplacer à l''horizontale sur une<br>surface verticale ou encore au plafond, la tête en bas,<br>tout en gardant les mains libres.<br>Résistance au poison. Vous bénéficiez de la<br>Résistance aux dégâts de poison.<br>Toile d''araignée. Vous pouvez lancer toile d''araignée<br>(DD de sauvegarde 13). La toile d''araignée créée par ce<br>sort remplit le double de la surface normale. Une fois<br>utilisée, cette propriété ne peut plus resservir avant<br>l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape de la chauve-souris', '<p>Tant que vous portez cette cape, vous bénéficiez<br>de l''Avantage aux tests de Dextérité (Discrétion).<br>Dans une zone de Lumière faible ou de Ténèbres, vous<br>pouvez saisir les bords de la cape à deux mains et l''uti -<br>liser pour recevoir une Vitesse de vol de 12 m. Si vous<br>lâchez les bords de la cape en volant de cette manière,<br>ou si vous n''êtes plus dans une zone de Lumière faible<br>ou de Ténèbres, vous perdez cette Vitesse de vol.<br>Tant que vous portez cette cape dans une zone de<br>Lumière faible ou de ténèbres, vous pouvez lancer<br>métamorphose sur vous-même, qui vous transforme<br>en chauve-souris . Sous cette forme, vous conservez<br>vos valeurs d''Intelligence, de Sagesse et de Charisme.<br>La cape ne peut plus être utilisée de cette manière<br>jusqu''à l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape de la raie manta', '<p>Tant que vous portez cette cape, vous pouvez respirer<br>sous l''eau et disposez d''une Vitesse de nage de 18 m.Cape de protection</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape de vol', '<p>Tant que vous portez cette cape, vous pouvez entre -<br>prendre l''action Magie pour la transformer en paire<br>d''ailes dans votre dos. Elles persistent pendant<br>1 heure, sauf si vous y mettez fin prématurément au<br>prix de l''action Magie. Ces ailes vous octroient une<br>Vitesse de vol de 18 m. Si vous êtes en l''air lorsqu''elles<br>disparaissent, vous tombez. Après leur disparition,<br>vous ne pouvez plus les déployer pendant 1d12 heures.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape du prestidigitateur', '<p>Cette cape sent légèrement le soufre. Quand vous la<br>portez, vous pouvez l''utiliser pour lancer porte dimen -<br>sionnelle au prix de l''action Magie. Cette propriété ne<br>peut plus resservir avant l''aube suivante.<br>En vous téléportant avec ce sort, vous laissez der -<br>rière vous un nuage de fumée. Cette fumée entraîne<br>une Visibilité réduite dans l''espace que vous venez de<br>quitter jusqu''à la fin de votre tour suivant.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cape elfique', '<p>Tant que vous portez cette cape, tout test de Sagesse<br>(Perception) effectué pour vous repérer subit le<br>Désavantage, et vous bénéficiez de l''Avantage à vos<br>tests de Dextérité (Discrétion).</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Carafe intarissable', '<p>Ce récipient muni d''un bouchon clapote quand on<br>l''agite, comme s''il contenait de l''eau. La carafe pèse 1 kg.<br>Vous pouvez consacrer l''action Magie à retirer le<br>bouchon et prononcer l''un des trois mots de com -<br>mande, après quoi une quantité d''eau douce ou d''eau<br>salée (au choix) s''écoule de la carafe. L''eau cesse de<br>couler au début de votre tour suivant. Choisissez<br>parmi les mots de commande suivants :<br>Éclaboussure. La carafe produit 4 litres d''eau.<br>Fontaine. La carafe produit 20 litres d''eau.<br>Geyser. La carafe produit 120 litres d''une eau qui<br>jaillit sous la forme d''une Ligne de 9 m de long pour<br>30 cm de large. En tenant la carafe, vous pouvez<br>orienter le geyser dans une direction (pas d''action<br>requise). Une créature de votre choix présente sur<br>cette Ligne doit réussir un jet de sauvegarde de<br>Force DD 13 sous peine de subir 1d4 dégâts conton -<br>dants et l''état À terre. Au lieu d''une créature, vous<br>pouvez prendre pour cible un objet sur la Ligne qui<br>n''est porté par personne et dont le poids n''excède<br>pas 100 kg. L''objet est renversé par le geyser.<br>236Carillon d''ouverture</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Carillon d''ouverture', '<p>Ce tube de métal creux, long d''environ 30 cm, pèse<br>500 g. Au prix de l''action Magie, vous pouvez tinter le<br>carillon pour lancer déblocage . Le son habituel du sort<br>est remplacé par le tintement clair du carillon, audible<br>à 90 m.<br>Le carillon peut être utilisé 10 fois. Il se fissure et<br>devient inutilisable après la dixième utilisation.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Carquois efficace', '<p>Chacun des trois compartiments de ce carquois est lié<br>à un espace extradimensionnel qui permet au carquois<br>de contenir de nombreux objets sans jamais peser plus<br>de 1 kg. Le compartiment court peut contenir jusqu''à<br>60 flèches, carreaux ou objets comparables. Le com -<br>partiment de taille intermédiaire peut contenir jusqu''à<br>18 javelines ou objets comparables. Le compartiment<br>long peut contenir jusqu''à 6 objets longs de type arc,<br>bâton de combat ou lance.<br>Vous pouvez extraire n''importe quel objet contenu<br>dans le carquois comme si vous le tiriez d''un carquois<br>ou d''un fourreau ordinaire.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Ceinturon de force de géant', '<p>requise)<br>Tant que vous portez ce ceinturon, votre valeur de<br>Force devient celle octroyée par l''objet. Le type de<br>géant détermine cette valeur (cf. table ci-dessous).<br>Si votre Force est déjà supérieure ou égale à la valeur<br>octroyée par le ceinturon, l''objet n''a aucun effet<br>sur vous.<br>Ceinturon For Rareté<br>(collines)21 Rare<br>(givre ou pierres)23 Très rare<br>Ceinturon de force de géant (feu) 25 Très rare<br>(nuages)27 Légendaire<br>(tempêtes)29 Légendaire</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Ceinturon des nains', '<p>Tant que vous portez ce ceinturon, vous recevez les<br>bénéfices suivants :<br>Ami des nains. Vous bénéficiez de l''Avantage aux tests<br>de Charisme (Persuasion) effectués dans le cadre<br>d''interactions avec des nains et des duergars.<br>Nain. Vous parlez et lisez le nain.<br>Robustesse. Votre Constitution augmente de 2,<br>jusqu''à un maximum de 20.En outre et tant que vous êtes harmonisé avec le<br>ceinturon, il y a chaque jour à l''aube 50 % de chances<br>qu''une barbe fournie vous couvre le menton si votre<br>physiologie vous le permet, ou que votre barbe épais -<br>sisse si vous en arboriez déjà une.<br>Si vous n''êtes ni nain ni duergar, vous recevez les<br>bénéfices suivants tant que vous portez ce ceinturon :<br>Résilience. Vous bénéficiez de la Résistance aux<br>dégâts de poison. Vous avez en outre l''Avantage aux<br>jets de sauvegarde visant à éviter l''état Empoisonné<br>ou à y mettre un terme sur vous-même.<br>Vision dans le noir. Vous disposez de la Vision dans<br>le noir sur 18 m.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Chapeau de déguisement', '<p>Tant que vous portez ce chapeau sur la tête, vous pou -<br>vez lancer le sort déguisement . Le sort prend fin si vous<br>ne coiffez plus le chapeau.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Chapeau mille-sorts', '<p>avec un Magicien)<br>Ce chapeau pointu présente les propriétés suivantes.<br>Focaliseur d''incantation. Tant que vous le tenez, ce<br>chapeau peut faire office de focaliseur d''incantation<br>pour vos sorts de Magicien. Tout sort que vous lancez<br>pas le biais du chapeau reçoit une composante soma -<br>tique spéciale : vous devez plonger la main dans le<br>chapeau et en « sortir » le sort.<br>Sort inconnu. Tant que vous tenez le chapeau, vous<br>pouvez tenter de lancer un sort du 1er niveau ou supé -<br>rieur que vous ne connaissez pas. Ce sort doit figurer<br>sur la liste de sorts du Magicien, être d''un niveau que<br>vous pouvez lancer, et le coût de ses composantes<br>matérielles ne doit pas excéder 1 000 po. Une fois<br>le sort choisi, dépensez un emplacement de sort<br>correspondant au niveau du sort. Puis, pour déter -<br>miner si vous parvenez à le lancer, effectuez un test<br>d''Intelligence (Arcanes) (DD 10 + le niveau du sort).<br>En cas de réussite, vous lancez le sort en respectant<br>son temps d''incantation, et ne pouvez plus recourir à<br>cette propriété avant d''avoir terminé un Repos court<br>ou long. En cas d''échec, vous ne lancez pas le sort,<br>mais produisez un effet aléatoire, déterminé selon la<br>table ci-après.<br>Tout sort lancé par le biais du chapeau reprend votre<br>DD de sauvegarde des sorts et votre bonus d''attaque<br>de sort.<br>2371d100 Effet<br>01-50 Vous lancez un sort déterminé aléatoirement<br>en jetant 1d10 : 1 , agrandissement/rapetissement<br>(effet agrandissement) ; 2 , agrandissement/rape -<br>tissement (effet rapetissement) ; 3 , boule de<br>feu ; 4, bourrasque ; 5, éclair ; 6, force fantasma -<br>gorique ; 7, invisibilité (lancé sur vous) ; 8 , lueurs<br>féeriques ; 9, métamorphose ; 10, nuage<br>nauséabond .<br>51-55 Vous subissez l''état Étourdi jusqu''à la fin de<br>votre tour suivant, convaincu qu''un événement<br>extraordinaire vient de se produire.<br>56-60 Une nuée de papillons inoffensifs remplit un<br>Cube de 3 m dans un rayon de 9 m de vous.<br>La nuée se disperse au bout de 1 minute.<br>61-65 Vous sortez un objet non magique du cha -<br>peau. Lancez 1d4 pour déterminer de quel<br>objet il s''agit : 1 , une fiole d''acide ; 2 , une<br>flasque de feu grégeois ; 3, un pied-de-biche ;<br>4, une torche allumée.<br>66-70 En proie à une poussée de « maladie<br>magique », vous subissez l''état Empoisonné<br>pendant 1 heure.<br>71-75 Vous subissez l''état Pétrifié jusqu''à la fin de<br>votre tour suivant.<br>76-80 Vous sortez un objet non magique du chapeau.<br>Lancez 1d4 pour déterminer de quel objet il<br>s''agit : 1 , une dague ; 2 , un grappin attaché<br>à une corde ; 3 , un sac de chausse-trappes ;<br>4, une gemme d''une valeur de 50 po.<br>81-85 Une créature apparaît dans un espace<br>inoccupé, le plus près possible de vous.<br>La créature n''est pas sous votre contrôle,<br>agit normalement et disparaît après 1 heure<br>ou lorsqu''elle tombe à 0 point de vie. Lancez<br>1d4 pour déterminer la créature : 1 , un cha -<br>meau ; 2, un éléphant ; 3, une mule ;<br>4, un serpent constricteur .<br>86-90 Une nuée de chauve-souris Hostile<br>sort du chapeau, occupe votre espace et<br>vous attaque.<br>91-95 Un portail vertical bidirectionnel de 3 m,<br>donnant sur un autre plan d''existence, s''ouvre<br>en un espace inoccupé dans un rayon de 9 m<br>de vous et reste ouvert jusqu''à la fin de votre<br>tour suivant. Le MJ détermine sur quel plan<br>il mène.<br>96-00 Vous sortez un objet magique du chapeau.<br>Lancez 1d6 pour déterminer la rareté de<br>l''objet : 1 à 3 , courant ; 4 ou 5 , peu courant ;<br>6, rare. Le MJ choisit l''objet, qui disparaît au<br>bout de 1 heure s''il n''est pas consommé ou<br>détruit avant cela.Chapelet mystique</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Chaussons de l''araignée', '<p>Tant que vous portez ces chaussures légères, vous<br>pouvez vous déplacer dans toutes les directions le<br>long des surfaces verticales, ainsi que sur les plafonds,<br>tout en gardant les mains libres. Vous bénéficiez d''une<br>Vitesse d''escalade égale à votre Vitesse. Toutefois,<br>ces chaussons ne facilitent en rien les déplacements<br>sur une surface glissante, couverte d''huile ou de glace<br>par exemple.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cierge d''invocation', '<p>La magie du cierge est activée lorsque celui-ci est<br>allumé, ce qui nécessite l''action Magie. Après avoir<br>brûlé 4 heures, le cierge est détruit. Vous pouvez<br>l''éteindre auparavant, afin de le réutiliser par la suite.<br>Déduisez le temps de combustion par incréments de<br>1 minute de son temps de combustion total.<br>Tant qu''il brûle, le cierge émet une Lumière faible<br>dans un rayon de 9 m. Dans cette lumière, vous béné -<br>ficiez de l''Avantage aux Tests d20. En outre, tout Clerc<br>ou Druide dans sa lumière peut lancer ses sorts du<br>1er niveau préparés sans dépenser d''emplacements<br>de sort.<br>Une autre option, lorsque vous allumez le cierge<br>pour la première fois, consiste à lancer le sort portail .<br>Dans ce cas, le cierge est détruit. Le portail créé par<br>238le sort ouvre sur un Plan Extérieur spécifique choisi<br>par le MJ ou déterminé par le hasard selon la table<br>ci-après.<br>1d100 Plan Extérieur 1d100 Plan Extérieur<br>01-05 Abysses 52-56 Hadès<br>06-10 Achéron 57-61 Limbes<br>11-17 Arborée 62-69 Méchanus<br>18-25 Arcadie 70-77 Mont Céleste<br>26-33 Bytopie 78-82 Neuf Enfers<br>34-38 Carcères 83-87 Pandémonium<br>39-46 Élysée 88-95 Terres des Bêtes<br>47-51 Géhenne 96-00 Ysgard<br>Cimeterre de célérité<br>Arme (cimeterre), très rare (Harmonisation requise)<br>Vous recevez un bonus de +2 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique. Vous pou -<br>vez en outre effectuer une attaque avec ce cimeterre<br>par une action Bonus à chacun de vous tours.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Colle universelle', '<p>Cette substance visqueuse d''un blanc laiteux permet<br>de créer un lien adhésif permanent entre deux objets.<br>Cette colle doit être stockée dans un pot ou une<br>flasque dont on a préalablement enduit l''intérieur<br>d''huile d''insaisissabilité . Lorsqu''on le découvre, un tel<br>récipient contient 1d6 + 1 doses de 30 grammes.<br>Une dose de colle suffit à couvrir une surface car -<br>rée de 30 cm de côté. L''application d''une dose de colle<br>universelle requiert l''action Utilisation, sachant que la<br>colle met 1 minute à sécher. Après cela, le lien qu''elle<br>crée ne peut être défait que par l''application de solvant<br>universel, d'' huile éthérée ou par le sort souhait .</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Collier d''adaptation', '<p>Tant que vous portez ce collier, vous pouvez respirer<br>normalement dans n''importe quel environnement et<br>bénéficiez de l''Avantage aux jets de sauvegarde visant<br>à éviter l''état Empoisonné ou à y mettre fin.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Collier de boules de feu', '<p>1d6 + 3 perles sont enfilées sur le collier. Vous pouvez<br>entreprendre l''action Magie pour détacher une perle et<br>la lancer jusqu''à 18 m. Quand la perle arrive en fin de<br>trajectoire, elle détone en produisant l''équivalent du<br>sort du 3e niveau boule de feu (DD de sauvegarde 15).<br>Vous pouvez lancer plusieurs perles, voire le collier<br>entier, en une seule fois. Dans ce cas, augmentez les<br>dégâts de la boule de feu de 1d6 pour chaque perle en<br>plus de la première (maximum 12d6).Cor de dévastation</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cor du Valhalla', '<p>(bronze) ou légendaire (fer)<br>Souffler dans le cor s''effectue au prix de l''action<br>Magie. En réponse, des esprits guerriers du plan<br>d''Ysgard apparaissent en des espaces inoccupés dans<br>un rayon de 18 m de vous. Chaque esprit utilise le<br>profil berserker et retourne en Ysgard au bout de<br>1 heure, ou quand il tombe à 0 point de vie. Ces esprits<br>ont l''aspect de combattants vivants et respirants, et<br>bénéficient de l''Immunité contre les états Charmé et<br>Effrayé. Une fois ce cor utilisé, il ne peut plus resservir<br>pendant 7 jours.<br>Quatre types de cor du Valhalla sont connus, chacun<br>fait d''un métal différent. Le type de cor détermine<br>combien d''esprits répondent à l''invocation, ainsi que<br>l''éventuel prérequis pour son utilisation. Le MJ en<br>choisit le type ou le détermine aléatoirement selon la<br>table suivante.<br>Si vous soufflez dans le cor sans répondre au pré -<br>requis, les esprits invoqués vous attaquent. Si vous<br>remplissez le prérequis, ils sont Amicaux envers vous<br>et vos alliés, et obéissent à vos ordres.<br>1d100 Type de cor Esprits Prérequis<br>01-40 Argent 2 Aucun<br>41-75 Airain 3 Maîtrise de toutes<br>les armes courantes<br>76-90 Bronze 4 Formation au port de<br>toutes les armures<br>intermédiaires<br>91-00 Fer 5 Maîtrise de toutes<br>les armes de guerre</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Corde d''ascension', '<p>Cette corde de 18 m de long peut supporter jusqu''à<br>1 500 kg. En tenant une extrémité de la corde, vous<br>pouvez entreprendre l''action Magie pour ordonner<br>à l''autre extrémité de s''animer et de se déplacer vers<br>la destination de votre choix, dans les limites de la<br>239longueur de la corde. L''extrémité animée se déplace<br>de 3 m à votre tour la première fois que vous lui en<br>donnez l''ordre et de 3 m supplémentaires au début<br>de chacun de vos tours suivants jusqu''à avoir atteint<br>sa destination ou que vous lui ordonniez de s''arrêter.<br>Vous pouvez en outre ordonner à la corde de se nouer<br>solidement à un objet ou de se détacher, de passer<br>de corde lisse à corde à nœuds et inversement ou de<br>s''enrouler pour le transport.<br>Si vous optez pour une corde à nœuds, des nœuds<br>épais apparaissent tous les 30 cm environ sur toute sa<br>longueur. Sous sa forme à nœuds, la corde ne mesure<br>plus que 15 m de long et octroie l''Avantage aux tests<br>de caractéristique effectués pour grimper.<br>Elle présente le profil suivant : CA 20, 20 pv,<br>Immunité contre les dégâts psychiques et de poison.<br>Tant qu''il lui reste au moins 1 point de vie, elle récu -<br>père 1 pv toutes les 5 minutes. Une corde qui tombe à<br>0 pv est détruite.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Corde d''enchevêtrement', '<p>Cette corde est longue de 9 m. En tenant une extré -<br>mité de la corde, vous pouvez entreprendre l''action<br>Magie pour ordonner à l''autre extrémité de se proje -<br>ter en avant afin d''enchevêtrer une créature que vous<br>voyez dans un rayon de 6 m. La cible doit réussir un jet<br>de sauvegarde de Dextérité DD 15 sous peine de subir<br>l''état Entravé. Vous pouvez libérer la cible en lâchant<br>votre extrémité de la corde (qui se love alors sponta -<br>nément dans l''espace de la cible) ou en répétant l''ordre<br>par une action Bonus (la corde s''enroule alors dans<br>votre main).<br>Une cible Entravée par la corde peut consacrer<br>une action à effectuer, au choix, un test de Force<br>(Athlétisme) ou de Dextérité (Acrobaties) DD 15.<br>En cas de réussite, elle n''est plus Entravée par la<br>corde. Si vous tenez toujours la corde lorsqu''une cible<br>s''en échappe, vous pouvez jouer votre Réaction pour<br>ordonner à la corde de s''enrouler dans votre main ;<br>sans cela, elle se love dans l''espace de la cible.<br>Elle présente le profil suivant : CA 20, 20 pv,<br>Immunité contre les dégâts psychiques et de poison.<br>Tant qu''il lui reste au moins 1 point de vie, elle récu -<br>père 1 pv toutes les 5 minutes. Une corde qui tombe à<br>0 pv est détruite.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cube de force', '<p>Ce cube mesure 2 à 3 centimètres d''arête. Chaque face<br>s''orne d''un symbole distinct. Il vous suffit d''appuyer<br>sur une face et de dépenser le nombre de charges<br>requis pour lancer le sort associé à cette face (DD de<br>sauvegarde 17), comme indiqué sur la table « Faces du<br>cube de force ».<br>Le cube dispose de 10 charges et récupère quoti -<br>diennement 1d6 charges dépensées, à l''aube.Faces du cube de force<br>Sort Coût en charges<br>armure du mage 1<br>bouclier 1<br>petite hutte 3<br>sanctuaire privé 4<br>sphère résiliente 4<br>mur de force 5</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Cube des plans', '<p>Ce cube mesure 7,5 cm d''arête et diffuse une énergie<br>magique palpable. Les six faces du cube sont chacune<br>liées à un plan d''existence distinct, l''un d''eux étant le<br>Plan Matériel. Les autres faces sont liées à des plans<br>déterminés par le MJ.<br>Le cube dispose de 3 charges et récupère quotidien -<br>nement 1d3 charges dépensées, à l''aube. Au prix de<br>l''action Magie, vous pouvez dépenser 1 charge du cube<br>pour lancer l''un des sorts ci-après par le biais du cube.<br>Changement de plan. Appuyer deux fois sur une<br>face du cube vous permet de lancer changement de<br>plan , qui transporte les cibles sur le plan d''existence<br>lié à cette face.<br>Portail. Appuyer sur une face du cube vous permet<br>de lancer portail, qui ouvre un portail vers le plan<br>d''existence lié à cette face.<br>Dague venimeuse<br>Arme (dague), rare<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>Par une action Bonus, vous enduisez magiquement la<br>lame de poison. Le poison persiste 1 minute ou jusqu''à<br>ce qu''une attaque avec cette arme touche une créa -<br>ture. Cette créature doit réussir un jet de sauvegarde<br>de Constitution DD 15 sous peine de subir 2d10 dégâts<br>de poison et l''état Empoisonné pendant 1 minute.<br>L''arme ne peut plus resservir de cette manière avant<br>l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Diadème de destruction', '<p>Tant que vous portez ce diadème, vous pouvez lan -<br>cer rayon ardent par son biais (+5 pour toucher).<br>Le diadème ne peut alors plus relancer ce sort avant<br>l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Élixir de jouvence', '<p>Lorsque vous buvez cet élixir, votre âge physique dimi -<br>nue de 1d6 + 6 ans, jusqu''à un minimum de 13 ans.<br>Chaque fois que vous ingérez un élixir de jouvence<br>au-delà du premier, il y a 10 % de chances cumulatives<br>que vous vieillissiez au contraire de 1d6 + 6 ans.<br>240Un minuscule cœur en suspension dans ce liquide<br>ambré bat encore, contre toute logique. Ces ingré -<br>dients disparaissent à l''ouverture de la potion.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Élixir de santé', '<p>Boire cette potion vous guérit de toute contagion<br>magique. Les états ci-après prennent en outre fin pour<br>vous : Assourdi, Aveuglé, Empoisonné et Paralysé.<br>Ce liquide rouge limpide est constellé de petites<br>bulles de lumière.<br>Encensoir de contrôle des élémentaires<br>de l''air</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Éventail enchanté', '<p>Lorsque vous tenez cet éventail, vous pouvez lan -<br>cer bourrasque (DD de sauvegarde 13) par son biais.<br>Cependant, chaque nouvelle utilisation avant l''aube<br>suivante fragilise l''objet : les risques qu''il se désa -<br>grège augmentent de 20 % à chaque fois. Si cela se<br>produit, il est réduit à l''état de lambeaux non magiques<br>inutilisables.<br>Fer gelé<br>Arme (cimeterre, coutille, épée à deux mains,<br>épée courte, épée longue ou rapière), très rare<br>(Harmonisation requise)<br>Lorsque votre jet d''attaque touche avec cette arme<br>magique, la cible subit 1d6 dégâts de froid supplé -<br>mentaires. En outre et tant que vous tenez l''arme,<br>vous bénéficiez de la Résistance aux dégâts de feu.<br>Lorsqu''il gèle, l''arme émet une Lumière vive sur un<br>rayon de 3 m et une Lumière faible sur 3 m de plus.<br>En dégainant cette arme, vous pouvez décider<br>d''éteindre toutes les flammes non magiques dans un<br>rayon de 9 m. Une fois utilisée, cette propriété ne peut<br>plus resservir pendant 1 heure.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Fers de rapidité', '<p>Ces fers à cheval vont par quatre. Au prix de l''action<br>Magie, vous pouvez mettre l''un des fers au contact du<br>sabot d''un cheval ou d''une créature équivalente : le<br>fer se fixe au sabot. Retirer un fer nécessite également<br>l''action Magie.<br>Si les quatre fers sont fixés aux sabots de la même<br>créature, la Vitesse de celle-ci augmente de 9 m.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Fers du zéphyr', '<p>Ces fers à cheval vont par quatre. Au prix de l''action<br>Magie, vous pouvez mettre l''un des fers au contact du<br>sabot d''un cheval ou d''une créature équivalente : le fer<br>se fixe au sabot. Retirer un fer nécessite également<br>l''action Magie.Si les quatre fers sont fixés aux sabots d''un cheval<br>ou d''une créature équivalente, ils permettent à cette<br>créature de se déplacer normalement tout en flot -<br>tant 10 cm au-dessus du sol. Cet effet signifie que la<br>créature peut traverser ou survoler des surfaces non<br>solides ou instables, comme l''eau ou la lave. La créa -<br>ture ferrée ne laisse aucune trace et n''est pas soumise<br>au Terrain difficile. Elle peut en outre voyager pen -<br>dant 12 heures par jour sans recevoir de niveau<br>d''Épuisement.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Figurine merveilleuse', '<p>Une figurine merveilleuse est une statuette qui tient<br>dans la poche. Si vous entreprenez l''action Magie<br>pour lancer la figurine en un point du sol situé dans<br>un rayon de 18 m, elle devient une créature vivante<br>précisée dans la description de la figurine ci-après.<br>Si l''espace où la créature est censée apparaître est<br>occupé par d''autres créatures ou objets, ou si cet<br>espace est insuffisant pour la créature, la figurine ne<br>se transforme pas.<br>La créature est Amicale envers vous et vos compa -<br>gnons. Elle comprend les mêmes langues que vous,<br>obéit à vos ordres et joue son tour juste après vous<br>à votre rang d''initiative. Si vous ne prononcez<br>aucune instruction, la créature se défend si besoin,<br>mais n''entreprend pas d''autre action.<br>La créature existe pour une durée propre à chaque<br>figurine. À la fin de cette durée, elle retrouve son état<br>de figurine. Elle reprend cette forme prématurément<br>si la créature tombe à 0 point de vie ou si vous consa -<br>crez l''action Magie à toucher la créature afin qu''elle<br>redevienne une figurine. Quand la créature retrouve<br>l''état de figurine, sa propriété ne peut plus être réuti -<br>lisée pendant un certain temps, comme indiqué dans<br>sa description.<br>Chèvres d''ivoire (rare). Ces statuettes de chèvre en<br>ivoire sont toujours créées par série de trois. Chaque<br>chèvre a un aspect unique et fonctionne différemment<br>des autres. Leurs propriétés se déclinent comme suit :<br>Chèvre industrieuse. Cette figurine peut se trans -<br>former en chèvre géante pendant un maximum de<br>3 heures. Une fois cette figurine utilisée, vous ne<br>pouvez plus y recourir pendant 30 jours.<br>Chèvre terrifiante. Cette figurine peut se transfor -<br>mer en chèvre géante pendant un maximum de<br>3 heures. Cette chèvre ne peut pas porter d''attaque,<br>mais vous pouvez retirer ses cornes (de façon inof -<br>fensive) et les utiliser comme armes. L''une des<br>cornes devient une lance d''arçon +1, l''autre une<br>épée longue +2 . Retirer une corne nécessite l''action<br>Magie. Quand la chèvre retrouve sa forme de figu -<br>rine, elle récupère aussi ses cornes et les armes<br>disparaissent. Tant que vous chevauchez la chèvre,<br>toute créature Hostile qui débute son tour dans<br>une Émanation de 9 m centrée sur la chèvre doit<br>réussir un jet de sauvegarde de Sagesse DD 15 sous<br>peine subir l''état Effrayé pendant 1 minute (l''état<br>242prend également fin si vous ne chevauchez plus la<br>chèvre ou que celle-ci retrouve sa forme de figurine).<br>Une créature Effrayée réitère le JS à la fin de chacun<br>de ses tours et met un terme à l''effet sur elle-même<br>en cas de réussite. En cas de réussite, une créature<br>est immunisée contre cet effet pendant 24 heures.<br>Une fois cette figurine utilisée, vous ne pouvez plus y<br>recourir pendant 15 jours.<br>Chèvre voyageuse. Cette figurine se transforme en<br>chèvre de taille G avec le profil du cheval de selle .<br>Elle dispose de 24 charges, et chaque heure ou frac -<br>tion d''heure passée sous forme de chèvre coûte<br>1 charge. Tant qu''il lui reste des charges, vous pouvez<br>l''utiliser aussi souvent que vous le souhaitez. Quand<br>elle n''a plus de charge, elle redevient une figurine à<br>laquelle vous ne pouvez plus recourir pendant 7 jours,<br>échéance à laquelle elle récupère toutes ses charges.<br>Chien d''onyx (rare). Cette statuette de chien en<br>onyx se transforme en molosse pendant un maximum<br>de 6 heures. Ce molosse est doté d''une Intelligence de<br>8 et parle le commun. Il dispose en outre de la Vision<br>aveugle sur 18 m. Une fois cette figurine utilisée, vous<br>ne pouvez plus y recourir pendant 7 jours.<br>Chouette de serpentine (rare). Cette statuette<br>de chouette en serpentine peut se transformer en<br>chouette géante pendant un maximum de 8 heures.<br>La chouette communique par télépathie avec vous,<br>quelle que soit la distance qui vous en sépare, à condi -<br>tion de se trouver sur le même plan d''existence que<br>vous. Une fois cette figurine utilisée, vous ne pouvez<br>plus y recourir pendant 2 jours.<br>Corbeau d''argent (peu courant). Cette statuette en<br>argent se transforme en corbeau pendant un maxi -<br>mum de 12 heures. Une fois cette figurine utilisée,<br>vous ne pouvez plus y recourir pendant 2 jours. Sous<br>forme de corbeau, la figurine vous octroie le pouvoir<br>de lancer messager animal sur elle.<br>Destrier d''obsidienne (très rare). Ce cheval<br>d''obsidienne polie se transforme en horriflamme<br>(destrier noir) pendant un maximum de 24 heures.<br>L''horriflamme ne combat que pour se défendre. Une<br>fois cette figurine utilisée, vous ne pouvez plus y<br>recourir pendant 5 jours.<br>Chaque fois que vous utilisez la figurine, il y a 10 %<br>de chances qu''elle reste sourde à vos ordres, y compris<br>si vous lui intimez de retrouver sa forme de figurine.<br>Si vous chevauchez l''horriflamme alors qu''elle est<br>sourde à vos ordres, vous-même et la créature êtes<br>instantanément transportés vers un endroit aléa -<br>toire du plan d''existence d''Hadès, où l''horriflamme<br>retrouve sa forme de figurine.<br>Éléphant de marbre (rare). Cette statuette de<br>marbre figure un éléphant qui barrit. Elle se trans -<br>forme en éléphant pendant un maximum de<br>24 heures. Une fois cette figurine utilisée, vous ne pou -<br>vez plus y recourir pendant 7 jours.<br>Griffon de bronze (rare). Cette statuette en bronze<br>représente un griffon rampant (cabré, en héraldique).<br>Elle peut se transformer en griffon pendant un maximum de 6 heures. Une fois cette figurine utilisée,<br>vous ne pouvez plus y recourir pendant 5 jours.<br>Lions d''or (rare). Ces statuettes de lion en or sont<br>toujours créées par paire. Vous pouvez utiliser une<br>figurine ou les deux simultanément. Chacune peut se<br>transformer en lion pendant un maximum de 1 heure.<br>Une fois un lion utilisé, vous ne pouvez plus recourir à<br>sa figurine pendant 7 jours.<br>Mouche d''ébène (rare). Cette statuette d''ébène,<br>taillée à l''effigie d''un taon, peut se transformer en<br>mouche géante (cf. profil joint) pendant un maximum<br>de 12 h et peut faire office de monture. Une fois cette<br>figurine utilisée, vous ne pouvez plus y recourir pen -<br>dant 2 jours.<br>Mouche géante<br>Bête de taille G, non alignée<br>CA 11 Initiative +1 (11)<br>Pv 19 (3d10 + 3)<br>Vitesse 9 m, vol 18 m<br>MOD JS MOD JS MOD JS<br>For 14 +2+2 Dex 13+1+1 Con 13+1+1<br>Int 2 −4−4 Sag 10 +0+0 Cha 3−4−4<br>Sens Vision dans le noir 18 m, Perception passive 10<br>Langues aucune<br>FP 0 (0 PX ; BM +2)</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Flasque de fer', '<p>Lorsque vous tenez cette flasque de fer au bouchon de<br>laiton, vous pouvez entreprendre l''action Magie pour<br>cibler une créature que vous voyez dans un rayon de<br>18 m. Si la flasque est vide et que cette cible est origi -<br>naire d''un plan d''existence autre que celui sur lequel<br>vous vous trouvez, elle doit réussir un jet de sauve -<br>garde de Sagesse DD 17 sous peine d''être emprisonnée<br>dans la flasque. Une cible qui a déjà été séquestrée<br>dans la flasque a l''Avantage à ce JS. Une fois empri -<br>sonnée, une créature reste confinée dans la flasque<br>jusqu''à ce qu''elle en soit libérée. La flasque ne peut<br>détenir qu''une créature à la fois. Une créature piégée<br>dans la flasque ne vieillit pas et n''a pas besoin de res -<br>pirer, manger ou boire.<br>Vous pouvez entreprendre l''action Magie pour<br>retirer le bouchon de la flasque et libérer la créature<br>qu''elle contient. La créature obéit alors à vos ordres<br>pendant 1 heure ; elle les comprend même si elle<br>ne connaît pas la langue dans laquelle ils sont for -<br>mulés. Si vous ne donnez aucun ordre ou si vous lui<br>intimez une activité susceptible d''entraîner sa mort<br>ou son emprisonnement, la créature se défend mais ne<br>prend aucune autre initiative. À la fin de cette durée,<br>la créature se comporte à nouveau en accord avec sa<br>personnalité et son alignement.<br>Le sort identification révèle si la flasque contient une<br>créature, mais seule l''ouverture du récipient permet<br>d''en déterminer la nature exacte. Une flasque de fer qui<br>243vient d''être découverte peut déjà contenir une créa -<br>ture choisie par le MJ.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Flûte des égouts', '<p>Tant que cette flûte est sur vous, les rats ordinaires et<br>les rats géants vous sont Indifférents et ne vous atta -<br>queront pas, sauf si vous les menacez ou leur faites<br>du mal.<br>Cette flûte dispose de 3 charges et récupère quoti -<br>diennement 1d3 charges dépensées, à l''aube. Si vous<br>en jouez au prix de l''action Magie, vous pouvez dépen -<br>ser 1 à 3 charges par une action Bonus, appelant à<br>vous une nuée de rats pour chaque charge dépensée,<br>à condition qu''il y ait suffisamment de rats dans un<br>rayon de 750 m susceptibles de répondre à cet appel<br>(cette décision appartient au MJ). S''il n''y a pas assez de<br>rats dans les environs pour former une nuée, la charge<br>est perdue. Les nuées appelées se déplacent vers l''ori -<br>gine de la mélodie par le chemin le plus sûr, mais elles<br>ne sont pas sous votre contrôle.<br>Chaque fois qu''une nuée de rats qui n''est pas sous<br>le contrôle d''une autre créature arrive dans un rayon<br>de 9 m de vous alors que vous jouez de la flûte, la<br>nuée effectue un jet de sauvegarde de Sagesse DD 15.<br>En cas de réussite, elle se comporte normalement et<br>ne peut plus être influencée par la musique de la flûte<br>pendant 24 heures. En cas d''échec, la nuée est envoû -<br>tée par cette mélodie et devient Amicale envers vous<br>et vos alliés, et le reste tant que vous continuez à en<br>jouer chaque round au prix de l''action Magie. Une nuée<br>Amicale obéit à vos ordres. En l''absence d''instructions<br>précises, une nuée Amicale se défend au besoin mais<br>n''entreprend pas d''autre action. Si une nuée Amicale<br>commence son tour à plus de 9 m de vous, votre<br>contrôle sur elle prend fin et elle se comporte norma -<br>lement. Elle ne peut alors plus être influencée par la<br>musique de la flûte pendant 24 heures.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Flûte terrifiante', '<p>Cette flûte dispose de 3 charges et récupère quotidien -<br>nement 1d3 charges dépensées, à l''aube. Vous pouvez<br>entreprendre l''action Magie pour en jouer et dépenser<br>1 charge afin de faire naître une mélodie envoûtante.<br>Chaque créature de votre choix dans un rayon de 9 m<br>doit réussir un jet de sauvegarde de Sagesse DD 15<br>sous peine de subir l''état Effrayé pendant 1 minute.<br>En cas d''échec, la créature peut réitérer ce JS à la<br>fin de chacun de ses tours et met un terme à l''effet<br>sur elle-même en cas de réussite. En cas de réussite,<br>la créature est immunisée contre l''effet de cette flûte<br>pendant 24 heures.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Forteresse instantanée', '<p>Au prix de l''action Magie, vous placez au sol cette sta -<br>tuette en adamantium de 2,5 cm puis, en prononçant<br>le mot de commande, provoquez sa croissance rapide en tour en adamantium de section carrée. Répéter le<br>mot de commande fait revenir la tour à sa forme de<br>statuette, ce qui ne fonctionne que lorsque la tour est<br>inoccupée. Chaque créature se trouvant dans la zone<br>où la tour apparaît est repoussée dans un espace inoc -<br>cupé extérieur à la tour, mais adjacent à elle. Tout objet<br>présent dans la zone et n''étant porté par personne est<br>lui aussi repoussé par la tour.<br>La tour est large de 6 m et haute de 9 m, avec des<br>meurtrières sur tous les flancs et un crénelage en son<br>sommet. Son intérieur se divise en deux étages reliés<br>par une échelle, un escalier ou un plan incliné (à votre<br>guise). L''échelle, escalier ou plan incliné aboutit à une<br>trappe qui ouvre sur le toit. À sa création, la tour pré -<br>sente une seule porte au rez-de-chaussée, orientée<br>vers vous. Cette porte ne s''ouvre que sur votre ordre,<br>que vous pouvez prononcer par une action Bonus.<br>Elle est immunisée contre le sort déblocage et toute<br>magie comparable.<br>Sa magie empêche la tour de basculer. Toit, porte<br>et murs ont chacun le profil suivant : CA 20, 100 pv ;<br>Immunité contre les dégâts contondants, perforants et<br>tranchants sauf ceux des armes de siège ; Résistance à<br>tous les autres dégâts. Rendre sa taille de statuette à<br>la tour ne répare pas les dégâts qu''elle a subis. Seul le<br>sort souhait peut réparer la tour (cette utilisation<br>du sort compte comme la reproduction d''un sort du<br>8e niveau ou inférieur). Chaque incantation de souhait<br>fait regagner tous ses points de vie à la tour.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gantelets de puissance d''ogre', '<p>Votre Force passe à 19 tant que vous portez ces gan -<br>telets. Ils restent sans effet sur vous si votre Force est<br>supérieure ou égale à 19 sans que vous les portiez.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gants de chapardeur', '<p>Une fois enfilés, ces gants sont imperceptibles.<br>Tant que vous les portez, vous recevez un bonus de +5<br>à vos tests de Dextérité (Escamotage).</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gants de nage et d''escalade', '<p>Tant que vous portez ces gants, vous recevez une<br>Vitesse d''escalade et une Vitesse de nage égales à votre<br>Vitesse, ainsi qu''un bonus de +5 aux tests de Force<br>(Athlétisme) visant à escalader ou nager.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gants piégeurs de projectiles', '<p>Si un jet d''attaque vous touche avec une arme à dis -<br>tance ou dotée de la propriété Lancer alors que vous<br>portez ces gants, jouer votre Réaction vous permet de<br>réduire les dégâts subis de 1d10 + votre modificateur<br>de Dextérité à condition d''avoir une main libre. Si vous<br>réduisez ces dégâts à 0, vous pouvez attraper l''arme<br>(ou le projectile) si ses dimensions vous permettent<br>de la tenir.<br>244Gardienne<br>Arme (toute arme de corps à corps), légendaire<br>(Harmonisation requise)<br>Vous recevez un bonus de +3 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>La première fois que vous attaquez avec l''arme à<br>chacun de vos tours, vous pouvez transférer tout ou<br>partie de son bonus à votre classe d''armure. Vous pou -<br>vez par exemple réduire le bonus à vos jets d''attaque<br>et de dégâts à +1 afin de recevoir un bonus de +2 à<br>la CA. Les bonus ajustés restent en vigueur jusqu''au<br>début de votre tour suivant, mais vous devez continuer<br>à tenir l''arme pour recevoir le bonus qu''elle octroie<br>à la CA.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gemme d''illumination', '<p>Ce prisme dispose de 50 charges. Tant que vous le<br>tenez, vous pouvez consacrer l''action Magie à pronon -<br>cer l''un de ses trois mots de commande afin de lui faire<br>produire l''un des effets suivants :<br>Premier mot de commande. La gemme projette une<br>Lumière vive sur un rayon de 9 m, et une Lumière<br>faible sur 9 m de plus. Cet effet ne consomme pas de<br>charge. Il persiste jusqu''à ce que vous réitériez le<br>mot de commande par une action Bonus ou que vous<br>utilisiez une autre fonction de la gemme.<br>Deuxième mot de commande. Vous dépensez<br>1 charge et projetez un faisceau de lumière éclatante<br>sur une créature que vous voyez dans un rayon de<br>18 m. La créature doit réussir un jet de sauvegarde<br>de Constitution DD 15 sous peine de subir l''état<br>Aveuglé pendant 1 minute. La créature réitère le JS à<br>la fin de chacun de ses tours et met un terme à l''effet<br>sur elle-même en cas de réussite.<br>Troisième mot de commande. Dépensez 5 charges :<br>la gemme projette une lumière aveuglante dans un<br>Cône de 9 m. Chaque créature prise dans le Cône<br>effectue un jet de sauvegarde comme si elle avait été<br>frappée par le faisceau créé avec le deuxième mot<br>de commande.<br>Une fois toutes les charges de la gemme dépensées,<br>celle-ci devient un joyau non magique d''une valeur<br>de 50 po.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Gemme de vision', '<p>Cette gemme dispose de 3 charges. Au prix de l''action<br>Magie, vous pouvez dépenser 1 charge. Pendant les<br>10 prochaines minutes, vous disposez de la Vision<br>lucide sur 36 m lorsque vous regardez à travers<br>la gemme.<br>La gemme récupère quotidiennement 1d3 charges<br>dépensées, à l''aube.Gemme élémentaire</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Havresac magique', '<p>Ce sac à dos se compose d''une poche centrale et<br>de deux poches latérales, chacune ouvrant sur un<br>espace extradimensionnel. Chaque poche latérale<br>peut contenir 100 kg de matériel pour un volume<br>maximal de 700 litres. La poche centrale peut conte -<br>nir 250 kg de matériel pour un volume maximal de<br>1 800 litres. Le havresac ne pèse que 2,5 kg, quel que<br>soit son contenu.<br>Récupérer un objet dans le havresac nécessite<br>l''action Utilisation ou une action Bonus (à votre guise).<br>Lorsque vous plongez la main dans le havresac en<br>quête d''un objet spécifique, celui-ci se trouve toujours<br>magiquement au-dessus.<br>Si l''une de ses poches est surchargée, percée ou<br>déchirée, le havresac éclate et il est détruit. Si le<br>havresac est détruit, son contenu est perdu à jamais<br>(un Artefact finit cependant toujours par réapparaître<br>quelque part). Si le havresac est retourné comme<br>un gant, son contenu se déverse sans que rien ne se<br>brise ; il doit être remis à l''endroit avant de pouvoir<br>être réutilisé.<br>Chaque poche du havresac contient suffisamment<br>d''air pour 10 minutes de ventilation, divisées par le<br>nombre de créatures qui respirent à l''intérieur.<br>Placer ce havresac dans l''espace extradimension -<br>nel créé par un sac sans fond , un puits portable ou tout<br>autre objet équivalent détruit instantanément les<br>deux objets et ouvre un portail vers le Plan Astral.<br>Ce portail s''ouvre à l''endroit où l''objet a été placé dans<br>l''autre. Toute créature dans un rayon de 3 m du por -<br>tail, si elle ne dispose pas d''un Abri total, est aspirée et<br>déposée en un lieu aléatoire du Plan Astral. Le portail<br>se referme alors. Il est à sens unique et ne peut pas<br>être rouvert.Heaume de compréhension des langues</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Heaume de télépathie', '<p>Tant que vous portez ce heaume, vous bénéficiez de la<br>télépathie à une portée de 9 m, et pouvez lancer détec -<br>tion des pensées ou suggestion (DD de sauvegarde 13)<br>par le biais du heaume. Dès que l''un de ces sorts a été<br>lancé par le biais du heaume, il ne peut plus être lancé<br>via cet objet avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Heaume de téléportation', '<p>Ce heaume dispose de 3 charges. Tant que vous le<br>portez, vous pouvez dépenser 1 charge pour lancer<br>téléportation par son biais. Le heaume récupère quoti -<br>diennement 1d3 charges dépensées, à l''aube.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Heaume scintillant', '<p>Ce heaume étincelant est serti de 1d10 diamants,<br>2d10 rubis, 3d10 opales de feu et 4d10 opales. Toute<br>gemme extraite du heaume tombe en poussière.<br>Lorsque toutes les gemmes ont été extraites ou<br>détruites, le heaume perd sa magie.<br>Tant que vous portez ce heaume, vous recevez les<br>bénéfices suivants :<br>Flammes d''opale de feu. Tant qu''il reste au moins<br>une opale de feu au heaume, vous pouvez consacrer<br>l''action Magie à nimber de flammes une arme que<br>vous tenez. Ces flammes émettent une Lumière vive<br>dans un rayon de 3 m et une Lumière faible sur 3 m de<br>plus. Les flammes sont inoffensives pour vous et pour<br>l''arme. Lorsque vous touchez une cible avec l''arme<br>enflammée, elle subit 1d6 dégâts de feu supplémen -<br>taires. Les flammes persistent jusqu''à ce que vous les<br>éteigniez par une action Bonus ou que vous rengainiez<br>ou lâchiez l''arme.<br>Lumière diamantine. Tant qu''il lui reste au moins<br>un diamant, le heaume diffuse une Émanation de 9 m.<br>Lorsqu''au moins un Mort-vivant est présent dans<br>cette zone, l''Émanation est remplie de Lumière faible.<br>Tout Mort-vivant qui débute son tour dans cette zone<br>subit 1d6 dégâts radiants.<br>Résistance rubis. Tant qu''il reste au moins un<br>rubis au heaume, vous bénéficiez de la Résistance aux<br>dégâts de feu.<br>Sorts. Vous pouvez lancer l''un des sorts suivants<br>(DD de sauvegarde 18), en utilisant comme compo -<br>sante l''une des gemmes du heaume du type spécifié :<br>boule de feu (opale de feu), embruns prismatiques (dia -<br>mant), lumière du jour (opale) ou mur de feu (rubis).<br>La gemme concernée est détruite et disparaît du<br>heaume lorsque le sort est lancé.<br>246Subir des dégâts de feu. Lancez 1d20 si vous portez<br>le heaume et subissez des dégâts de feu après avoir<br>raté un jet de sauvegarde contre un sort. Sur un résul -<br>tat de 1, le heaume émet des faisceaux de lumière<br>depuis les gemmes restantes, puis il est détruit.<br>Chaque créature prise dans une Émanation de 18 m<br>centrée sur vous doit réussir un jet de sauvegarde de<br>Dextérité DD 17 sous peine d''être frappée par un fais -<br>ceau lumineux et de subir autant de dégâts radiants<br>que le heaume compte de gemmes.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Huile éthérée', '<p>Une fiole de cette huile suffit à enduire une créature<br>de taille M ou inférieure, ainsi que tout l''équipement<br>qu''elle porte (une fiole supplémentaire est nécessaire<br>pour chaque catégorie de taille au-dessus de M).<br>L''application de l''huile prend 10 minutes. La créature<br>ointe reçoit l''effet du sort forme éthérée pendant<br>1 heure.<br>Des gouttes perlées se forment sur la paroi exté -<br>rieure de ce récipient rempli d''une huile grisâtre et<br>trouble, et s''évaporent rapidement.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Huile d''affûtage', '<p>Une fiole de cette huile peut enduire une arme de<br>corps à corps ou vingt projectiles, sachant que<br>seules les munitions et les armes de corps à corps<br>non magiques infligeant des dégâts perforants ou<br>tranchants sont affectées. L''application de l''huile<br>prend 1 minute, après quoi l''huile s''infiltre magi -<br>quement dans ce qu''elle recouvre, ce qui transforme<br>l''arme enduite en arme +3 (les munitions enduites en<br>projectiles +3 ).<br>Dans cette huile incolore et gélatineuse scintillent<br>de minuscules paillettes d''argent.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Huile d''insaisissabilité', '<p>Une fiole de cette huile suffit à enduire une créature<br>de taille M ou inférieure, ainsi que tout l''équipement<br>qu''elle porte (une fiole supplémentaire est nécessaire<br>pour chaque catégorie de taille au-dessus de M).<br>L''application de l''huile prend 10 minutes. La créature<br>ointe reçoit l''effet du sort liberté de mouvement pen -<br>dant 8 heures.<br>Au lieu de cela, l''huile peut être versée au sol au prix<br>de l''action Magie, auquel cas elle couvre un carré de<br>3 m et reproduit l''effet du sort graisse dans cette zone<br>pendant 8 heures.<br>Cet onguent noir et gluant, épais et lourd, s''écoule<br>pourtant très vite.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Jatte de contrôle des élémentaires de l''eau', '<p>Tant que cette jatte est remplie d''eau et se trouve dans<br>un rayon de 1,50 m, vous pouvez entreprendre l''action<br>Magie pour convoquer un élémentaire de l''eau . L''élémentaire apparaît en un espace inoccupé aussi<br>près que possible de la jatte, comprend les mêmes lan -<br>gues que vous, obéit à vos ordres et joue son tour juste<br>après vous à votre rang d''initiative. Il disparaît au<br>bout de 1 heure, s''il meurt, ou si vous le révoquez par<br>une action Bonus. La jatte ne peut plus être utilisée de<br>cette manière avant l''aube suivante.<br>La jatte mesure environ 30 cm de diamètre et 15 de<br>profondeur. Sa contenance est de 12 litres environ.<br>Javeline de foudre<br>Arme (javeline), peu courante<br>Chaque fois que vous réussissez un jet d''attaque avec<br>cette arme magique, vous pouvez choisir d''infliger des<br>dégâts de foudre au lieu de dégâts perforants.<br>Éclair. Lorsque vous lancez cette arme sur une cible<br>située à 36 m ou moins de vous, vous pouvez renoncer<br>au jet d''attaque à distance pour transformer l''arme en<br>éclair. Cet éclair forme une Ligne de 1,50 m de large<br>entre vous et la cible. La cible et chaque créature prise<br>dans la Ligne (vous excepté) effectuent un jet de sau -<br>vegarde de Dextérité DD 13, et subissent 4d6 dégâts<br>de foudre en cas d''échec, la moitié en cas de réussite.<br>Aussitôt après avoir infligé ces dégâts, l''arme réap -<br>paraît dans votre main. Cette propriété ne peut plus<br>resservir avant l''aube suivante.<br>Lame porte-bonheur<br>Arme (cimeterre, coutille, épée à deux mains, épée<br>courte, épée longue, rapière ou serpe), légendaire<br>(Harmonisation requise)<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique. Tant que<br>l''arme est sur vous, vous recevez en outre un bonus de<br>+1 aux jets de sauvegarde.<br>Chance. Si l''arme est sur vous et si vous ne subissez<br>pas l''état Neutralisé, vous pouvez faire appel à sa<br>chance (pas d''action requise) pour relancer un Test d20<br>raté. Vous devez garder le deuxième jet. Une fois utili -<br>sée, cette propriété ne peut plus resservir avant l''aube<br>suivante.<br>Souhait. L''arme est dotée de 1d3 charges. En la<br>tenant, vous pouvez dépenser 1 charge et lancer sou -<br>hait par son intermédiaire. Une fois utilisée, cette<br>propriété ne peut plus resservir avant l''aube suivante.<br>L''arme perd cette propriété quand toutes ses charges<br>ont été dépensées.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Lanterne de révélation', '<p>Lorsqu''elle est allumée, cette lanterne à capote brûle<br>pendant 6 heures avec 50 cl d''huile, en projetant une<br>Lumière vive dans un rayon de 9 m et une Lumière<br>faible sur 9 m supplémentaires. Les créatures et objets<br>Invisibles sont visibles sous la Lumière vive de la lan -<br>terne. Vous pouvez entreprendre l''action Utilisation<br>pour abaisser la capote, ce qui réduit la lumière de la<br>lanterne à une Lumière faible dans un rayon de 1,50 m.<br>247Lentilles de netteté</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Lentilles de netteté', '<p>Ces lentilles en cristal s''appliquent sur les yeux.<br>Tant que vous les portez, votre vision s''améliore net -<br>tement jusqu''à 30 cm, vous octroyant la Vision dans<br>le noir à cette portée et l''Avantage aux tests d''Intelli -<br>gence (Investigation) effectués pour examiner quelque<br>chose à cette même portée.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Liens de fer', '<p>Cette sphère de fer rouillé, d''un diamètre de 7,5 cm,<br>pèse 500 g. Vous pouvez entreprendre l''action Magie<br>pour jeter la sphère sur une créature de taille TG ou<br>inférieure que vous voyez dans un rayon de 18 m.<br>À mesure que la sphère vole vers sa cible, elle se<br>déplie pour former un enchevêtrement de bandes<br>métalliques.<br>Effectuez un jet d''attaque à distance, le bonus<br>d''attaque étant égal à votre modificateur de Dextérité<br>plus votre bonus de maîtrise. Si l''attaque touche, la<br>cible subit l''état Entravé jusqu''à ce que vous consacriez<br>une action Bonus à la libérer d''une simple instruction.<br>Si vous libérez la cible ou si l''attaque la rate, les bandes<br>se contractent pour reformer la sphère.<br>Une créature, y compris celle qui est Entravée, peut<br>consacrer une action à toucher les liens de fer pour<br>effectuer un test de Force (Athlétisme) DD 20 afin<br>de les briser. En cas de réussite, l''objet est détruit<br>et la créature Entravée est libérée. En cas d''échec,<br>toutes les autres tentatives de cette même créature<br>échouent automatiquement jusqu''à ce que 24 heures<br>se soient écoulées.<br>Une fois ces liens utilisés, ils ne peuvent plus resser -<br>vir avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Lunettes du nyctalope', '<p>Tant que vous chaussez ces lunettes teintées, vous<br>bénéficiez de la Vision dans le noir à 18 m. Si vous<br>disposiez déjà de la Vision dans le noir, le port de ces<br>lunettes en augmente la portée de 18 m.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Manteau de résistance aux sorts', '<p>Vous avez l''Avantage aux jets de sauvegarde contre les<br>sorts quand vous portez ce manteau.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Manuel d''exercices physiques', '<p>Ce livre aux inscriptions chargées de magie dispense<br>de précieux conseils en matière d''exercices physiques.<br>Si vous consacrez 48 heures sur une période maximale<br>de 6 jours à étudier le contenu de l''ouvrage et à le<br>mettre en pratique, votre valeur de Force augmente de<br>2, jusqu''à un maximum de 30. Le manuel perd alors sa<br>magie, mais la retrouve après un siècle.Manuel de vitalité</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Manuel de vivacité', '<p>Ce livre aux inscriptions chargées de magie dispense<br>de précieux conseils en matière d''exercices de coordi -<br>nation et d''équilibre. Si vous consacrez 48 heures sur<br>une période maximale de 6 jours à étudier le contenu<br>de l''ouvrage et à le mettre en pratique, votre valeur de<br>Dextérité augmente de 2, jusqu''à un maximum de 30.<br>Le manuel perd alors sa magie, mais la retrouve après<br>un siècle.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Manuel des golems', '<p>Cet ouvrage renferme les informations et incanta -<br>tions nécessaires à l''assemblage d''un type spécifique<br>de golem. Le MJ en choisit le type ou le détermine<br>aléatoirement selon la table suivante. Pour déchiffrer<br>et utiliser ce manuel, vous devez être un incantateur<br>disposant d''au moins deux emplacements de sort du<br>5e niveau. Une créature incapable d''utiliser le manuel<br>des golems et qui tente de le lire subit 6d6 dégâts<br>psychiques.<br>Pour créer un golem, vous devez consacrer le<br>nombre de jours indiqué sur la table et travailler sans<br>relâche avec le manuel à portée de main sans prendre<br>plus de 8 heures de Repos par jour. Vous devez éga -<br>lement acquitter le coût indiqué pour acheter les<br>matériaux nécessaires.<br>Une fois la création du golem terminée, des flammes<br>mystiques dévorent le livre. Le golem s''anime lorsque<br>les cendres du manuel sont dispersées sur lui.<br>Reportez-vous à « Monstres » pour le profil de jeu du<br>golem. Il est sous votre contrôle, vous comprend et<br>obéit à vos ordres.<br>1d20 Golem Temps Prix<br>1-5 Golem d''argile 30 jours 65 000 po<br>6-17 Golem de chair 60 jours 50 000 po<br>18 Golem de fer 120 jours 100 000 po<br>19-20 Golem de pierre 90 jours 80 000 po<br>Marteau de tonnerre<br>Arme (maillet d''armes ou marteau de guerre),<br>légendaire (Harmonisation requise)<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>248L''arme dispose de 5 charges. Vous pouvez dépen -<br>ser 1 charge et effectuer une attaque à distance avec<br>cette arme, en la lançant comme si elle était dotée<br>de la propriété Lancer avec une portée normale de<br>6 m et une portée longue de 18 m. Si l''attaque touche,<br>l''arme fait retentir un coup de tonnerre audible dans<br>un rayon de 90 m. La cible et toutes les créatures dans<br>un rayon de 9 m d''elle doivent réussir un jet de sauve -<br>garde de Constitution DD 17 sous peine de subir l''état<br>Étourdi jusqu''à la fin de votre tour suivant. Aussitôt<br>après avoir touché ou raté sa cible, l''arme revient<br>dans votre main. L''arme récupère quotidiennement<br>1d4 + 1 charges dépensées, à l''aube.<br>Souveraineté gigante. Tant que persiste votre<br>Harmonisation avec l''arme et que vous portez un cein -<br>turon de force de géant ou des gantelets de puissance<br>d''ogre également soumis à votre Harmonisation, vous<br>recevez les bénéfices suivants :<br>Fléau des géants. Lorsque vous obtenez un 20 sur<br>le d20 d''un jet d''attaque effectué avec cette arme<br>contre un Géant, la créature doit réussir un jet de<br>sauvegarde de Constitution DD 17 sous peine de<br>mourir sur le coup.<br>Puissance gigante. La valeur de Force octroyée par<br>votre ceinturon de force de géant ou vos gantelets de<br>puissance d''ogre augmente de 4, jusqu''à un maximum<br>de 30.<br>Marteau volant des nains<br>Arme (marteau de guerre), très rare (Harmonisation<br>requise avec un nain ou une créature harmonisée avec<br>un ceinturon des nains)<br>Vous recevez un bonus de +3 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique. Elle est<br>dotée de la propriété Lancer avec une portée normale<br>de 6 m et une portée longue de 18 m. Lorsque vous<br>touchez avec une attaque à distance à l''aide de cette<br>arme, celle-ci inflige 1d8 dégâts de force supplémen -<br>taires (2d8 si la cible est un Géant). Aussitôt après<br>avoir touché ou raté sa cible, l''arme revient dans<br>votre main.<br>Masse d''anéantissement<br>Arme (masse d''armes), rare (Harmonisation requise)<br>Quand vous touchez un Fiélon ou un Mort-vivant avec<br>cette arme magique, cette créature subit 2d6 dégâts<br>radiants supplémentaires. S''il reste 25 points de vie<br>ou moins à la cible après application de ces dégâts,<br>elle doit réussir un jet de sauvegarde de Sagesse DD 15<br>sous peine d''être détruite. En cas de réussite, la créa -<br>ture subit toutefois l''état Effrayé jusqu''à la fin de votre<br>tour suivant.<br>Lumière. Tant que vous tenez cette arme en main,<br>elle émet une Lumière vive sur un rayon de 6 m et une<br>Lumière faible sur 6 m de plus.Masse destructrice<br>Arme (masse d''armes), rare<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique. Ce bonus<br>passe à +3 lorsque vous utilisez l''arme pour attaquer<br>un Artificiel.<br>Lorsque vous obtenez un 20 sur un jet d''attaque<br>effectué avec cette arme, la cible subit 7 dégâts<br>contondants supplémentaires, ou 14 dégâts conton -<br>dants supplémentaires s''il s''agit d''un Artificiel. Tout<br>Artificiel qui se retrouve avec 25 points de vie ou<br>moins après application de ces dégâts est détruit.<br>Masse terrifiante<br>Arme (masse d''armes), rare (Harmonisation requise)<br>Cette arme magique dispose de 3 charges et récupère<br>quotidiennement 1d3 charges dépensées, à l''aube.<br>En tenant l''arme, vous pouvez entreprendre l''action<br>Magie et dépenser 1 charge pour en libérer une vague<br>de terreur. Chaque créature de votre choix dans un<br>rayon de 9 m doit réussir un jet de sauvegarde de<br>Sagesse DD 15 sous peine de subir l''état Effrayé pendant<br>1 minute. Une créature ainsi Effrayée doit consacrer<br>ses tours à tenter de s''éloigner le plus possible de vous,<br>et elle ne peut pas effectuer d''attaques d''Opportunité.<br>Dans le cadre d''une action, elle ne peut entreprendre<br>que Pointe ou tenter de se libérer d''un effet qui<br>l''empêche de se déplacer. Si elle n''a nulle part où aller,<br>elle peut entreprendre l''action Esquive. La créature réi -<br>tère le JS à la fin de chacun de ses tours et met un terme<br>à l''effet sur elle-même en cas de réussite.<br>Massue tonnante<br>Arme (massue), très rare (Harmonisation requise)<br>Tant que persiste votre Harmonisation avec cette<br>arme magique, votre Force est de 20, à moins qu''elle<br>soit déjà égale ou supérieure à cette valeur. L''arme<br>inflige 1d8 dégâts de tonnerre supplémentaires à<br>toute créature qu''elle touche, et 3d8 dégâts de ton -<br>nerre supplémentaires aux objets qu''elle touche et qui<br>ne sont portés par personne.<br>L''arme est dotée des propriétés supplémentaires<br>suivantes.<br>Coup de tonnerre. Au prix de l''action Magie, vous<br>pouvez frapper l''arme contre une surface dure pour<br>créer un puissant coup de tonnerre audible à 90 m.<br>Vous générez également un Cône d''énergie tonitruante<br>de 9 m. Chaque créature prise dans le Cône doit réus -<br>sir un jet de sauvegarde de Force DD 15 sous peine<br>de subir l''état À terre. Dans ce Cône, les objets non<br>magiques qui ne sont portés par personne subissent<br>3d8 dégâts de tonnerre.<br>Tremblement de terre. Au prix de l''action Magie,<br>vous pouvez frapper l''arme contre le sol pour déclen -<br>cher une intense perturbation sismique dans un<br>cercle de 15 m de rayon centré sur le point d''impact.<br>Les structures en contact avec le sol de cette zone<br>subissent 50 dégâts contondants, et chaque créa -<br>ture touchant le sol de la zone doit réussir un jet de<br>249sauvegarde de Dextérité DD 20 sous peine de subir<br>l''état À terre. Une créature qui se concentre doit éga -<br>lement réussir un jet de sauvegarde de Constitution<br>DD 20 sous peine de perdre sa Concentration. Vous<br>pouvez en outre ouvrir une faille de 9 m de profon -<br>deur et 3 m de large n''importe où dans la zone. Toute<br>créature se trouvant à cet endroit effectue un jet de<br>sauvegarde de Dextérité DD 20. Elle tombe dans la<br>faille en cas d''échec, et parvient à se décaler au bord<br>du gouffre en cas de réussite. Toute structure située<br>à l''endroit où s''ouvre la faille s''effondre dans celle-ci.<br>Une fois cette propriété utilisée, vous ne pouvez plus y<br>recourir avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Médaillon des pensées', '<p>Ce médaillon dispose de 5 charges. Lorsque vous le<br>portez, vous pouvez dépenser 1 charge pour lancer<br>détection des pensées (DD de sauvegarde 13) par son<br>intermédiaire. Le médaillon récupère quotidienne -<br>ment 1d4 charges dépensées, à l''aube.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Menottes dimensionnelles', '<p>L''action Utilisation vous permet d''employer cet<br>objet pour menotter une créature subissant l''état<br>Neutralisé. Les menottes s''ajustent à toute créature<br>de taille P, M ou G. Ces menottes empêchent la<br>créature menottée de recourir à tout moyen de<br>déplacement extradimensionnel, y compris la télé -<br>portation ou le voyage vers un autre plan d''existence.<br>Elles n''empêchent toutefois pas la créature de traver -<br>ser un portail interdimensionnel.<br>Vous-même et toute créature que vous désignez<br>lorsque vous utilisez ces menottes pouvez consacrer<br>l''action Utilisation à les retirer. Une fois tous les<br>30 jours, la créature menottée peut effectuer un test<br>de Force (Athlétisme) DD 30. En cas de réussite, elle se<br>libère et détruit les menottes.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Miroir d''emprisonnement', '<p>Quand on regarde indirectement dans ce miroir de<br>1,20 m de haut pour 60 cm de large, on y distingue<br>des reflets fugitifs de créatures. Le miroir pèse 25 kg<br>avec le profil suivant : CA 11, 10 pv, Immunité contre<br>les dégâts psychiques et de poison, Vulnérabilité aux<br>dégâts contondants. Réduit à 0 point de vie, il se brise<br>en mille morceaux, définitivement détruit.<br>Si le miroir est accroché à une surface verticale et<br>que vous vous trouvez à 1,50 m ou moins de lui, vous<br>pouvez entreprendre l''action Magie et prononcer un<br>mot de commande pour l''activer. Il reste activé jusqu''à<br>ce que vous entrepreniez l''action Magie et répétiez le<br>mot de commande pour le désactiver.<br>Toute créature autre que vous qui voit son reflet<br>dans le miroir activé alors qu''elle se tient dans un<br>rayon de 9 m de l''objet doit réussir un jet de sau -<br>vegarde de Charisme DD 15 sous peine d''être emprisonnée, avec tout ce qu''elle porte, dans l''un<br>des douze cachots extradimensionnels du miroir.<br>Une créature qui connaît la nature du miroir effectue<br>ce jet de sauvegarde avec l''Avantage, tandis que les<br>Artificiels réussissent automatiquement le JS.<br>Un cachot extradimensionnel est un espace infini<br>dans lequel flotte un épais brouillard qui réduit la<br>visibilité à 3 m. Les créatures prisonnières du miroir<br>peuvent se passer de nourriture, de boisson et de<br>sommeil et elles ne vieillissent pas. Une créature pri -<br>sonnière d''un cachot peut s''en échapper si elle recourt<br>à une magie qui permet de voyager entre les plans.<br>Dans le cas contraire, cette créature est prisonnière<br>du cachot jusqu''à ce qu''elle en soit libérée.<br>Si le miroir piège une créature alors que ses douze<br>cachots extradimensionnels sont occupés, l''objet libère<br>au hasard une créature emprisonnée pour accueillir<br>le nouveau prisonnier. Une créature libérée apparaît<br>dans un espace inoccupé en vue du miroir, mais de dos<br>par rapport à lui. Si le miroir est brisé, toutes les créa -<br>tures qu''il emprisonne sont libérées et apparaissent<br>dans des espaces inoccupés à proximité.<br>Dans un rayon de 1,50 m du miroir, vous pou -<br>vez entreprendre l''action Magie pour prononcer le<br>nom d''une créature emprisonnée ou le numéro d''un<br>cachot. La créature nommée ou prisonnière du cachot<br>annoncé apparaît sous la forme d''un reflet à la surface<br>du miroir. Vous-même et la créature pouvez alors<br>communiquer.<br>De même, vous pouvez entreprendre l''action Magie<br>et utiliser un second mot de commande pour libérer<br>une créature piégée dans le miroir. La créature libérée<br>apparaît, avec tout son équipement, dans l''espace inoc -<br>cupé le plus proche du miroir, en lui tournant le dos.<br>Placer le miroir dans un espace extradimensionnel<br>créé par un sac sans fond , un puits portable ou un objet<br>similaire détruit instantanément les deux objets et<br>ouvre un portail vers le Plan Astral. Ce portail s''ouvre<br>à l''endroit où l''objet a été placé dans l''autre. Toute<br>créature dans un rayon de 3 m du portail, si elle ne<br>dispose pas d''un Abri total, est aspirée et se retrouve<br>en un lieu aléatoire du Plan Astral. Le portail se<br>referme alors. Il est à sens unique et ne peut pas être<br>rouvert.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Orbe draconique', '<p>Chaque orbe est un globe de cristal gravé d''environ<br>25 cm de diamètre. Lorsqu''il est utilisé, il enfle pour<br>atteindre un diamètre d''environ 50 cm, tandis que de<br>la brume tourbillonne à l''intérieur.<br>Une fois harmonisé avec l''orbe, vous pouvez entre -<br>prendre l''action Magie pour scruter ses profondeurs<br>insondables. Effectuez un jet de sauvegarde de<br>Charisme DD 15. En cas de réussite, vous contrôlez<br>l''orbe aussi longtemps que l''harmonisation persiste.<br>Un échec, en revanche, vous place sous l''emprise de<br>l''Artefact en vous imposant l''état Charmé pour toute la<br>durée de l''Harmonisation.<br>250Tant que vous êtes Charmé par l''orbe, vous ne pouvez<br>pas volontairement mettre fin à cette Harmonisation<br>et l''orbe lance suggestion sur vous à volonté (sauve -<br>garde DD 18) en vous pressant d''œuvrer à ses desseins<br>maléfiques. Les désirs de l''essence du dragon peuvent<br>prendre bien des formes : anéantir un groupe spéci -<br>fique, libérer l''orbe, répandre la souffrance dans le<br>monde, faire prospérer le culte de Tiamat ou tout autre<br>sombre dessein imaginé par le MJ.<br>Sorts. L''orbe dispose de 7 charges et récupère quo -<br>tidiennement 1d4 + 3 charges dépensées, à l''aube.<br>Si vous contrôlez l''orbe, vous pouvez lancer l''un des<br>sorts de la table suivante. La table indique le nombre<br>de charges à dépenser pour lancer le sort.<br>Sort Coût en charges<br>détection de la magie 0<br>lumière du jour 1<br>protection contre la mort 2<br>scrutation (DD de sauvegarde 18) 3<br>soins (au 9e niveau) 4<br>Appel des dragons. Tant que vous contrôlez l''orbe,<br>vous pouvez, au prix de l''action Magie, émettre par<br>son biais un appel télépathique qui s''étend dans toutes<br>les directions sur 60 km. Les dragons chromatiques à<br>portée sont contraints de venir vers l''orbe au plus vite<br>et par l''itinéraire le plus direct. Les divinités draco -<br>niques, comme Tiamat, ne sont pas affectées par cet<br>appel. Les dragons chromatiques attirés par l''orbe<br>peuvent se montrer Hostiles envers vous pour les avoir<br>contraints à venir. Une fois utilisée, cette propriété ne<br>peut plus resservir pendant 1 heure.<br>Destruction d''un orbe. Un Orbe draconique est doté<br>d''une CA de 20 et ne peut être détruit que s''il subit<br>des dégâts d''une arme +3 ou du sort désintégration .<br>Nulle autre force ne saurait l''entamer.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Parchemin de sort', '<p>Un parchemin de sort renferme la formule d''un sort<br>unique, rédigée dans un code ésotérique. Si ce sort<br>figure dans votre liste de sorts, vous pouvez lire le<br>parchemin pour en lancer le sort sans composantes<br>matérielles. Sans cela, le parchemin reste illisible.<br>Lancer le sort par le biais du parchemin requiert le<br>temps d''incantation normal. Une fois le sort lancé,<br>le parchemin tombe en poussière. Si l''incantation est<br>interrompue, le parchemin n''est pas perdu.<br>Si le sort figure bien dans votre liste, mais qu''il est<br>d''un niveau supérieur à ce que vous pouvez normale -<br>ment lancer, vous effectuez un test de caractéristique<br>avec votre caractéristique d''incantation pour savoir<br>si vous parvenez à le lancer. Le DD est égal à 10 + le<br>niveau du sort. En cas d''échec, le sort s''efface du par -<br>chemin et il ne se passe rien d''autre.<br>Le niveau du sort inscrit sur un parchemin déter -<br>mine le DD de sauvegarde et le bonus d''attaque associés, ainsi que la rareté du parchemin,<br>comme indiqué sur la table suivante.<br>Niveau<br>du sort RaretéDD de<br>sauvegardeBonus à<br>l''attaque<br>Sort mineur Courant 13 +5<br>1 Courant 13 +5<br>2 Peu courant 13 +5<br>3 Peu courant 15 +7<br>4 Rare 15 +7<br>5 Rare 17 +9<br>6 Très rare 17 +9<br>7 Très rare 18 +10<br>8 Très rare 18 +10<br>9 Légendaire 19 +11<br>Copier un parchemin dans un grimoire. Un sort<br>de Magicien inscrit sur un parchemin de sort peut être<br>copié dans un grimoire. Pour ce faire, le copiste doit<br>réussir un test d''Intelligence (Arcanes) assorti d''un DD<br>égal à 10 + le niveau du sort. En cas de réussite, le sort<br>est copié. Que ce test réussisse ou échoue, le parchemin<br>de sort est détruit.</p>', 2, 93, 2, 1, 39);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Perle de force', '<p>Cette petite sphère noire de 2 cm de diamètre pèse<br>environ 30 g. Les perles de force se trouvent générale -<br>ment par poignée de 1d4 + 4.<br>Entreprendre l''action Magie permet de lancer la<br>perle à une distance maximale de 18 m. La perle pro -<br>voque une explosion à l''impact dans une Sphère de<br>3 m de rayon, ce qui la détruit. Chaque créature prise<br>dans la Sphère doit réussir un jet de sauvegarde de<br>Dextérité DD 15, sous peine de subir 5d4 dégâts de<br>force. Une sphère de force transparente entoure la<br>zone pendant 1 minute. Toute créature ayant raté le<br>JS, si elle se trouve entièrement dans la zone, est pié -<br>gée à l''intérieur de cette sphère. Les créatures qui<br>ont réussi leur sauvegarde ou qui ne sont que par -<br>tiellement dans la zone sont repoussées depuis le<br>centre de la sphère jusqu''à se retrouver entièrement<br>en dehors. Seul l''air respirable peut traverser la paroi<br>de la sphère. Les attaques et autres effets, quels qu''ils<br>soient, en sont incapables.<br>Une créature piégée peut entreprendre l''action<br>Utilisation pour pousser sur la paroi de la sphère,<br>ce qui la fait rouler à concurrence de la moitié de sa<br>propre Vitesse. On peut ramasser la sphère, qui ne<br>pèse que 500 g en raison de sa magie, quel que soit le<br>poids des créatures piégées à l''intérieur.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Perle de thaumaturgie', '<p>requise avec un incantateur)<br>Tant que cette perle est sur vous, vous pouvez<br>entreprendre l''action Magie pour récupérer un<br>251emplacement de sort dépensé du 3e niveau ou infé -<br>rieur. Une fois la perle utilisée, vous ne pouvez plus y<br>recourir avant l''aube suivante.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Perle nutritive', '<p>Cette perle gélatineuse sans saveur fond sur la langue<br>et fournit l''équivalent nutritif de 1 jour de rations.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Philtre d''amour', '<p>La première fois que vous voyez une créature dans les<br>10 minutes après avoir bu ce philtre, vous êtes séduit<br>par cette créature et recevez l''état Charmé pendant<br>1 heure.<br>Ce liquide rosé effervescent contient une impercep -<br>tible bulle en forme de cœur.<br>Pierre de contrôle des élémentaires<br>de la terre</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Pierre de Ioun', '<p>requise)<br>De la taille d''une bille, les pierres de Ioun font référence<br>à Ioun, dieu du savoir et des prophéties vénéré sur cer -<br>tains mondes. Il existe de nombreux types de pierre de<br>Ioun avec une forme et une couleur propres à chacune.<br>Quand vous entreprenez l''action Magie pour lancer<br>en l''air une pierre de Ioun , celle-ci se place en orbite<br>autour de votre tête à une distance de 1d3 x 30 cm<br>et vous octroie son bénéfice tant qu''elle tourne.<br>Vous pouvez avoir jusqu''à trois pierres de Ioun en<br>orbite simultanée autour de votre tête.<br>Chaque pierre de Ioun en orbite est considérée<br>comme un objet que vous portez. La pierre en orbite<br>évite tout contact avec les autres créatures et objets,<br>en ajustant sa trajectoire afin d''éviter les collisions et<br>en déjouant toutes les tentatives des autres créatures<br>visant à l''attaquer ou à s''en emparer.<br>Au prix de l''action Utilisation, vous pouvez saisir<br>et ranger une ou plusieurs pierres de Ioun gravitant<br>autour de votre tête. Si votre Harmonisation avec une<br>pierre de Ioun cesse alors qu''elle gravite autour de<br>vous, elle tombe au sol comme si vous l''aviez lâchée.<br>Le type de pierre définit sa rareté et ses effets.Absorption (très rare). Tant que cet ellipsoïde<br>lavande pâle gravite autour de votre tête, vous pou -<br>vez jouer votre Réaction pour annuler un sort du<br>4e niveau ou inférieur lancé par une créature que vous<br>voyez. Un sort annulé se dissipe sans produire d''effet<br>et toutes les ressources engagées par l''incantation<br>sont gaspillées. Dès que la pierre a annulé 20 niveaux<br>de sort de cette manière, elle se consume, vire au gris<br>terne et perd sa magie.<br>Absorption suprême (légendaire). Tant que cet<br>ellipsoïde marbré lavande et vert gravite autour de<br>votre tête, vous pouvez jouer votre Réaction pour<br>annuler un sort du 8e niveau ou inférieur lancé par<br>une créature que vous voyez. Un sort annulé se dissipe<br>sans produire d''effet et toutes les ressources enga -<br>gées par l''incantation sont gaspillées. Dès que la pierre<br>a annulé 20 niveaux de sort de cette manière, elle se<br>consume, vire au gris terne et perd sa magie.<br>Agilité (très rare). Votre Dextérité augmente de<br>2, jusqu''à un maximum de 20, tant que cette sphère<br>rouge foncé gravite autour de votre tête.<br>Commandement (très rare). Votre Charisme aug -<br>mente de 2, jusqu''à un maximum de 20, tant que<br>cette sphère marbrée rose et vert gravite autour de<br>votre tête.<br>Force (très rare). Votre Force augmente de 2, jusqu''à<br>un maximum de 20, tant que ce rhomboïde bleu pâle<br>gravite autour de votre tête.<br>Intellect (très rare). Votre Intelligence augmente<br>de 2, jusqu''à un maximum de 20, tant que cette sphère<br>marbrée écarlate et bleu gravite autour de votre tête.<br>Intuition (très rare). Votre Sagesse augmente de 2,<br>jusqu''à un maximum de 20, tant que cette sphère bleu<br>incandescent gravite autour de votre tête.<br>Maîtrise (légendaire). Votre bonus de maîtrise aug -<br>mente de 1 tant que ce prisme vert pâle gravite autour<br>de votre tête.<br>Protection (rare). Vous recevez un bonus de +1 à la<br>classe d''armure tant que ce prisme rose mat gravite<br>autour de votre tête.<br>Régénération (légendaire). Vous récupérez<br>15 points de vie à la fin de chaque heure tant que<br>ce fuseau blanc nacré gravite autour de votre tête,<br>à condition qu''il vous reste au moins 1 point de vie.<br>Réserve (rare). Ce prisme violet vif stocke les sorts<br>qui sont lancés dessus et les conserve jusqu''à ce<br>que vous les utilisiez. La pierre peut stocker jusqu''à<br>4 niveaux de sort à la fois. Quand on la trouve, elle<br>contient 1d4 niveaux de sort choisis par le MJ.<br>Toute créature peut lancer un sort du 1er au 4e niveau<br>dans la pierre à condition de la toucher au moment<br>de l''incantation. Le sort ne produit aucun effet hor -<br>mis celui d''être stocké dans la pierre. Si la pierre ne<br>peut pas contenir ce sort, il est dépensé sans effet.<br>Le niveau de l''emplacement utilisé pour lancer le sort<br>détermine la quantité d''espace qu''il utilise.<br>Tant que cette pierre gravite autour de votre tête,<br>vous pouvez lancer l''un des sorts qui y sont stockés.<br>Ce sort utilise le niveau d''emplacement de sort, le DD<br>252de sauvegarde des sorts, le bonus d''attaque de sort<br>et la caractéristique d''incantation de l''incantateur<br>d''origine, mais il est par ailleurs traité comme si vous<br>le lanciez. Le sort lancé depuis la pierre n''y est plus<br>stocké et libère l''espace correspondant.<br>Subsistance (rare). Vous pouvez vous passer de<br>nourriture et de boisson tant que ce fuseau translu -<br>cide gravite autour de votre tête.<br>Vigilance (rare). Tant que ce rhomboïde bleu nuit<br>gravite autour de votre tête, vous bénéficiez de<br>l''Avantage aux jets d''Initiative et aux tests de Sagesse<br>(Perception).<br>Vigueur (très rare). Votre Constitution augmente<br>de 2, jusqu''à un maximum de 20, tant que ce rhom -<br>boïde rose gravite autour de votre tête.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Pierre porte-bonheur', '<p>Tant que vous portez sur vous cette agate polie, vous<br>recevez un bonus de +1 aux tests de caractéristique et<br>aux jets de sauvegarde.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Pierres messagères', '<p>Les pierres messagères vont par deux, les motifs<br>ciselés à la surface de chacune étant assortis et faci -<br>lement reconnaissables. En tenant l''une des pierres,<br>vous pouvez lancer communication à distance par<br>son biais. La cible du sort est le porteur de l''autre<br>pierre. Si aucune créature ne porte l''autre pierre,<br>vous l''apprenez dès que vous cherchez à vous servir de<br>la vôtre, et vous ne lancez pas le sort.<br>Une fois que communication à distance est lancé par<br>l''une des pierres, celles-ci ne peuvent plus resservir<br>avant l''aube suivante. Si l''une des pierres de la paire<br>est détruite, l''autre devient non magique.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Pigments merveilleux', '<p>Cette belle boîte en bois contient 1d4 pots de pigments<br>et un pinceau (pour un poids total de 500 g).<br>En utilisant le pinceau et en dépensant 1 pot de<br>pigments, vous pouvez peindre un nombre illimité<br>d''objets tridimensionnels et d''éléments de terrain<br>(tels que murs, portes, arbres, fleurs, armes, toiles<br>d''araignée et fosses), à condition que ces éléments<br>tiennent tous dans un Cube de 6 m. L''opération prend<br>10 minutes (quel que soit le nombre d''éléments que<br>vous créez), pendant lesquelles vous devez rester dans<br>le Cube, et nécessite votre Concentration. Si votre<br>Concentration est rompue ou que vous quittez le Cube<br>avant que le travail ne soit terminé, tous les éléments<br>peints disparaissent et le pot de pigments est gaspillé.<br>Une fois le travail terminé, tous les objets et élé -<br>ments de terrain peints deviennent réels. Ainsi,<br>peindre une porte sur un mur crée-t-il une vraie porte<br>qu''on peut ouvrir sur ce qui se trouve au-delà du mur.<br>Peindre une fosse crée une véritable fosse, dont la pro -<br>fondeur totale doit se trouver dans le Cube de 6 m.Aucun objet créé par un pot de pigments ne peut<br>avoir une valeur supérieure à 25 po, tandis que la<br>valeur totale de tous les objets créés par un même pot<br>de pigments ne peut dépasser 500 po. Si vous tracez<br>des objets de plus grande valeur (comme un gros tas<br>d''or), ils paraissent authentiques, mais un examen<br>attentif révèle qu''ils sont faits de pâte, de biscuits ou<br>de quelque autre matériau sans valeur.<br>Si vous peignez une forme d''énergie comme le feu ou<br>la foudre, l''énergie se dissipe sitôt la peinture achevée,<br>sans rien endommager.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Plume magique', '<p>Cet objet ressemble à une plume. Il existe divers<br>types de plume magique, chacun avec un effet à usage<br>unique différent. Le MJ choisit le type de plume ou<br>le détermine aléatoirement selon la table « Plumes<br>magiques ». Le type de plume en définit la rareté.<br>Ancre (peu courante). Vous pouvez consacrer l''action<br>Magie à mettre la plume en contact avec un bateau ou<br>un navire. Pendant les prochaines 24 heures, le navire<br>ne peut en aucun cas être déplacé. Remettre la plume en<br>contact avec le bateau met fin à l''effet d''immobilisation.<br>Quand cet effet se termine, la plume disparaît.<br>Arbre (peu courant). Vous devez être en extérieur<br>pour utiliser cette plume. Vous pouvez entreprendre<br>l''action Magie pour mettre la plume en contact avec un<br>espace inoccupé au sol. La plume disparaît ; à sa place<br>pousse un chêne non magique. L''arbre mesure 18 m<br>de haut et son tronc 1,50 m de diamètre, la ramure au<br>sommet atteignant 6 m de rayon.<br>Bateau-cygne (rare). Vous pouvez consacrer l''action<br>Magie à mettre la plume en contact avec une étendue<br>d''eau dont le diamètre est supérieur ou égal à 18 m.<br>La plume disparaît, remplacée par un bateau de 15 m<br>de long et 6 m de large en forme de cygne géant.<br>Ce bateau est autopropulsé et se déplace sur l''eau à<br>une vitesse de 9 km par heure. Tant que vous êtes à<br>bord, vous pouvez entreprendre l''action Magie pour lui<br>ordonner de se déplacer ou de virer d''un maximum de<br>90 degrés. Le bateau persiste pendant 24 heures puis<br>disparaît. Vous pouvez révoquer l''embarcation au prix<br>de l''action Magie.<br>Éventail (peu courant). Si vous êtes à bord d''un<br>bateau à voile, vous pouvez consacrer l''action Magie<br>à lancer cette plume en l''air, à une hauteur maximale<br>de 3 m. La plume disparaît, remplacée par un éventail<br>géant qui s''agite spontanément. L''éventail flotte<br>et crée un vent fort. Ce vent gonfle les voiles du<br>navire, augmentant sa vitesse de 7,5 km/h pendant<br>8 heures. Vous pouvez révoquer l''éventail au prix de<br>l''action Magie.<br>Fouet (rare). Vous pouvez consacrer l''action Magie<br>à lancer la plume à une distance maximale de 3 m.<br>La plume disparaît, remplacée par un fouet flottant.<br>Vous pouvez ensuite, par une action Bonus, effec -<br>tuer une attaque de sort au corps à corps contre une<br>créature située dans un rayon de 3 m du fouet avec<br>253un bonus à l''attaque de +9. Si l''attaque touche, la cible<br>subit 1d6 + 5 dégâts de force.<br>Par une action Bonus, vous pouvez déplacer le fouet<br>flottant d''un maximum de 6 m et réitérer l''attaque<br>contre une créature située dans un rayon de 3 m de<br>l''arme. Le fouet disparaît au bout de 1 heure, lorsque<br>vous entreprenez une action Magie pour le révoquer,<br>ou lorsque vous mourez ou subissez l''état Neutralisé.<br>Oiseau (rare). Vous pouvez consacrer l''action<br>Magie à lancer cette plume en l''air, à une hauteur de<br>1,50 m. La plume disparaît, remplacée par un énorme<br>oiseau multicolore. L''oiseau, qui reprend le profil<br>du rukh , ne peut pas porter d''attaque. Il obéit à vos<br>ordres et peut transporter jusqu''à 250 kg en vol à sa<br>vitesse maximale (24 km/heure, pour un maximum<br>de 216 km par jour avec 1 heure de repos toutes les<br>3 heures de vol), ou 500 kg à la moitié de cette vitesse.<br>L''oiseau disparaît après avoir volé sur sa distance<br>maximale pour la journée (même chose s''il tombe à<br>0 point de vie). Vous pouvez révoquer l''oiseau au prix<br>de l''action Magie.<br>Plumes magiques<br>1d100 Plume Rareté<br>01-20 Ancre Peu courante<br>21-45 Arbre Peu courante<br>46-60 Bateau-cygne Rare<br>61-75 Éventail Peu courante<br>76-85 Fouet Rare<br>86-00 Oiseau Rare</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''agrandissement', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>« agrandissement » du sort agrandissement/rapetis -<br>sement pendant 10 minutes (aucune Concentration<br>requise).<br>La partie rouge du liquide de la potion se dilate et<br>se contracte en boucle, d''une petite perle colorant le<br>liquide incolore et vice-versa. Le processus ne s''inter -<br>rompt pas, même quand on secoue la bouteille.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''amitié avec les animaux', '<p>Lorsque vous buvez cette potion, vous pouvez lan -<br>cer le sort amitié avec les animaux au 3e niveau (DD de<br>sauvegarde 13).<br>Agiter ce liquide trouble permet de distinguer les<br>menus objets qui y flottent : écaille de poisson, plume<br>de colibri, griffe de chat, poil d''écureuil.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''escalade', '<p>Lorsque vous buvez cette potion, vous recevez une<br>Vitesse d''escalade égale à votre Vitesse pendant 1 heure. Pendant cette heure, vous avez l''Avantage aux<br>tests de Force (Athlétisme) effectués pour l''escalade.<br>La potion est divisée en nappes brunes, argentées<br>et grises évoquant des strates dans la roche. Ces cou -<br>leurs ne se mélangent pas, même quand on secoue<br>la bouteille.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''héroïsme', '<p>Lorsque vous buvez cette potion, vous recevez<br>10 points de vie temporaires qui persistent 1 heure.<br>Pendant cette heure, vous êtes sous l''effet du sort<br>bénédiction (aucune Concentration requise).<br>Ce liquide bleu bouillonne et fume comme s''il était<br>en ébullition.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''invisibilité', '<p>Le récipient de cette potion paraît vide, tout en don -<br>nant étrangement l''impression de contenir un liquide.<br>Lorsque vous buvez la potion, vous recevez l''état<br>Invisible pendant 1 heure. Cet effet prend fin prématu -<br>rément si vous effectuez un jet d''attaque, infligez des<br>dégâts ou lancez un sort.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion d''invulnérabilité', '<p>Pendant 1 minute après avoir bu cette potion,<br>vous bénéficiez de la Résistance à tous les dégâts.<br>Ce liquide sirupeux ressemble à du fer liquide.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de clairvoyance', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>du sort clairvoyance (aucune Concentration requise).<br>Le globe oculaire qui flotte dans ce liquide jaunâtre<br>disparaît quand la potion est ouverte.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de diminution', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>« rapetissement » du sort agrandissement/rapetis -<br>sement pendant 1d4 heures (aucune Concentration<br>requise).<br>La partie rouge du liquide de la potion se contracte<br>continuellement en une boule minuscule, puis se dilate<br>pour colorer le fluide incolore qui l''entoure. Le pro -<br>cessus ne s''interrompt pas, même quand on secoue<br>la bouteille.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de force de géant', '<p>Lorsque vous buvez cette potion, votre valeur de Force<br>change pendant 1 heure. Le type de géant détermine<br>cette valeur (cf. table ci-dessous). Si votre Force est<br>déjà supérieure ou égale à la valeur octroyée par la<br>potion, celle-ci n''a aucun effet sur vous.<br>254Ce liquide transparent contient un éclat de lumière<br>flottant qui évoque l''ongle d''un géant.<br>Potion Force Rareté<br>Potion de force de géant (collines) 21 Peu<br>courante<br>Potion de force de géant (givre<br>ou pierres)23 Rare<br>Potion de force de géant (feu) 25 Rare<br>Potion de force de géant (nuages) 27 Très rare<br>Potion de force de géant (tempêtes) 29 Légendaire</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de forme gazeuse', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>du sort forme gazeuse pendant 1 heure (aucune<br>Concentration requise) ou jusqu''à ce que vous mettiez<br>fin à cet effet par une action Bonus.<br>Le récipient de cette potion semble contenir du<br>brouillard dont la fluidité est cependant celle de l''eau.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de lecture des pensées', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>du sort détection des pensées (DD de sauvegarde 13)<br>pendant 10 minutes (aucune Concentration requise).<br>Dans ce liquide dense et pourpre flotte un nuage<br>ovoïde et rose.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de résistance', '<p>Lorsque vous buvez cette potion, vous recevez la<br>Résistance à un type de dégâts pendant 1 heure. Le MJ<br>en choisit le type ou le détermine aléatoirement selon<br>la table suivante.<br>1d10 Type de dégâts 1d10 Type de dégâts<br>1 Acide 6 Nécrotiques<br>2 Feu 7 Poison<br>3 Force 8 Psychiques<br>4 Foudre 9 Radiants<br>5 Froid 10 Tonnerre</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de respiration aquatique', '<p>Vous pouvez respirer sous l''eau pendant 24 heures<br>après avoir bu cette potion.<br>Ce liquide vert laiteux, dans lequel flotte une bulle<br>aux allures de méduse (acalèphe), dégage des senteurs<br>marines.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de vitalité', '<p>Lorsque vous buvez cette potion, elle supprime tous<br>vos niveaux d''Épuisement et met fin à l''éventuel état<br>Empoisonné qui vous affecte. Pendant 24 heures, vous récupérez le maximum de points de vie pour<br>chaque dé de vie dépensé.<br>Ce liquide cramoisi palpite régulièrement d''une<br>lueur sourde, tel un battement de cœur.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de vitesse', '<p>Lorsque vous buvez cette potion, vous recevez l''effet<br>du sort hâte pendant 1 minute (aucune Concentration<br>requise) sans subir la vague de léthargie qui survient<br>habituellement à la fin de l''effet.<br>Le liquide jaune de la potion, strié de noir, tourbil -<br>lonne sans qu''on l''agite.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion de vol', '<p>Lorsque vous buvez cette potion, vous recevez une<br>Vitesse de vol égale à votre Vitesse pendant 1 heure<br>et pouvez évoluer en vol stationnaire. Si vous êtes en<br>vol au moment où la potion cesse de faire effet, vous<br>tombez si vous ne disposez d''aucun autre moyen de<br>vous maintenir dans les airs.<br>Le liquide translucide de cette potion flotte dans la<br>partie supérieure du récipient, troublé par des impu -<br>retés blanches.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potion toxique', '<p>Cette décoction a l''apparence, l''odeur et le goût d''une<br>potion de guérison ou d''une autre potion bénéfique.<br>Il s''agit toutefois d''un poison masqué par quelque<br>illusion magique. Le sort identification révèle sa<br>véritable nature.<br>Si vous en buvez le contenu, vous subissez<br>4d6 dégâts de poison et devez réussir un jet de sauve -<br>garde de Constitution DD 13 sous peine de subir l''état<br>Empoisonné pendant 1 heure.</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Potions de guérison', '<p>Vous récupérez des points de vie en buvant cette<br>potion. Le nombre de points de vie dépend de la rareté<br>de la potion, comme indiqué sur la table ci-après.<br>Quelle que soit la puissance de la potion, son liquide<br>rouge étincelle lorsqu''on l''agite.<br>Potion Pv récupérés Rareté<br>Potion de guérison 2d4 + 2 Courante<br>Potion de guérison<br>(importante)4d4 + 4 Peu courante<br>Potion de guérison<br>(supérieure)8d4 + 8 Rare<br>Potion de guérison<br>(suprême)10d4 + 20 Très rare<br>255Poudre à éternuer</p>', 2, 93, 2, 1, 40);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Poudre à éternuer', '<p>Trouvée dans un petit récipient, cette fine poudre res -<br>semble à de la poussière de disparition , même le sort<br>identification la percevant comme telle. Il y en a assez<br>pour une utilisation.<br>Au prix de l''action Utilisation, vous pouvez lancer<br>cette poudre en l''air, ce qui vous soumet ainsi que<br>chaque créature prise dans une Émanation de 9 m cen -<br>trée sur vous à un jet de sauvegarde de Constitution<br>DD 15. Artificiels, Élémentaires, Morts-vivants,<br>Plantes et Vases réussissent automatiquement ce JS.<br>En cas d''échec, une créature se met à éternuer de<br>façon incontrôlable ; elle subit l''état Neutralisé et<br>s''asphyxie. La créature réitère le JS à la fin de chacun<br>de ses tours et met un terme à l''effet sur elle-même en<br>cas de réussite. L''effet prend également fin sur toute<br>créature cible du sort restauration partielle .</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Poudre dessiccative', '<p>Cette petite pochette contient 1d6 + 4 pincées de<br>poudre. Au prix de l''action Utilisation, vous dispersez<br>une pincée de cette poudre sur de l''eau, transfor -<br>mant un Cube d''eau de 4,50 m en une boulette de la<br>taille d''une bille, qui flotte ou repose près de l''endroit<br>où la poudre a été appliquée. Le poids de la boulette<br>est négligeable. Une créature qui consacre l''action<br>Utilisation à projeter violemment la boulette contre<br>une surface dure provoque son éclatement, ce qui<br>libère la quantité d''eau absorbée par la poudre. Ce fai -<br>sant, la boulette est détruite et met fin à sa magie.<br>Au prix de l''action Utilisation, vous pouvez disperser<br>une pincée de cette poudre sur un Élémentaire essen -<br>tiellement composé d''eau (par exemple un élémentaire<br>de l''eau ) situé dans un rayon de 1,50 m. Exposée à une<br>pincée de poudre, une telle créature effectue un jet de<br>sauvegarde de Constitution DD 13 et subit 10d6 dégâts<br>nécrotiques en cas d''échec, la moitié en cas de réussite.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Poussière de disparition', '<p>Cette poudre ressemble à du sable fin. Il y en a assez<br>pour une utilisation. Lorsque vous entreprenez l''action<br>Utilisation pour lancer la poudre en l''air, vous-même<br>et chaque créature ou objet pris dans une Émanation<br>de 3 m centrée sur vous recevez l''état Invisible pen -<br>dant 2d4 minutes. La durée est la même pour tous<br>les sujets, et la poussière est détruite quand sa magie<br>s''active. Aussitôt après qu''une créature affectée effec -<br>tue un jet d''attaque, inflige des dégâts ou lance un sort,<br>l''état Invisible prend fin pour elle.<br>Projectile +1, +2 ou +3<br>Arme (tout type de projectile), peu courante (+1),<br>rare (+2) ou très rare (+3)<br>Vous recevez un bonus aux jets d''attaque et de dégâts<br>effectués avec ces munitions magiques. Ce bonus est déterminé par la rareté du projectile. Dès qu''il touche<br>une cible, le projectile perd ses propriétés magiques.<br>Ces munitions sont généralement trouvées ou ven -<br>dues par quantités de dix ou vingt. Dix projectiles<br>équivalent en valeur à une potion de même rareté.<br>Projectile tueur<br>Arme (tout type de munitions), très rare<br>Ce projectile magique est conçu pour tuer les créa -<br>tures d''un type donné, que le MJ choisit ou détermine<br>aléatoirement selon la table ci-après. Si la créature<br>de ce type subit des dégâts du projectile, elle effectue<br>un jet de sauvegarde de Constitution DD 17 et subit<br>6d10 dégâts de force supplémentaires en cas d''échec,<br>la moitié en cas de réussite.<br>Après avoir infligé ces dégâts supplémentaires à une<br>créature, le projectile devient non magique.<br>1d100Type de<br>créature 1d100Type de<br>créature<br>01-10 Aberrations 56-65 Fiélons<br>11-15 Artificiels 66-70 Géants<br>16-20 Bêtes 71-75 Humanoïdes<br>21-25 Célestes 76-80 Monstruosités<br>26-35 Dragons 81-90 Morts-vivants<br>36-45 Élémentaires 91-95 Plantes<br>46-55 Fées 96-00 Vases</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Puits des mondes', '<p>Ce pan d''étoffe noire et précieuse, aussi douce que de la<br>soie, est plié aux dimensions d''un mouchoir de poche.<br>Déplié, il forme un cercle de 1,80 m de diamètre.<br>Vous pouvez entreprendre l''action Magie pour<br>déplier le puits des mondes en le plaçant sur une<br>surface solide, où il forme un portail circulaire bidi -<br>rectionnel de 1,80 m de diamètre vers un autre monde<br>ou plan d''existence. Chaque fois que l''objet ouvre un<br>portail, le MJ décide où il mène. Le portail reste ouvert<br>jusqu''à ce qu''une créature dans un rayon de 1,50 m<br>entreprenne l''action Magie pour le fermer en saisis -<br>sant les bords du tissu et en le repliant.<br>Une fois que le puits des mondes a ouvert un portail,<br>il ne peut plus en rouvrir d''autres pendant 1d8 heures.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Puits portable', '<p>Ce pan d''étoffe noire et précieuse, aussi douce que de la<br>soie, est plié aux dimensions d''un mouchoir de poche.<br>Déplié, il forme un cercle de 1,80 m de diamètre.<br>Vous pouvez entreprendre l''action Magie pour déplier<br>un puits portable et le placer sur ou contre une surface<br>solide. Le puits portable crée alors un trou extradimen -<br>sionnel de 3 m de profondeur. L''espace cylindrique à<br>l''intérieur du puits, qui existe sur un plan d''existence<br>différent, ne peut pas être utilisé pour créer un passage.<br>256Toute créature à l''intérieur d''un puits portable ouvert<br>peut en sortir en escaladant la paroi.<br>Vous pouvez consacrer l''action Magie à refermer<br>un puits portable en saisissant les bords de l''étoffe et<br>en le repliant. Plier le tissu ferme le puits. Toutes les<br>créatures et tous les objets qu''il contient restent<br>dans l''espace extradimensionnel. Quoi qu''il renferme,<br>le puits ne pèse presque rien.<br>Si le puits est replié, une créature à l''intérieur de<br>l''espace extradimensionnel peut consacrer une action<br>à effectuer un test de Force (Athlétisme) DD 10. En cas<br>de réussite, elle se fraie un chemin et apparaît dans<br>un rayon de 1,50 m du puits portable . Un puits portable<br>fermé contient suffisamment d''air pour 1 heure de<br>ventilation, à diviser par le nombre de créatures qui<br>respirent à l''intérieur.<br>Placer un puits portable dans l''espace extradimen -<br>sionnel créé par un sac sans fond , un havresac magique<br>ou tout autre objet comparable détruit instantanément<br>les deux objets et ouvre un portail vers le Plan Astral.<br>Ce portail s''ouvre à l''endroit où l''objet a été placé dans<br>l''autre. Toute créature dans un rayon de 3 m du por -<br>tail, si elle ne dispose pas d''un Abri total, est aspirée et<br>déposée en un lieu aléatoire du Plan Astral. Le portail<br>se referme alors. Il est à sens unique et ne peut pas<br>être rouvert.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Regard charmeur', '<p>Ces lentilles en cristal s''appliquent sur les yeux.<br>Elles disposent de 3 charges. Tant que vous les por -<br>tez, vous pouvez dépenser 1 ou plusieurs charges<br>pour lancer charme-personne (DD de sauvegarde 13).<br>Avec 1 charge, vous lancez le sort au 1er niveau.<br>Chaque charge supplémentaire que vous dépensez aug -<br>mente de 1 le niveau du sort. Les lentilles récupèrent<br>quotidiennement toutes les charges dépensées, à l''aube.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Robe aux étoiles', '<p>De petites étoiles blanches et argentées sont brodées<br>sur cette robe noire ou bleu nuit. Vous recevez un<br>bonus de +1 aux jets de sauvegarde tant que vous la<br>portez.<br>Six étoiles, situées sur la face avant de la robe,<br>au niveau du col, sont plus grandes que les autres.<br>Tant que vous portez cette robe, vous pouvez entre -<br>prendre l''action Magie pour retirer l''une des étoiles<br>et la dépenser afin de lancer projectile magique au<br>5e niveau. Chaque jour au crépuscule, 1d6 étoiles ainsi<br>retirées réapparaissent sur la robe.<br>Lorsque vous portez la robe, vous pouvez entre -<br>prendre l''action Magie pour entrer dans le Plan Astral<br>avec tout ce que vous portez. Vous y restez jusqu''à<br>ce que vous entrepreniez l''action Magie pour retour -<br>ner sur le plan d''existence où vous étiez auparavant.<br>Vous réapparaissez dans le dernier espace que vous<br>occupiez ou, si celui-ci n''est plus libre, dans l''espace<br>inoccupé le plus proche.Robe de l''archimage</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Robe de vision totale', '<p>Cette robe est ornée de motifs représentant des yeux.<br>Tant que vous la portez, vous recevez les bénéfices<br>suivants :<br>Sens spéciaux. Vous disposez de la Vision dans le noir<br>et de la Vision lucide sur 36 m.<br>Vision panoramique. La robe vous confère l''Avantage<br>aux tests de Sagesse (Perception) qui reposent sur<br>la vue.<br>Inconvénients. Le sort lumière lancé sur la robe ou<br>le sort lumière du jour lancé dans un rayon de 1,50 m<br>du vêtement vous fait subir l''état Aveuglé pendant<br>1 minute. À la fin de chacun de vos tours, vous pouvez<br>effectuer un jet de sauvegarde de Constitution (DD 11<br>pour lumière , DD 15 pour lumière du jour ) et mettez fin<br>à cet état en cas de réussite.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Robe du camelot', '<p>Des pièces d''étoffe de formes et de couleurs diverses<br>sont cousues sur cette robe. Lorsque vous portez la<br>robe, vous pouvez entreprendre l''action Magie pour<br>détacher l''une de ces pièces qui devient l''objet ou la<br>créature qu''elle représente. Une fois la dernière pièce<br>détachée, la robe devient un vêtement ordinaire.<br>Sur la robe sont cousus deux exemplaires de chacune<br>des pièces suivantes :<br>• Corde (enroulée)<br>• Dague<br>• Lanterne sourde (remplie d''huile et allumée)<br>• Miroir<br>• Perche<br>• Sac<br>4d4 autres pièces sont elles aussi cousues sur la robe.<br>Le MJ en choisit le type ou le détermine aléatoirement<br>selon la table suivante.<br>2571d100 Pièce<br>01-08 Sac de 100 po<br>09-15 Coffre en argent (30 cm de long, 15 de large et<br>de profondeur) d''une valeur de 500 po<br>16-22 Porte en fer (jusqu''à 3 m de large et 3 m de<br>haut, barrée du côté de votre choix) que vous<br>pouvez encastrer dans une ouverture à votre<br>portée ; elle s''adapte à l''ouverture, se fixe et<br>pivote sur ses gonds<br>23-30 10 gemmes d''une valeur unitaire de 100 po<br>31-44 Échelle en bois (7,20 m de long)<br>45-51 Cheval de selle équipé d''une selle d''équitation<br>52-59 Fossé (un Cube de 3 m) que vous pouvez dis -<br>poser au sol dans un rayon de 3 m de vous<br>60-68 4 potions de guérison<br>69-75 Barque (3,60 m de long)<br>76-83 Parchemin de sort contenant un sort du 1er, 2e<br>ou 3e niveau (choisissez)<br>84-90 2 molosses<br>91-96 Fenêtre (60 cm sur 1,20 m, profondeur jusqu''à<br>60 cm), que vous pouvez placer sur une sur -<br>face verticale à portée<br>97-00 Bélier portable</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Robe prismatique', '<p>Cette robe dispose de 3 charges et récupère quotidien -<br>nement 1d3 charges dépensées, à l''aube. Lorsque vous<br>la portez, vous pouvez entreprendre l''action Magie et<br>dépenser 1 charge pour y faire apparaître un motif<br>changeant de teintes éblouissantes, jusqu''à la fin de<br>votre tour suivant. Pendant cet intervalle, elle produit<br>une Lumière vive sur un rayon de 9 m et une Lumière<br>faible sur 9 m de plus, et les créatures qui vous voient<br>subissent le Désavantage aux jets d''attaque contre<br>vous. Toute créature dans la zone de Lumière vive, si<br>elle vous voit alors que le pouvoir de la robe est activé,<br>doit réussir un jet de sauvegarde de Sagesse DD 15<br>sous peine de subir l''état Étourdi jusqu''à ce que l''effet<br>prenne fin.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sac à malices', '<p>Ce sac en toile grise, rouille ou brune, semble vide.<br>Pourtant, pour peu que l''on fouille à l''intérieur du sac,<br>on sent la présence d''un petit objet pelucheux.<br>Entreprendre l''action Magie permet d''extraire du sac<br>l''objet pelucheux et de le lancer à une distance maxi -<br>male de 6 m. Quand il retombe, il se transforme en une<br>créature que vous déterminez en lançant le dé selon<br>la table qui correspond à la couleur du sac. Reportez-<br>vous à « Monstres » pour le profil de jeu de la créature.<br>La créature disparaît à l''aube suivante, ou plus tôt si<br>elle est réduite à 0 point de vie.Amicale envers vous et vos alliés, la créature agit<br>juste après vous à votre rang d''initiative. Par une action<br>Bonus, vous pouvez diriger le déplacement de la créa -<br>ture et l''action qu''elle entreprend à son tour suivant,<br>par exemple attaquer un adversaire. En l''absence de tels<br>ordres, la créature agit conformément à sa nature.<br>Une fois que trois objets pelucheux ont été sortis<br>du sac, celui-ci ne peut plus être réutilisé avant l''aube<br>suivante.<br>Sac à malices gris<br>1d8 Créature 1d8 Créature<br>1 Belette 5 Panthère<br>2 Rat géant 6 Blaireau géant<br>3 Blaireau 7 Loup sanguinaire<br>4 Sanglier 8 Cervidé géant<br>Sac à malices rouille<br>1d8 Créature 1d8 Créature<br>1 Rat 5 Chèvre géante<br>2 Chouette 6 Sanglier géant<br>3 Molosse 7 Lion<br>4 Chèvre 8 Ours brun<br>Sac à malices brun<br>1d8 Créature 1d8 Créature<br>1 Chacal 5 Ours noir<br>2 Grand singe 6 Belette géante<br>3 Babouin 7 Hyène géante<br>4 Autrache 8 Tigre</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sac de haricots magiques', '<p>Ce sac de toile épaisse renferme 3d4 haricots secs<br>quand on le découvre. Il pèse 250 g indépendamment<br>du nombre de haricots qu''il contient et devient un<br>objet non magique dès qu''il est vide.<br>Si vous lancez un ou plusieurs haricots hors du sac,<br>ils explosent sous forme d''une Sphère de 3 m de rayon<br>centrée sur lui. Tous les haricots ainsi lancés sont<br>détruits dans l''explosion. Chaque créature prise dans<br>la Sphère, y compris vous-même, effectue un jet de<br>sauvegarde de Dextérité DD 15, et subit 5d4 dégâts de<br>force en cas d''échec, la moitié en cas de réussite.<br>Si vous retirez un haricot du sac, le plantez dans la<br>terre ou le sable puis l''arrosez, il disparaît et produit<br>un effet 1 minute plus tard, à l''endroit où vous l''avez<br>planté. Le MJ peut choisir un effet dans la table<br>ci-après ou laisser le hasard décider.<br>2581d100 Effet<br>01 5d4 champignons poussent. Si une créature<br>mange un champignon, lancez n''importe quel<br>dé. En cas de résultat impair, la créature doit<br>réussir un jet de sauvegarde de Constitution<br>DD 15 sous peine de subir 5d6 dégâts de<br>poison et l''état Empoisonné pendant 1 heure.<br>En cas de résultat pair, la créature reçoit<br>5d6 points de vie temporaires qui persistent<br>pendant 1 heure.<br>02-10 Un geyser jaillit sur 9 m de haut en déversant<br>de l''eau, de la bière, de la mayonnaise, du<br>thé, du vinaigre, du vin ou de l''huile (au choix<br>du MJ) pendant 1d4 minutes.<br>11-20 Un sylvanien pousse. Lancez n''importe quel<br>dé. En cas de résultat impair, ce sylvanien est<br>Chaotique Mauvais. En cas de résultat pair,<br>il est Chaotique Bon.<br>21-30 Une statue de pierre à votre effigie, animée,<br>mais immobile, se dresse et profère des<br>menaces verbales à votre encontre. Si vous<br>partez et que d''autres s''en approchent,<br>elle vous décrit comme le plus odieux des<br>scélérats et intime aux nouveaux arrivants<br>de vous pourchasser. Si vous êtes sur le<br>même plan d''existence que la statue, elle sait<br>exactement où vous êtes. La statue devient<br>inanimée au bout de 24 heures.<br>31-40 Un feu de camp aux flammes vertes s''allume ;<br>il brûle pendant 24 heures (sauf si quelqu''un<br>l''éteint).<br>41-50 Trois criards poussent.<br>51-60 1d4 + 4 crapauds rose vif émergent en ram -<br>pant. Chaque fois qu''un crapaud est touché,<br>il se transforme en un monstre de taille G ou<br>inférieure au choix du MJ, qui agit selon son<br>alignement et sa nature. Le monstre persiste<br>pendant 1 minute puis disparaît dans une<br>bouffée de fumée rose vif.<br>61-70 Une bulette affamée surgit du sol et passe à<br>l''attaque.<br>71-80 Un arbre fruitier émerge. Il porte 1d10 + 20<br>fruits, dont 1d8 agissent comme autant de<br>potions déterminées aléatoirement. L''arbre<br>disparaît au bout de 1 heure. Les fruits cueil -<br>lis persistent et conservent leurs propriétés<br>magiques pendant 30 jours.1d100 Effet<br>81-90 Un nid contenant 1d4 + 3 œufs aux couleurs<br>de l''arc-en-ciel apparaît. Toute créature qui<br>mange un œuf effectue un jet de sauvegarde<br>de Constitution DD 20. En cas de réussite,<br>cette créature augmente sa valeur de carac -<br>téristique la plus basse de 1, de manière<br>permanente, le hasard décidant de laquelle<br>en cas d''égalité. En cas d''échec, la créature<br>subit 10d6 dégâts de force, provoqués par<br>une explosion interne.<br>91-95 Une pyramide à base carrée de 18 m de côté<br>surgit du sol. À l''intérieur, une chambre funé -<br>raire abrite une momie , une momie auguste<br>ou quelque autre Mort-vivant choisi par le MJ.<br>Son sarcophage contient un trésor choisi par<br>le MJ.<br>96-00 Un plant de haricot géant surgit, pous -<br>sant jusqu''à une hauteur décidée par le MJ.<br>Le sommet mène là où le MJ le décide : pano -<br>rama superbe, château d''une géante des<br>nuages, autre plan d''existence, etc.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sac dévoreur', '<p>Ce sac, qui ressemble de prime abord à un sac sans<br>fond , est en réalité la gueule par laquelle s''alimente<br>une gigantesque créature extradimensionnelle.<br>Retourner le sac comme un gant obstrue l''orifice.<br>La créature extradimensionnelle attachée au sac<br>a conscience de tout ce qui est placé à l''intérieur.<br>Toute matière d''origine animale ou végétale placée<br>en totalité dans le sac est dévorée et perdue à jamais.<br>Quand une partie d''une créature vivante est placée<br>dans le sac, comme cela se produit lorsque l''on plonge la<br>main à l''intérieur, cette créature a 50 % de risque d''être<br>happée à l''intérieur. Une créature à l''intérieur du sac<br>peut entreprendre une action pour tenter de s''échap -<br>per, ce qui lui demande de réussir un test de Force<br>(Athlétisme) DD 15. Une autre créature peut entre -<br>prendre une action pour plonger le bras dans le sac afin<br>d''en extraire une créature, ce qui lui demande de réus -<br>sir un test de Force (Athlétisme) DD 20, à la condition<br>de ne pas avoir été d''abord happée elle-même par le sac.<br>Toute créature qui commence son tour à l''intérieur du<br>sac est dévorée et son corps est détruit.<br>Les objets inanimés peuvent être stockés dans le<br>sac, qui peut contenir 30 litres de matière inerte.<br>Cependant, une fois par jour, le sac avale tous les<br>objets qu''il contient et les recrache sur un autre<br>plan d''existence. Le MJ détermine l''heure et le plan<br>d''existence.<br>Le sac est détruit s''il est troué ou déchiré. Tout son<br>contenu est alors transporté vers un lieu aléatoire du<br>Plan Astral.<br>259Sac sans fond</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sac sans fond', '<p>L''espace de stockage de ce sac est considérablement<br>plus grand que le laissent penser ses dimensions exté -<br>rieures : 1,20 m de profondeur pour 60 cm de section.<br>Le sac peut en fait contenir jusqu''à 250 kg, pour un<br>volume maximal de 1 800 litres. Il pèse 2,5 kg quel que<br>soit son contenu. Récupérer un objet dans le sac néces -<br>site l''action Utilisation.<br>S''il est surchargé, troué ou déchiré, il est détruit.<br>Son contenu est alors disséminé sur le Plan Astral.<br>Si le sac est retourné comme un gant, son contenu<br>se déverse sans que rien ne se brise, mais le sac doit<br>être remis à l''endroit avant de pouvoir être réutilisé.<br>Le sac contient suffisamment d''air pour 10 minutes de<br>ventilation, divisées par le nombre de créatures qui<br>respirent à l''intérieur.<br>Placer un sac sans fond dans l''espace extradi -<br>mensionnel créé par un havresac magique , un puits<br>portable ou tout autre objet comparable détruit ins -<br>tantanément les deux objets et ouvre un portail vers<br>le Plan Astral. Ce portail s''ouvre à l''endroit où l''objet<br>a été placé dans l''autre. Toute créature située dans<br>une Sphère de 3 m de rayon centrée sur le portail est<br>aspirée pour se retrouver en un lieu aléatoire du Plan<br>Astral. Le portail se referme alors. Il est à sens unique<br>et ne peut pas être rouvert.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Scarabée de protection', '<p>Ce médaillon en forme de scarabée offre trois béné -<br>fices lorsque vous le portez.<br>Défense. Vous recevez un bonus de +1 à la classe<br>d''armure.<br>Préservation. Le scarabée dispose de 12 charges.<br>Si vous ratez un jet de sauvegarde contre un sort<br>de Nécromancie ou un effet néfaste émanant d''un<br>Mort-vivant, vous pouvez jouer votre Réaction pour<br>dépenser 1 charge et transformer l''échec au JS en réus -<br>site. Le scarabée tombe en poussière, détruit à jamais,<br>lorsque sa dernière charge est dépensée.<br>Résistance aux sorts. Vous avez l''Avantage aux jets<br>de sauvegarde contre les sorts.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre d''absorption', '<p>Tant que vous tenez ce sceptre, vous pouvez jouer<br>votre Réaction pour absorber un sort qui ne cible que<br>vous et ne produit pas de zone d''effet. L''effet du sort<br>absorbé est annulé et son énergie est stockée dans le<br>sceptre (mais pas le sort lui-même). L''énergie est du<br>même niveau que le sort à son incantation. Un sort<br>ainsi annulé se dissipe sans produire d''effet ; toutes les<br>ressources engagées par l''incantation sont gaspillées.<br>Le sceptre peut absorber et stocker jusqu''à 50 niveaux<br>d''énergie au cours de son existence. Une fois que ce<br>sceptre a absorbé 50 niveaux d''énergie, il ne peut<br>plus en absorber. Si vous êtes la cible d''un sort que le sceptre ne peut pas stocker, l''objet n''a aucun effet sur<br>ce sort.<br>En vous harmonisant avec le sceptre, vous savez<br>combien de niveaux d''énergie il a absorbés au cours de<br>son existence et combien de niveaux d''énergie de sort<br>sont actuellement stockés à l''intérieur.<br>Si vous êtes un incantateur et tenez le sceptre, vous<br>pouvez convertir l''énergie qu''il contient en emplace -<br>ments de sort afin de lancer des sorts que vous avez<br>préparés ou que vous connaissez. Vous ne pouvez créer<br>que des emplacements de sort d''un niveau inférieur ou<br>égal à vos propres emplacements de sort, sans dépas -<br>ser le 5e niveau. Vous utilisez les niveaux stockés à la<br>place de vos propres emplacements, mais pour tout le<br>reste, ces sorts sont lancés normalement. Vous pouvez<br>par exemple utiliser 3 niveaux stockés dans le sceptre<br>comme emplacement de sort du 3e niveau.<br>Un sceptre nouvellement découvert contient généra -<br>lement 1d10 niveaux d''énergie de sort. Un sceptre qui<br>ne peut plus absorber l''énergie des sorts et qui n''a plus<br>d''énergie en stock devient non magique.</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre de puissance seigneuriale', '<p>Les jets d''attaque et de dégâts que vous effectuez avec<br>ce sceptre à ailettes, considéré comme une masse<br>d''armes magique, reçoivent un bonus de +3. Le sceptre<br>possède des propriétés associées à six boutons dif -<br>férents étagés le long du manche. Il est aussi doté de<br>trois autres propriétés, détaillées ci-après.<br>Boutons-poussoirs. Vous pouvez appuyer sur l''un<br>des boutons suivants par une action Bonus. L''effet d''un<br>bouton dure jusqu''à ce que vous pressiez un autre<br>bouton ou jusqu''à ce que vous réappuyiez sur le<br>même bouton, ce qui fait revenir le sceptre à sa forme<br>normale.<br>Bouton 1. Une lame ardente surgit de l''extrémité<br>opposée à la tête à ailettes du sceptre. Les flammes<br>émettent une Lumière vive dans un rayon de 12 m<br>et une Lumière faible sur 12 m de plus. La lame fonc -<br>tionne comme une épée longue ou une épée courte<br>magique (choisissez) qui inflige 2d6 dégâts de feu<br>supplémentaires si l''attaque touche.<br>Bouton 2. La tête à ailettes du sceptre se replie et<br>laisse la place à deux lames en croissant de lune ;<br>les jets d''attaque et de dégâts que vous effectuez<br>avec cette arme considérée comme une hache<br>d''armes magique reçoivent un bonus de +3.<br>Bouton 3. La tête à ailettes du sceptre se replie et<br>un fer de lance surgit de l''extrémité tandis que le<br>manche s''allonge pour former une hampe de 1,80 m ;<br>les jets d''attaque et de dégâts que vous effectuez<br>avec cette arme considérée comme une lance<br>magique reçoivent un bonus de +3.<br>Bouton 4. Le sceptre se transforme en un mât d''esca -<br>lade pouvant atteindre 15 m de long (vous spécifiez<br>la longueur). Les boutons du sceptre restent à votre<br>portée. Ce mât s''ancre dans toute surface aussi dure<br>que le granit, par l''intermédiaire d''une pointe à la<br>260base et de trois crochets au sommet. Des barreaux<br>horizontaux de 7,5 cm de long se déploient sur les<br>côtés, à 30 cm d''écart, formant une échelle. Le mât<br>supporte un poids maximal de 2 000 kg. Un poids<br>excessif ou un ancrage insuffisant font revenir le<br>sceptre à sa forme normale .<br>Bouton 5. Le sceptre se transforme en bélier portable<br>qui octroie à son utilisateur un bonus de +10 aux<br>tests de Force (Athlétisme) visant à défoncer une<br>porte, une barricade ou toute autre barrière.<br>Bouton 6. Le sceptre retrouve ou conserve son aspect<br>normal et indique le nord magnétique. (Rien ne se<br>passe si cette fonction du sceptre est utilisée en un<br>lieu dépourvu de nord magnétique.) Le sceptre vous<br>fournit en outre une estimation de votre profondeur<br>sous terre ou de votre altitude à la surface.<br>Absorption de vie. Lorsque vous touchez une créa -<br>ture avec une attaque de corps à corps en utilisant<br>le sceptre, vous pouvez soumettre la cible à un jet de<br>sauvegarde de Constitution DD 17. En cas d''échec,<br>la cible subit 4d6 dégâts nécrotiques supplémentaires<br>et vous récupérez autant de points de vie que la moitié<br>des dégâts nécrotiques ainsi infligés. Une fois utilisée,<br>cette propriété ne peut plus resservir jusqu''à l''aube<br>suivante.<br>Paralysie. Lorsque vous touchez une créature avec<br>une attaque de corps à corps en utilisant le sceptre,<br>vous pouvez soumettre la cible à un jet de sauvegarde<br>de Constitution DD 17. En cas d''échec, la cible subit<br>l''état Paralysé pendant 1 minute. La cible réitère le JS<br>à la fin de chacun de ses tours et met un terme à l''ef -<br>fet sur elle-même en cas de réussite. Une fois utilisée,<br>cette propriété ne peut plus resservir jusqu''à l''aube<br>suivante.<br>Terreur. Tant que vous brandissez le sceptre, vous<br>pouvez entreprendre l''action Magie pour soumettre<br>chaque créature que vous voyez dans un rayon de<br>9 m à un jet de sauvegarde de Sagesse DD 17. En cas<br>d''échec, la cible subit l''état Effrayé pendant 1 minute.<br>Chaque cible Effrayée réitère le JS à la fin de chacun de<br>ses tours et met un terme à l''effet sur elle-même en cas<br>de réussite. Une fois utilisée, cette propriété ne peut<br>plus resservir jusqu''à l''aube suivante.</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre de résurrection', '<p>Le sceptre dispose de 5 charges. Lorsque vous le tenez,<br>vous pouvez lancer l''un des sorts suivants par son<br>intermédiaire : guérison (dépense 1 charge) ou résur -<br>rection (dépense 5 charges).<br>Le sceptre récupère quotidiennement 1 charge<br>dépensée, à l''aube. Si vous dépensez la dernière<br>charge, lancez 1d20. Sur un résultat de 1, le sceptre<br>disparaît dans une explosion radiante inoffensive.Sceptre de sécurité</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre de suzeraineté', '<p>Vous pouvez entreprendre l''action Magie pour brandir<br>le sceptre et exiger l''obéissance de toutes les créa -<br>tures de votre choix parmi celles que vous voyez dans<br>un rayon de 36 m. Chaque cible doit réussir un jet de<br>sauvegarde de Sagesse DD 15 sous peine de subir l''état<br>Charmé pendant 8 heures. Tant qu''elle est Charmée<br>de la sorte, une créature se fie à votre autorité. Si elle<br>est blessée par vous ou vos alliés, ou s''il lui est donné<br>l''ordre de commettre un acte contraire à sa nature,<br>une cible cesse d''être ainsi Charmée. Une fois uti -<br>lisée, cette propriété ne peut plus resservir avant<br>l''aube suivante.</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre de vigilance', '<p>Ce sceptre possède les propriétés suivantes.<br>Vigilance. Tant que vous tenez ce sceptre, vous avez<br>l''Avantage aux tests de Sagesse (Perception) et aux jets<br>d''Initiative.<br>Sorts. En tenant le sceptre, vous pouvez lancer les<br>sorts suivants par son intermédiaire :<br>• détection du mal et du bien<br>• détection de la magie<br>261• détection du poison et des maladies<br>• détection de l''invisibilité<br>Aura de protection. Au prix de l''action Magie, vous<br>pouvez planter le manche du sceptre dans le sol,<br>auquel cas sa tête émet une Lumière vive sur un rayon<br>de 18 m et une Lumière faible sur 18 m de plus. Dans<br>cette Lumière vive, vous et vos alliés recevez un bonus<br>de +1 à la CA et aux jets de sauvegarde, et vous perce -<br>vez la position de toute créature Invisible également<br>présente dans la Lumière vive.<br>La tête du sceptre cesse de briller et l''effet prend<br>fin au bout de 10 minutes (plus tôt si une créature<br>consacre l''action Magie à l''arracher du sol). Une fois<br>utilisée, cette propriété ne peut plus resservir jusqu''à<br>l''aube suivante.</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sceptre inamovible', '<p>Ce sceptre en fer présente un poussoir à une extré -<br>mité. Consacrer l''action Utilisation à appuyer sur<br>le poussoir a pour conséquence de figer magique -<br>ment le sceptre sur place. Jusqu''à ce que vous-même<br>ou une autre créature consacriez l''action Utilisation<br>à appuyer de nouveau sur le poussoir, le sceptre<br>ne bouge pas, même si sa position défie les lois de<br>la gravité. Le sceptre peut supporter un maximum<br>de 4 000 kg. Un poids supérieur provoque la désac -<br>tivation du sceptre et sa chute. Une créature peut<br>consacrer l''action Utilisation à effectuer un test de<br>Force (Athlétisme) DD 30, et déplace le sceptre figé<br>d''un maximum de 3 m en cas de réussite.</p>', 2, 93, 2, 1, 41);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Solvant universel', '<p>Ce tube contient un liquide laiteux qui dégage une<br>forte odeur d''alcool. Lorsqu''on le découvre, un tel réci -<br>pient contient 1d6 + 1 doses de 30 g.<br>Vous pouvez entreprendre l''action Utilisation pour<br>verser une ou plusieurs doses sur une surface à portée<br>d''allonge. Le liquide dissout instantanément jusqu''à<br>30 x 30 cm d''adhésif qu''il touche, y compris de la<br>colle universelle .</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Sphère d''annihilation', '<p>Cette sphère noire de 60 cm de diamètre forme un<br>trou dans le multivers en suspension dans l''espace,<br>stabilisé par le champ magique qui l''entoure.<br>La sphère annihile toute matière qu''elle traverse et<br>toute matière qui la traverse. Les Artefacts constituent<br>la seule exception. Un Artefact qui n''est pas sensible<br>aux dégâts d''une sphère d''annihilation la traverse sans<br>dommage. Pour le reste, tout ce qui touche la sphère<br>sans être entièrement englouti et annihilé par elle<br>subit 8d10 dégâts de force.<br>Contrôler la sphère. Une sphère d''annihilation reste<br>stationnaire jusqu''à ce que quelqu''un en prenne le<br>contrôle. Si vous êtes dans un rayon de 18 m d''une<br>sphère, vous pouvez entreprendre l''action Magie pour effectuer un test d''Intelligence (Arcanes) DD 25. En cas<br>de réussite, vous contrôlez la sphère jusqu''au début de<br>votre tour suivant. Si elle était sous le contrôle d''une<br>autre créature, celle-ci en perd le contrôle. En cas<br>d''échec, la sphère se déplace de 3 m en ligne droite<br>vers vous.<br>Tant que vous contrôlez la sphère, vous pouvez<br>consacrer une action Bonus à la déplacer dans la direc -<br>tion de votre choix d''une distance maximale en mètres<br>égale à votre modificateur d''Intelligence x 1,5 (mini -<br>mum 1,50 m). Si la sphère pénètre dans l''espace d''une<br>créature, celle-ci doit réussir un jet de sauvegarde<br>de Dextérité DD 19 sous peine d''être touchée par la<br>sphère et de subir 8d10 dégâts de force. Une créature<br>réduite à 0 point de vie par ces dégâts est annihilée,<br>ne laissant derrière elle que ses biens, sans aucun<br>autre vestige physique.<br>Interactions avec la sphère. Si la sphère entre en<br>contact avec un portail planaire comme celui créé par<br>le sort portail ou un espace extradimensionnel comme<br>celui d''un puits portable , le MJ détermine aléatoire -<br>ment ce qui se passe, en recourant à la table ci-après.<br>1d100 Résultat<br>01-50 La sphère est détruite.<br>51-85 La sphère franchit le portail ou entre dans<br>l''espace extradimensionnel.<br>86-00 Une faille planaire propulse chaque créature<br>et objet dans un rayon de 54 m de la sphère,<br>cette dernière comprise, vers un plan d''exis -<br>tence aléatoire.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Submersible du Crabe', '<p>Cet objet ressemble de prime abord à un baril her -<br>métique en fer d''un poids de 250 kg. Le tonneau est<br>doté d''un loquet caché que l''on trouve à condition de<br>réussir un test d''Intelligence (Investigation) DD 20.<br>Actionner le loquet déverrouille une écoutille sur l''une<br>des faces rondes du baril, ce qui permet à deux créa -<br>tures de taille M ou inférieure de ramper à l''intérieur.<br>Dix leviers sont disposés en ligne au fond du baril, cha -<br>cun en position neutre et que l''on peut actionner vers<br>le haut ou le bas. Lorsque certains leviers sont action -<br>nés, l''appareil se transforme pour prendre l''apparence<br>d''un homard géant.<br>Le submersible du Crabe est un objet de taille G avec<br>le profil suivant : CA 20, 200 pv, Vitesse 9 m, nage<br>9 m (ou 0 m pour les deux si les pattes ne sont pas<br>déployées) ; Immunité contre les dégâts psychiques et<br>de poison.<br>Pour être utilisé comme véhicule, le submersible<br>nécessite un pilote. Tant que la trappe est fermée, le<br>compartiment est étanche à l''air et à l''eau. Le compar -<br>timent contient suffisamment d''air pour 10 heures de<br>ventilation, divisées par le nombre de créatures qui<br>respirent à l''intérieur.<br>262Le submersible flotte sur l''eau. Il peut également être<br>immergé jusqu''à une profondeur de 270 m. Plus profon -<br>dément, le véhicule, soumis à une trop forte pression,<br>subit chaque minute 2d6 dégâts contondants.<br>Une créature dans le compartiment peut consacrer<br>l''action Utilisation à activer un ou deux des leviers<br>du submersible vers le haut ou le bas. Après chaque<br>utilisation, un levier revient en position neutre.<br>Chaque levier, de gauche à droite, fonctionne comme<br>indiqué dans la table « Leviers du submersible ».</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Talisman du bien ultime', '<p>avec un Clerc ou Paladin)<br>Ce talisman est un puissant symbole de bonté. Un Fiélon<br>ou un Mort-vivant qui touche le talisman subit 8d6<br>dégâts radiants, et en subit autant chaque fois qu''il<br>termine son tour en tenant ou en portant le talisman.<br>Réprimande pure. Le talisman dispose de 7 charges.<br>Lorsque vous portez ou tenez le talisman, vous pouvez<br>entreprendre l''action Magie pour dépenser 1 charge et<br>cibler une créature que vous voyez en contact avec le<br>sol dans un rayon de 36 m. Une faille ardente s''ouvre<br>sous la cible, qui effectue un jet de sauvegarde de<br>Dextérité DD 20. Si la cible est un Fiélon ou un Mort-<br>vivant, elle subit le Désavantage au JS. En cas d''échec,<br>elle tombe dans la faille, ce qui la détruit sans en lais -<br>ser la moindre trace. En cas de réussite, la cible n''est<br>pas précipitée dans la faille mais l''épreuve lui inflige<br>4d6 dégâts psychiques. Dans un cas comme dans<br>l''autre, la faille se referme alors, ne laissant aucune<br>trace de son existence. Lorsque vous dépensez sa dernière charge, le talisman se désagrège en parti -<br>cules de lumière dorée, détruit à jamais.<br>Symbole sacré. Vous pouvez utiliser le talisman<br>comme symbole sacré. Vous recevez un bonus de +2<br>aux jets d''attaque de sort lorsque vous le portez ou<br>le tenez.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Talisman de la sphère', '<p>Tant que vous tenez ou portez ce talisman, vous avez<br>l''Avantage à tout test d''Intelligence (Arcanes) visant à<br>contrôler une sphère d''annihilation . En outre, lorsque<br>vous commencez votre tour en contrôlant une sphère<br>d''annihilation , vous pouvez entreprendre l''action Magie<br>pour la déplacer, en mètres, d''un maximum de 3 plus le<br>triple de votre modificateur d''Intelligence. Ce déplace -<br>ment n''est pas nécessairement en ligne droite.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Talisman du mal absolu', '<p>Cet objet symbolise la quintessence du mal. Toute<br>créature autre qu''un Fiélon ou un Mort-vivant qui<br>touche le talisman subit 8d6 dégâts nécrotiques, et en<br>subit autant chaque fois qu''elle termine son tour en<br>tenant ou en portant le talisman.<br>Fin irrévocable. Le talisman dispose de 6 charges.<br>Lorsque vous portez ou tenez le talisman, vous pouvez<br>entreprendre l''action Magie pour dépenser 1 charge et<br>cibler une créature que vous voyez en contact avec le<br>sol dans un rayon de 36 m. Une faille ardente s''ouvre<br>sous la cible, qui effectue un jet de sauvegarde de<br>Dextérité DD 20. Si la cible est un Céleste, elle subit le Leviers du submersible<br>Levier Haut Bas<br>1 Les pattes se déploient et le submersible est apte à la<br>marche comme à la nage.Les pattes se rétractent, ce qui réduit la Vitesse et la<br>Vitesse de nage du submersible à 0 m et l''empêche de<br>bénéficier d''un quelconque bonus de vitesse.<br>2 Le volet du hublot avant s''ouvre. Le volet du hublot avant se ferme.<br>3 Les volets des hublots latéraux s''ouvrent (deux<br>par côté).Les volets des hublots latéraux se ferment (deux<br>par côté).<br>4 Deux pinces se déploient depuis les côtés, à l''avant<br>du submersible.Les pinces se rétractent.<br>5 Chaque pince déployée effectue l''attaque de corps<br>à corps suivante : +8 pour toucher, allonge 1,50 m.<br>Touché : 7 (2d6) dégâts contondants.Chaque pince déployée effectue l''attaque de corps<br>à corps suivante : +8 pour toucher, allonge 1,50 m.<br>Touché : La cible subit l''état Agrippé (évasion DD 15).<br>6 Le submersible marche ou nage vers l''avant à condi -<br>tion que ses pattes soient déployées.Le submersible marche ou nage vers l''arrière à condi -<br>tion que ses pattes soient déployées.<br>7 Le submersible pivote de 90 degrés vers la gauche à<br>condition que ses pattes soient déployées.Le submersible pivote de 90 degrés vers la droite à<br>condition que ses pattes soient déployées.<br>8 Des yeux mécaniques émettent une Lumière vive dans<br>un rayon de 9 m et une Lumière faible sur 9 m de plus.La lumière s''éteint.<br>9 Le submersible descend de 6 m s''il évolue dans l''élé -<br>ment liquide.Le submersible remonte de 6 m s''il évolue dans l''élé -<br>ment liquide.<br>10 L''écoutille arrière s''ouvre. L''écoutille arrière se ferme hermétiquement.<br>263Désavantage au JS. En cas d''échec, elle tombe dans la<br>faille, ce qui la détruit sans en laisser la moindre trace.<br>En cas de réussite, la cible n''est pas précipitée dans la<br>faille mais l''épreuve lui inflige 4d6 dégâts psychiques.<br>Dans un cas comme dans l''autre, la faille se referme<br>alors, ne laissant aucune trace de son existence.<br>Lorsque vous dépensez sa dernière charge, le talisman<br>se dissout en limon malodorant, détruit à jamais.<br>Symbole sacré. Vous pouvez utiliser le talisman<br>comme symbole sacré. Vous recevez un bonus de +2 aux<br>jets d''attaque de sort lorsque vous le portez ou le tenez.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Tapis volant', '<p>Ce tapis devient volant et entre en vol stationnaire si<br>vous entreprenez l''action Magie et prononcez son mot<br>de commande. Il se déplace au gré de vos instructions<br>à condition que vous restiez dans un rayon de 9 m.<br>Il existe quatre tailles de tapis volant . Le MJ en choisit<br>le type ou laisse le hasard décider sur la table ci-après.<br>Un tapis peut transporter jusqu''au double du poids qui<br>figure sur la table, mais sa Vitesse de vol est réduite de<br>moitié s''il transporte plus que sa capacité normale.<br>1d100 Taille Capacité Vitesse de vol<br>01-20 90 cm × 1,50 m 100 kg 24 m<br>21-55 1,20 m × 1,80 m 200 kg 18 m<br>56-80 1,50 m × 2,10 m 300 kg 12 m<br>81-00 1,80 m × 2,70 m 400 kg 9 m</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Tarot fantasmagorique', '<p>Cette boîte contient un jeu de cartes. Un jeu complet se<br>compose de 34 cartes (ou « lames ») : 32 représentent<br>des créatures spécifiques, les deux dernières ont<br>une surface réfléchissante. Il manque généralement<br>1d20 − 1 cartes à un jeu trouvé comme trésor.<br>La magie du tarot n''opère que si les lames sont pio -<br>chées au hasard. Vous pouvez consacrer l''action Magie<br>à piocher une lame au hasard et à la jeter au sol, en un<br>point situé dans un rayon de 9 m de vous. L''illusion<br>d''une créature, déterminée par un tirage sur la table<br>« Tarot fantasmagorique », se forme au-dessus de<br>la carte ainsi jetée et persiste jusqu''à dissipation.<br>La créature illusoire créée par la lame ressemble à une<br>vraie créature de son espèce et se comporte comme<br>telle, mais elle est parfaitement inoffensive. Tant que<br>vous êtes dans un rayon de 36 m de la créature illu -<br>soire et que vous la voyez, vous pouvez consacrer<br>l''action Magie à la déplacer en n''importe quel point<br>situé dans un rayon de 9 m de sa carte d''origine.<br>Toute interaction physique avec la créature illusoire<br>percera l''illusion, car elle est intangible. Une créature<br>qui entreprend l''action Étude afin d''inspecter visuel -<br>lement la créature illusoire perce l''illusion pour peu<br>qu''elle réussisse un test d''Intelligence (Investigation)<br>DD 15. L''illusion persiste jusqu''à sa dissipation (par le<br>biais du sort dissipation de la magie ou de tout effet comparable) ou que sa carte soit déplacée. Lorsque<br>l''illusion prend fin, l''image de la carte s''efface et cette<br>carte ne peut pas être réutilisée.<br>1d100 Illusion*<br>01-03 Archimage<br>04-06 Assassin<br>07-09 Basilic<br>10-12 Berserker<br>13-15 Capitaine bandit<br>16-18 Chevalier<br>19-21 Combattant gnoll<br>22-24 Combattant gobelin<br>25-27 Combattant gobelours<br>28-30 Combattant hobgobelin<br>31-33 Combattant kobold<br>34-36 Dragon rouge adulte<br>37-39 Druide<br>40-42 Ecclésiastique<br>43-45 Érinye<br>46-48 Ettin<br>49-51 Géant des collines<br>52-54 Géant des nuages<br>55-57 Géant du feu<br>58-60 Géant du givre<br>61-63 Golem de fer<br>64-66 Guenaude nocturne<br>67-69 Incube<br>70-72 Liche<br>73-75 Méduse<br>76-78 Naga gardien<br>79-81 Ogre<br>82-84 Oni<br>85-87 Succube<br>88-90 Troll<br>91-93 Vétéran<br>94-96 Vouivre<br>97-00 La personne qui a tiré la carte<br>*Les profils de ces créatures (hormis celui de la personne qui a tiré<br>la carte) figurent dans la section « Monstres ».</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Tarot mystérieux', '<p>Généralement rangé dans un étui ou une sacoche,<br>ce jeu de tarot se compose de cartes (ou « lames »)<br>en ivoire ou en vélin. Si la plupart (75 %) de ces jeux<br>comportent treize cartes, certains en ont vingt-deux.<br>264Référez-vous à la colonne correspondante de la table<br>« Tarot mystérieux » pour laisser le hasard décider des<br>cartes que vous piochez dans le jeu.<br>Avant de piocher une carte, vous devez déclarer<br>combien de cartes vous comptez tirer, puis vous les<br>piochez au hasard. Toutes les cartes piochées au-delà<br>du chiffre annoncé sont sans effet. Sinon, la magie<br>d''une carte opère dès que vous piochez celle-ci dans le<br>paquet. Vous ne devez pas laisser s''écouler plus d''une<br>heure entre chaque pioche. Si vous renoncez à piocher<br>le chiffre annoncé, le nombre de cartes qui reste pour<br>atteindre ce chiffre s''envole de lui-même du paquet et<br>prend effet simultanément.<br>Dès qu''une carte a été piochée, elle disparaît.<br>À moins que cette carte soit le Fou ou le Bouffon,<br>la carte réapparaît dans le paquet, ce qui laisse la pos -<br>sibilité de piocher deux fois la même carte. (Quand le<br>Fou ou le Bouffon quitte le jeu, relancez sur la table si<br>cette carte est tirée de nouveau.)<br>1d100<br>(jeu de 13 cartes)1d100<br>(jeu de 22 cartes) Carte<br>— 01-05 La Balance<br>01-08 06-10 Le Bouffon<br>09-16 11-15 Le Chevalier<br>17-24 16-20 La Clef<br>— 21-25 La Comète<br>25-32 26-29 Le Crâne<br>— 30-33 Le Donjon<br>— 34-37 L''Énigme<br>33-40 38-42 L''Étoile<br>41-48 43-46 Euryale<br>49-56 47-50 Les Flammes<br>— 51-54 Le Fou<br>— 55-59 La Gemme<br>57-64 60-64 La Lune<br>65-68 65-68 Le Néant<br>— 69-73 Les Parques<br>69-76 74-77 La Ruine<br>— 78-81 Les Serres<br>77-84 82-86 Le Soleil<br>85-92 87-90 Le Traître<br>93-100 91-95 Le Trône<br>— 96-00 Le Vizir<br>L''effet de chaque carte est décrit ci-dessous.<br>La Balance. Vous pouvez augmenter de 2 l''une de<br>vos valeurs de caractéristique, jusqu''à un maximum de<br>22, à condition de diminuer une autre valeur de carac -<br>téristique de 2. Il vous est interdit de diminuer une<br>caractéristique dont la valeur est inférieure ou égale à 5. Vous pouvez également choisir de ne pas modifier<br>vos valeurs de caractéristique, auquel cas cette lame<br>est sans effet.<br>Le Bouffon. Vous bénéficiez de l''Avantage aux<br>Tests d20 pendant les 72 prochaines heures, ou bien<br>vous pouvez piocher deux cartes en plus du chiffre<br>annoncé.<br>Le Chevalier. Vous recevez l''allégeance d''un<br>chevalier , qui apparaît magiquement en un espace<br>inoccupé dans un rayon de 9 m de vous. Ce chevalier<br>est du même alignement que vous et vous sert loyale -<br>ment jusqu''à sa mort, convaincu que vos destins sont<br>intimement liés. Concertez-vous avec votre MJ afin<br>d''imaginer un nom et une histoire à ce PNJ. Le MJ peut<br>décider de recourir à un autre profil de jeu pour ce<br>chevalier, à sa guise.<br>La Clef. Une arme magique rare ou de rareté supé -<br>rieure, dont vous avez la maîtrise, apparaît dans vos<br>mains. C''est le MJ qui choisit cette arme.<br>La Comète. La prochaine fois que vous entrez en<br>combat avec une ou plusieurs créatures Hostiles, vous<br>pouvez désigner l''une d''elles comme votre ennemi<br>au moment de jouer l''Initiative. Si vous réduisez cet<br>ennemi à 0 point de vie lors du combat, vous bénéfi -<br>cierez de l''Avantage aux jets de sauvegarde contre la<br>mort pendant 1 an. Si quelqu''un d''autre réduit votre<br>ennemi désigné à 0 point de vie ou si vous n''en avez<br>choisi aucun, cette lame est sans effet.<br>Le Crâne. Un avatar de la Mort (cf. profil ci-joint)<br>apparaît dans un espace inoccupé, aussi près que pos -<br>sible de vous. L''avatar, un inquiétant squelette vêtu<br>d''une robe noire et brandissant une faux spectrale, ne<br>prend que vous pour cible avec ses attaques. L''avatar<br>disparaît lorsqu''il tombe à 0 point de vie ou que<br>vous mourez. Si l''un de vos alliés inflige des dégâts à<br>l''avatar, cet allié convoque un autre avatar de la Mort .<br>Le nouvel avatar apparaît dans un espace inoccupé,<br>aussi près que possible de cet allié, et ne cible que ce<br>dernier avec ses attaques. Vous-même et vos alliés<br>ne pouvez convoquer chacun qu''un seul avatar en<br>conséquence de cette pioche. Une créature tuée par un<br>avatar ne peut pas être ramenée à la vie.<br>Avatar de la Mort<br>Mort-vivant de taille M, Neutre Mauvais<br>CA 20 Initiative +3 (13)<br>Pv la moitié du maximum de pv de son invocateur<br>Vitesse 18 m, vol 18 m (vol stationnaire)<br>MOD JS MOD JS MOD JS<br>For 16 +3+3 Dex 16+3+3 Con 16+3+3<br>Int 16 +3+3 Sag 16 +3+3 Cha 16+3+3<br>Immunités nécrotiques, poison ; Charmé, Effrayé,<br>Empoisonné, Épuisement, Inconscient, Paralysé, Pétrifié<br>Sens Vision lucide 18 m, Perception passive 13<br>Langues toutes les langues connues de la créature qui<br>l''a convoqué<br>FP aucun (PX 0 ; BM égal à celui de l''invocateur)<br>265Traits<br>Déplacement intangible. L''avatar peut traverser d''autres<br>créatures et objets comme s''il s''agissait d''un Terrain<br>difficile. Il subit 5 (1d10) dégâts de force s''il termine son<br>tour à l''intérieur d''un objet.<br>Actions<br>Attaques multiples. L''avatar effectue autant d''attaques<br>de Faux tournoyante que la moitié du bonus de maîtrise<br>de son invocateur (arrondie au supérieur).<br>Faux tournoyante. Corps à corps : Touché automatique,<br>allonge 1,50 m. Touché : 7 (1d8 + 3) dégâts tranchants<br>plus 4 (1d8) dégâts nécrotiques.<br>Le Donjon. Vous disparaissez et plongez dans un état<br>d''animation suspendue au sein d''une sphère extradi -<br>mensionnelle. Tout ce que vous portiez disparaît avec<br>vous hormis les Artefacts, qui demeurent dans l''espace<br>que vous occupiez au moment de votre disparition.<br>Vous restez emprisonné jusqu''à ce qu''on vous trouve<br>ou vous retire de la sphère. Il est impossible de vous<br>localiser au moyen de la magie de Divination, mais le<br>sort souhait révèle la position de votre prison. Vous ne<br>piochez plus aucune carte.<br>L''Énigme. Réduit de façon permanente votre<br>Intelligence ou votre Sagesse de 1d4 + 1 (valeur mini -<br>male de 1). Vous pouvez piocher une carte en plus du<br>chiffre annoncé.<br>L''Étoile. L''une de vos valeurs de caractéristique aug -<br>mente de 2, jusqu''à un maximum de 24.<br>Euryale. Le visage de méduse de la carte vous lance<br>une malédiction. Vous subissez un malus de -2 aux<br>jets de sauvegarde tant que persiste cette malédiction.<br>Seul un dieu ou la magie de la carte « Les Parques »<br>permet de lever cette malédiction.<br>Les Flammes. Un diable puissant devient votre<br>ennemi. Ce diable travaille à votre perte et vous tour -<br>mente en savourant vos souffrances, avant de tenter<br>de vous tuer. Cette haine persiste jusqu''à votre mort<br>ou celle du diable.<br>Le Fou. Vous subissez le Désavantage aux Tests d20<br>pendant les 72 prochaines heures. Piochez une autre<br>carte ; celle-ci n''est pas décomptée du chiffre annoncé.<br>La Gemme. Vingt-cinq bijoux d''une valeur unitaire<br>de 2 000 po ou cinquante pierres précieuses d''une<br>valeur unitaire de 1 000 po apparaissent à vos pieds.<br>La Lune. Vous recevez l''aptitude à lancer<br>souhait 1d3 fois.<br>Le Néant. Votre âme est arrachée à votre corps et<br>enfermée dans un objet en un lieu choisi par le MJ.<br>Une ou plusieurs entités puissantes veillent sur ce lieu.<br>Tant que votre âme est emprisonnée de cette manière,<br>votre corps est inerte, cesse de vieillir et n''a nul besoin<br>de nourriture, d''air ou d''eau. Le sort souhait ne par -<br>vient pas à réunir votre corps et votre âme, mais il<br>révèle la position de l''objet qui renferme votre âme.<br>Vous ne piochez plus aucune carte.Les Parques. La trame de la réalité se délite et ses<br>fils en tissent une nouvelle, vous permettant d''échap -<br>per à un événement comme s''il ne s''était jamais<br>produit. Vous pouvez recourir à la magie de cette carte<br>dès que vous la piochez ou en toute autre circonstance<br>avant de mourir.<br>La Ruine. Toutes les formes de richesse que vous<br>portez ou possédez, à l''exception des objets magiques,<br>disparaissent. Vos biens meubles s''évanouissent.<br>Vos négoces, bâtiments et terres sont perdus de la<br>façon qui altère le moins possible le cours de la réalité.<br>Tous les documents attestant que vous possédiez un<br>bien volatilisé par cette carte disparaissent eux aussi.<br>Les Serres. Chaque objet magique que vous portez<br>ou transportez se désintègre. Les Artefacts en votre<br>possession, quant à eux, ne font que disparaître.<br>Le Soleil. Un objet magique (choisi par le MJ)<br>apparaît sur votre personne. Vous recevez en outre<br>quotidiennement 10 points de vie temporaires à l''aube,<br>et ce jusqu''à votre mort.<br>Le Traître. Un PNJ au choix du MJ devient Hostile<br>envers vous. Vous ignorez l''identité de ce PNJ tant que<br>lui-même ou une tierce personne ne vous la révèle pas.<br>Rien hormis le sort souhait ou une intervention divine<br>ne peut mettre fin à l''hostilité de ce PNJ à votre égard.<br>Le Trône. Vous recevez la maîtrise et l''Expertise<br>de votre choix entre les compétences Histoire,<br>Intimidation, Intuition ou Persuasion. En outre, vous<br>recevez la propriété légitime d''une petite forteresse<br>quelque part dans le monde. Cela étant, cette forte -<br>resse est actuellement occupée par un ou plusieurs<br>monstres, qui devront être éliminés pour que vous<br>puissiez la faire vôtre.<br>Le Vizir. À tout moment de votre choix au cours de<br>l''année qui suit la pioche de cette carte, vous pouvez<br>poser une question tout en méditant et recevez menta -<br>lement une réponse exacte à cette question.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Traité de perspicacité', '<p>Ce livre aux inscriptions chargées de magie recèle de<br>précieux exercices de mémoire et de logique. Si vous<br>consacrez 48 heures sur une période maximale de<br>6 jours à étudier le contenu de l''ouvrage et à le mettre<br>en pratique, votre valeur d''Intelligence augmente de<br>2, jusqu''à un maximum de 30. Le manuel perd alors sa<br>magie, mais la retrouve après un siècle.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Traité d''autorité et d''influence', '<p>Ce livre aux inscriptions chargées de magie dispense<br>de précieux conseils sur la façon d''influencer et de<br>captiver l''auditoire. Si vous consacrez 48 heures sur<br>une période maximale de 6 jours à étudier le contenu<br>de l''ouvrage et à le mettre en pratique, votre valeur de<br>Charisme augmente de 2, jusqu''à un maximum de 30.<br>Le manuel perd alors sa magie, mais la retrouve après<br>un siècle.<br>266Traité de compréhension</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Traité de compréhension', '<p>Ce livre aux inscriptions chargées de magie propose<br>de précieux exercices d''intuition et de perspicacité.<br>Si vous consacrez 48 heures sur une période maxi -<br>male de 6 jours à étudier le contenu de l''ouvrage et à le<br>mettre en pratique, votre valeur de Sagesse augmente<br>de 2, jusqu''à un maximum de 30. Le manuel perd alors<br>sa magie, mais la retrouve après un siècle.<br>Trident de domination aquatique<br>Arme (trident), peu courante (Harmonisation requise)<br>Cette arme magique dispose de 3 charges et récupère<br>quotidiennement 1d3 charges dépensées, à l''aube.<br>Tant que vous la portez, vous pouvez dépenser 1 charge<br>pour lancer le sort domination de bête (DD de sauve -<br>garde 15) par son biais sur une Bête dotée d''une Vitesse<br>de nage.<br>Tueuse de dragons<br>Arme (courante ou de guerre), rare<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>L''arme inflige 3d6 dégâts supplémentaires du type<br>de l''arme si la cible est un Dragon.<br>Tueuse de géants<br>Arme (courante ou de guerre), rare<br>Vous recevez un bonus de +1 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>Quand vous touchez un Géant avec cette arme,<br>il subit 2d6 dégâts supplémentaires du type associé<br>à l''arme et doit réussir un jet de sauvegarde de Force<br>DD 15 sous peine de subir l''état À terre.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Urne fumigène', '<p>Au prix de l''action Magie, vous ouvrez ou refermez<br>cette urne.<br>L''ouvrir provoque l''expulsion d''une fumée épaisse<br>qui génère un nuage sous forme d''une Émanation<br>de 18 m centrée sur l''urne. La zone enfumée est à<br>Visibilité nulle.<br>Chaque minute que l''urne reste ouverte, la taille de<br>l''Émanation augmente de 3 m jusqu''à avoir atteint sa<br>taille maximale de 36 m.<br>La fermeture de l''urne provoque l''immobilisation du<br>nuage, qui se disperse au bout de 10 minutes. Un vent<br>fort (tel que celui créé par le sort bourrasque ) disperse<br>le nuage en 1 minute.Vengeresse sacrée<br>Arme (courante ou de guerre), légendaire<br>(Harmonisation requise avec un Paladin)<br>Vous recevez un bonus de +3 aux jets d''attaque<br>et de dégâts effectués avec cette arme magique.<br>Quand vous touchez un Fiélon ou un Mort-vivant avec<br>cette arme, la créature subit 2d10 dégâts radiants<br>supplémentaires.<br>Tant que vous tenez l''arme au clair, elle crée une<br>Émanation de 3 m centrée sur vous. Vous-même et<br>toutes les créatures de l''Émanation qui vous sont<br>Amicales bénéficiez de l''Avantage aux jets de sau -<br>vegarde contre les sorts et autres effets magiques.<br>Si vous disposez de 17 niveaux ou plus dans la classe<br>de Paladin, la taille de cette Émanation passe à 9 m.<br>Voleuse de vie<br>Arme (courante ou de guerre), très rare<br>(Harmonisation requise)<br>Vous recevez un bonus de +2 aux jets d''attaque et de<br>dégâts effectués avec cette arme magique.<br>Vol de vie. L''arme dispose de 1d8 + 1 charges.<br>Lorsque vous attaquez une créature dotée de moins<br>de 100 points de vie avec cette arme et obtenez un<br>20 sur le d20 du jet d''attaque, la créature doit réus -<br>sir un jet de sauvegarde de Constitution DD 15 sous<br>peine de mourir sur-le-champ, l''épée lui arrachant sa<br>force vitale. Les Artificiels et les Morts-vivants réus -<br>sissent automatiquement ce JS. L''arme perd 1 charge<br>si la créature est tuée. Elle perd cette propriété quand<br>toutes ses charges ont été dépensées.</p>', 2, 93, 2, 1, 38);

INSERT INTO dd_objets_magiques (om_nom, om_description, om_fom_id, om_res_id, om_ruleset_var_id, om_visible, om_catom_id) 
VALUES ('Yeux de lynx', '<p>Ces lentilles en cristal s''appliquent sur les yeux.<br>Tant que vous les portez, vous avez l''Avantage aux<br>tests de Sagesse (Perception) qui reposent sur la vue.<br>Dans des conditions de bonne visibilité, vous pouvez<br>distinguer les détails de créatures et d''objets à très<br>longue distance, tant que leur largeur est d''au moins<br>60 cm.</p>', 2, 93, 2, 1, 38);

